// Generate automatic voucher code for Flight Voucher bookings
app.post('/api/generate-voucher-code', async (req, res) => {
    const {
        flight_category,
        customer_name,
        customer_email,
        location,
        experience_type,
        voucher_type,
        paid_amount,
        expires_date
    } = req.body;

    try {
        // Check for existing voucher code for same customer to prevent duplicates
        const duplicateCheck = () => {
            return new Promise((resolve, reject) => {
                if (voucher_type === 'Book Flight') {
                    // Check in all_booking table
                    const duplicateCheckSql = `
                        SELECT voucher_code as code FROM all_booking 
                        WHERE email = ? AND name = ? AND paid = ? 
                        AND created_at > DATE_SUB(NOW(), INTERVAL 2 MINUTE) 
                        LIMIT 1
                    `;
                    con.query(duplicateCheckSql, [customer_email, customer_name, paid_amount], (err, result) => {
                        if (err) {
                            reject(err);
                        } else {
                            resolve(result);
                        }
                    });
                } else {
                    // Check in all_vouchers table
                    const duplicateCheckSql = `
                        SELECT voucher_ref as code FROM all_vouchers 
                        WHERE email = ? AND name = ? AND paid = ? 
                        AND created_at > DATE_SUB(NOW(), INTERVAL 2 MINUTE) 
                        LIMIT 1
                    `;
                    con.query(duplicateCheckSql, [customer_email, customer_name, paid_amount], (err, result) => {
                        if (err) {
                            reject(err);
                        } else {
                            resolve(result);
                        }
                    });
                }
            });
        };

        // Check for recent duplicates first - only prevent if there's already a NON-NULL code
        const existingCode = await duplicateCheck();
        if (existingCode && existingCode.length > 0 && existingCode[0].code) {
            console.log('=== DUPLICATE VOUCHER CODE GENERATION PREVENTED ===');
            console.log('Existing code found:', existingCode[0].code);
            console.log('Customer:', customer_name, 'Email:', customer_email, 'Amount:', paid_amount);
            return res.json({
                success: true,
                message: 'Voucher code already exists for this customer',
                voucher_code: existingCode[0].code,
                duplicate_prevented: true
            });
        }

        console.log('=== NO EXISTING VOUCHER CODE FOUND ===');
        console.log('Proceeding with new voucher code generation for:', customer_name);

        // Generate voucher code based on the pattern: F/G + Category + Year + Serial
        const year = new Date().getFullYear().toString().slice(-2); // Get last 2 digits of year (25 for 2025)

        // Map flight categories to codes
        const categoryMap = {
            'Weekday Morning': 'WM',
            'Weekday Flex': 'WF',
            'Anytime': 'AT',
            'Any Day Flight': 'AT' // Default mapping
        };

        // Determine flight category based on voucher type if not provided
        let finalFlightCategory = flight_category;
        console.log('Received flight_category:', flight_category);
        console.log('Received voucher_type:', voucher_type);

        if (!finalFlightCategory && voucher_type) {
            // If voucher type is provided but flight category is not, try to determine from voucher type
            if (voucher_type === 'Book Flight' || voucher_type === 'Flight Voucher' || voucher_type === 'Buy Gift') {
                // For these types, we need to get the flight category from the request
                // This will be handled by the frontend sending the correct voucher type detail
                finalFlightCategory = 'Any Day Flight'; // Default fallback
            }
        }

        console.log('Final Flight Category:', finalFlightCategory);
        const categoryCode = categoryMap[finalFlightCategory] || 'AT';
        console.log('Generated Category Code:', categoryCode);

        // Determine prefix based on voucher type
        let prefix = 'F'; // Default for Flight Voucher
        if (voucher_type === 'Buy Gift' || voucher_type === 'Gift Voucher') {
            prefix = 'G';
        } else if (voucher_type === 'Book Flight') {
            prefix = 'B';
        }

        // Generate unique serial (3 characters)
        const generateSerial = () => {
            const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
            let result = '';
            for (let i = 0; i < 3; i++) {
                result += chars.charAt(Math.floor(Math.random() * chars.length));
            }
            return result;
        };

        // Helper to normalize currency inputs to float for comparisons
        const normalizePaidAmount = (value) => {
            if (typeof value === 'number' && !Number.isNaN(value)) {
                return value;
            }
            if (typeof value === 'string') {
                const numeric = parseFloat(value.replace(/[^0-9.-]/g, ''));
                return Number.isNaN(numeric) ? 0 : numeric;
            }
            return 0;
        };

        // Generate unique voucher code
        let voucherCode;
        let isUnique = false;
        let attempts = 0;
        const maxAttempts = 10;

        // Use async/await pattern for database operations
        const generateUniqueCode = async () => {
            while (!isUnique && attempts < maxAttempts) {
                const serial = generateSerial();
                voucherCode = `${prefix}${categoryCode}${year}${serial}`;

                // Check if code already exists in both tables
                const checkCode = () => {
                    return new Promise((resolve, reject) => {
                        const checkSql = `
                            SELECT id FROM all_vouchers WHERE voucher_ref = ?
                            UNION
                            SELECT id FROM all_booking WHERE voucher_code = ?
                        `;
                        con.query(checkSql, [voucherCode, voucherCode], (err, result) => {
                            if (err) {
                                reject(err);
                            } else {
                                resolve(result.length === 0);
                            }
                        });
                    });
                };

                try {
                    const codeAvailable = await checkCode();
                    if (codeAvailable) {
                        isUnique = true;
                        break;
                    }
                } catch (err) {
                    console.error('Error checking voucher code uniqueness:', err);
                    return res.status(500).json({ success: false, message: 'Database error' });
                }

                attempts++;
            }

            if (!isUnique) {
                return res.status(500).json({ success: false, message: 'Could not generate unique voucher code' });
            }
        };

        // Generate the unique code
        await generateUniqueCode();

        // Create title for the voucher code
        const title = `${customer_name} - ${flight_category} - ${location}`;

        // Handle different voucher types
        console.log('=== VOUCHER CODE UPDATE ===');
        console.log('Voucher type:', voucher_type);
        console.log('Looking for record with customer:', customer_name, customer_email, paid_amount);

        const findAndUpdateRecord = () => {
            return new Promise((resolve, reject) => {
                if (voucher_type === 'Book Flight') {
                    // For Book Flight, update the booking record
                    console.log('=== FINDING BOOKING RECORD TO UPDATE ===');
                    console.log('Searching for booking with:', {
                        customer_name,
                        customer_email,
                        paid_amount
                    });

                    const findSql = `
                        SELECT id FROM all_booking 
                        WHERE name = ? AND email = ? AND paid = ? 
                        AND (voucher_code IS NULL OR voucher_code = '') 
                        ORDER BY created_at DESC 
                        LIMIT 1
                    `;

                    con.query(findSql, [customer_name, customer_email, paid_amount], (err, findResult) => {
                        if (err) {
                            console.error('Error finding booking record:', err);
                            reject(err);
                            return;
                        }

                        console.log('Found booking records:', findResult.length);
                        console.log('Booking records:', findResult);

                        if (findResult.length === 0) {
                            console.log('No booking found with exact match, trying broader search...');

                            // Try broader search without exact paid amount match
                            const broaderSql = `
                                SELECT id FROM all_booking 
                                WHERE name = ? AND email = ? 
                                AND (voucher_code IS NULL OR voucher_code = '') 
                                ORDER BY created_at DESC 
                                LIMIT 1
                            `;

                            con.query(broaderSql, [customer_name, customer_email], (broaderErr, broaderResult) => {
                                if (broaderErr) {
                                    console.error('Error in broader search:', broaderErr);
                                    reject(new Error('No booking found to update with code'));
                                    return;
                                }

                                if (broaderResult.length === 0) {
                                    console.log('No booking found even with broader search');
                                    reject(new Error('No booking found to update with code'));
                                    return;
                                }

                                const bookingId = broaderResult[0].id;
                                console.log('Found booking ID with broader search:', bookingId);

                                // Update the booking with the generated code
                                const updateSql = 'UPDATE all_booking SET voucher_code = ? WHERE id = ?';
                                con.query(updateSql, [voucherCode, bookingId], (updateErr, updateResult) => {
                                    if (updateErr) {
                                        console.error('Error updating booking:', updateErr);
                                        reject(updateErr);
                                    } else {
                                        console.log('Booking updated with code:', voucherCode);
                                        resolve({ recordId: bookingId, voucherCode });
                                    }
                                });
                            });
                            return;
                        }

                        const bookingId = findResult[0].id;
                        console.log('Found booking ID to update:', bookingId);

                        // Update the booking with the generated code
                        const updateSql = 'UPDATE all_booking SET voucher_code = ? WHERE id = ?';
                        con.query(updateSql, [voucherCode, bookingId], (updateErr, updateResult) => {
                            if (updateErr) {
                                console.error('Error updating booking:', updateErr);
                                reject(updateErr);
                            } else {
                                console.log('Booking updated with code:', voucherCode);
                                resolve({ recordId: bookingId, voucherCode });
                            }
                        });
                    });
                } else {
                    // For Gift Vouchers, update the voucher record
                    console.log('Updating voucher record with voucher code');
                    const normalizedPaidAmount = normalizePaidAmount(paid_amount);
                    const normalizedName = (customer_name || '').trim();
                    const normalizedEmail = (customer_email || '').trim();

                    const queryAsync = (sql, params) => new Promise((resolveQuery, rejectQuery) => {
                        con.query(sql, params, (queryErr, result) => {
                            if (queryErr) {
                                rejectQuery(queryErr);
                            } else {
                                resolveQuery(result);
                            }
                        });
                    });

                    const updateGiftVoucher = async () => {
                        console.log('Gift voucher lookup payload:', {
                            normalizedName,
                            normalizedEmail,
                            normalizedPaidAmount
                        });

                        const strictSql = `
                            SELECT id, name, email, purchaser_name, purchaser_email, paid, created_at
                            FROM all_vouchers 
                            WHERE (voucher_ref IS NULL OR voucher_ref = '' OR voucher_ref = '-')
                              AND ABS(COALESCE(paid, 0) - ?) <= 1
                              AND (
                                    name = ? OR purchaser_name = ?
                                )
                              AND (
                                    email = ? OR purchaser_email = ?
                                )
                        ORDER BY created_at DESC 
                            LIMIT 5
                        `;

                        let candidates = await queryAsync(strictSql, [
                            normalizedPaidAmount,
                            normalizedName,
                            normalizedName,
                            normalizedEmail,
                            normalizedEmail
                        ]);

                        if (!candidates.length) {
                            console.log('No voucher found with strict lookup; trying fallback search ignoring paid amount.');
                            const fallbackSql = `
                                SELECT id, name, email, purchaser_name, purchaser_email, paid, created_at
                                FROM all_vouchers 
                                WHERE (voucher_ref IS NULL OR voucher_ref = '' OR voucher_ref = '-')
                                  AND (
                                        (name = ? OR purchaser_name = ?) OR
                                        (email = ? OR purchaser_email = ?)
                                    )
                                  AND created_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)
                                ORDER BY created_at DESC 
                                LIMIT 5
                            `;
                            candidates = await queryAsync(fallbackSql, [
                                normalizedName,
                                normalizedName,
                                normalizedEmail,
                                normalizedEmail
                            ]);
                        }

                        if (!candidates.length && normalizedEmail) {
                            console.log('No voucher found with fallback search; trying latest voucher by email only.');
                            const looseSql = `
                                SELECT id, name, email, purchaser_name, purchaser_email, paid, created_at
                                FROM all_vouchers 
                                WHERE (voucher_ref IS NULL OR voucher_ref = '' OR voucher_ref = '-')
                                  AND (email = ? OR purchaser_email = ?)
                                ORDER BY created_at DESC 
                                LIMIT 5
                            `;
                            candidates = await queryAsync(looseSql, [
                                normalizedEmail,
                                normalizedEmail
                            ]);
                        }

                        if (!candidates.length) {
                            throw new Error('No voucher found to update with code');
                        }

                        console.log('Voucher lookup candidates:', candidates.map(candidate => ({
                            id: candidate.id,
                            name: candidate.name,
                            purchaser_name: candidate.purchaser_name,
                            email: candidate.email,
                            purchaser_email: candidate.purchaser_email,
                            paid: candidate.paid,
                            created_at: candidate.created_at
                        })));

                        const voucherId = candidates[0].id;
                        console.log('Found voucher ID to update:', voucherId);

                        await queryAsync('UPDATE all_vouchers SET voucher_ref = ? WHERE id = ?', [voucherCode, voucherId]);
                        console.log('Voucher updated with code:', voucherCode);
                        return { recordId: voucherId, voucherCode };
                    };

                    updateGiftVoucher()
                        .then(resolve)
                        .catch(reject);
                }
            });
        };

        try {
            const result = await findAndUpdateRecord();

            // Ensure the generated code shows in settings as user_generated
            const defaultExpiryDate = (expires_date && expires_date !== '')
                ? expires_date
                : dayjs().add((experience_type === 'Private Charter' ? 18 : 24), 'month').format('YYYY-MM-DD');
            const insertUserCodeSql = `
                INSERT INTO voucher_codes (
                    code, title, valid_from, valid_until, max_uses, current_uses,
                    applicable_locations, applicable_experiences, applicable_voucher_types,
                    is_active, created_at, updated_at, source_type, customer_email, paid_amount
                ) VALUES (?, ?, NOW(), ?, 1, 0, ?, ?, ?, 1, NOW(), NOW(), 'user_generated', ?, ?)
                ON DUPLICATE KEY UPDATE 
                    source_type = VALUES(source_type),
                    title = VALUES(title),
                    valid_until = VALUES(valid_until),
                    applicable_locations = VALUES(applicable_locations),
                    applicable_experiences = VALUES(applicable_experiences),
                    applicable_voucher_types = VALUES(applicable_voucher_types),
                    updated_at = NOW()
            `;
            const insertVals = [
                voucherCode,
                title,
                defaultExpiryDate,
                location || null,
                experience_type || null,
                voucher_type || null,
                customer_email || null,
                paid_amount || 0
            ];
            con.query(insertUserCodeSql, insertVals, (insErr) => {
                if (insErr) {
                    console.warn('Warning: could not upsert user_generated voucher code:', insErr.message);
                }
            });

            res.json({
                success: true,
                message: `${voucher_type} code generated and assigned successfully`,
                voucher_code: voucherCode,
                record_id: result.recordId,
                customer_name: customer_name,
                customer_email: customer_email,
                updated_record: true
            });
        } catch (updateError) {
            console.error('Error updating record with code:', updateError);
            console.log('=== FALLBACK: Returning voucher code without updating record ===');
            // Still upsert into voucher_codes so it appears in settings
            try {
                const defaultExpiryDate = (expires_date && expires_date !== '')
                    ? expires_date
                    : dayjs().add((experience_type === 'Private Charter' ? 18 : 24), 'month').format('YYYY-MM-DD');
                const insertUserCodeSql = `
                    INSERT INTO voucher_codes (
                        code, title, valid_from, valid_until, max_uses, current_uses,
                        applicable_locations, applicable_experiences, applicable_voucher_types,
                        is_active, created_at, updated_at, source_type, customer_email, paid_amount
                    ) VALUES (?, ?, NOW(), ?, 1, 0, ?, ?, ?, 1, NOW(), NOW(), 'user_generated', ?, ?)
                    ON DUPLICATE KEY UPDATE 
                        source_type = VALUES(source_type),
                        title = VALUES(title),
                        valid_until = VALUES(valid_until),
                        applicable_locations = VALUES(applicable_locations),
                        applicable_experiences = VALUES(applicable_experiences),
                        applicable_voucher_types = VALUES(applicable_voucher_types),
                        updated_at = NOW()
                `;
                const insertVals = [
                    voucherCode,
                    title,
                    defaultExpiryDate,
                    location || null,
                    experience_type || null,
                    voucher_type || null,
                    customer_email || null,
                    paid_amount || 0
                ];
                con.query(insertUserCodeSql, insertVals, () => { });
            } catch (e) { }

            // Return the voucher code so it can be used
            res.json({
                success: true,
                message: `${voucher_type} code generated successfully (record update failed)`,
                voucher_code: voucherCode,
                customer_name: customer_name,
                customer_email: customer_email,
                updated_record: false,
                warning: 'Code generated but could not update record automatically'
            });
        }

    } catch (error) {
        console.error('Error generating voucher code:', error);
        console.error('Error details:', {
            message: error.message,
            stack: error.stack,
            requestData: {
                flight_category,
                customer_name,
                customer_email,
                location,
                experience_type,
                voucher_type,
                paid_amount,
                expires_date
            }
        });
        res.status(500).json({
            success: false,
            message: 'Server error',
            error: error.message,
            details: 'Check server logs for more information'
        });
    }
});

// Get all voucher codes
app.get('/api/voucher-codes', (req, res) => {
    // For User Generated Codes, show codes from both all_vouchers and all_booking tables
    // Fix collation issues by using COLLATE utf8mb4_unicode_ci for all string comparisons
    const sql = `
        SELECT 
            vc.id,
            vc.code,
            vc.title,
            vc.valid_from,
            vc.valid_until,
            vc.max_uses,
            vc.voucher_type,
            vc.current_uses,
            vc.applicable_locations,
            vc.applicable_experiences,
            vc.applicable_voucher_types,
            vc.is_active,
            vc.created_by,
            vc.source_type,
            vc.customer_email,
            vc.paid_amount,
            vc.created_at,
            vc.updated_at,
            COUNT(vcu.id) as total_uses,
            CASE 
                WHEN vc.max_uses IS NULL THEN 'Unlimited'
                ELSE CONCAT(vc.current_uses, '/', vc.max_uses)
            END as usage_status
        FROM voucher_codes vc
        LEFT JOIN voucher_code_usage vcu ON vc.id = vcu.voucher_code_id
        WHERE 
            -- For user_generated codes, only show if they exist in all_vouchers or all_booking
            (vc.source_type COLLATE utf8mb4_unicode_ci != 'user_generated' COLLATE utf8mb4_unicode_ci OR 
             EXISTS (
                 SELECT 1 FROM all_vouchers av 
                 WHERE av.voucher_ref COLLATE utf8mb4_unicode_ci = vc.code COLLATE utf8mb4_unicode_ci
                 AND av.voucher_ref IS NOT NULL 
                 AND av.voucher_ref COLLATE utf8mb4_unicode_ci != '' COLLATE utf8mb4_unicode_ci
             ) OR 
             EXISTS (
                 SELECT 1 FROM all_booking ab 
                 WHERE ab.voucher_code COLLATE utf8mb4_unicode_ci = vc.code COLLATE utf8mb4_unicode_ci
                 AND ab.voucher_code IS NOT NULL 
                 AND ab.voucher_code COLLATE utf8mb4_unicode_ci != '' COLLATE utf8mb4_unicode_ci
             ))
        GROUP BY vc.id, vc.code, vc.title, vc.valid_from, vc.valid_until, vc.max_uses, vc.voucher_type, vc.current_uses,
                 vc.applicable_locations, vc.applicable_experiences, vc.applicable_voucher_types,
                 vc.is_active, vc.created_by, vc.source_type, vc.customer_email, vc.paid_amount,
                 vc.created_at, vc.updated_at
        
        UNION ALL
        
        -- Also include voucher codes from all_vouchers that don't exist in voucher_codes yet
        SELECT 
            NULL as id,
            av.voucher_ref as code,
            CONCAT(COALESCE(av.name, ''), ' - ', COALESCE(av.voucher_type, ''), ' - ', COALESCE(av.preferred_location, '')) as title,
            NULL as valid_from,
            av.expires as valid_until,
            1 as max_uses,
            av.voucher_type as voucher_type,
            CASE WHEN av.redeemed COLLATE utf8mb4_unicode_ci = 'Yes' COLLATE utf8mb4_unicode_ci THEN 1 ELSE 0 END as current_uses,
            NULL as applicable_locations,
            NULL as applicable_experiences,
            NULL as applicable_voucher_types,
            CASE WHEN av.redeemed COLLATE utf8mb4_unicode_ci = 'Yes' COLLATE utf8mb4_unicode_ci THEN 0 ELSE 1 END as is_active,
            NULL as created_by,
            'user_generated' as source_type,
            COALESCE(av.email, av.purchaser_email) as customer_email,
            av.paid as paid_amount,
            av.created_at,
            NOW() as updated_at,
            0 as total_uses,
            '1/1' as usage_status
        FROM all_vouchers av
        WHERE av.voucher_ref IS NOT NULL 
        AND av.voucher_ref COLLATE utf8mb4_unicode_ci != '' COLLATE utf8mb4_unicode_ci
        AND av.voucher_ref COLLATE utf8mb4_unicode_ci != '-' COLLATE utf8mb4_unicode_ci
        AND av.voucher_ref COLLATE utf8mb4_unicode_ci != ' ' COLLATE utf8mb4_unicode_ci
        AND NOT EXISTS (
            SELECT 1 FROM voucher_codes vc2 
            WHERE vc2.code COLLATE utf8mb4_unicode_ci = av.voucher_ref COLLATE utf8mb4_unicode_ci
        )
        
        UNION ALL
        
        -- Also include voucher codes from all_booking that don't exist in voucher_codes yet
        SELECT 
            NULL as id,
            ab.voucher_code as code,
            CONCAT(COALESCE(ab.name, ''), ' - ', COALESCE(ab.voucher_type, ''), ' - ', COALESCE(ab.location, '')) as title,
            NULL as valid_from,
            ab.expires as valid_until,
            1 as max_uses,
            ab.voucher_type as voucher_type,
            CASE WHEN ab.redeemed_voucher COLLATE utf8mb4_unicode_ci = 'Yes' COLLATE utf8mb4_unicode_ci THEN 1 ELSE 0 END as current_uses,
            NULL as applicable_locations,
            NULL as applicable_experiences,
            NULL as applicable_voucher_types,
            CASE WHEN ab.redeemed_voucher COLLATE utf8mb4_unicode_ci = 'Yes' COLLATE utf8mb4_unicode_ci THEN 0 ELSE 1 END as is_active,
            NULL as created_by,
            'user_generated' as source_type,
            ab.email as customer_email,
            ab.paid as paid_amount,
            ab.created_at,
            NOW() as updated_at,
            0 as total_uses,
            '1/1' as usage_status
        FROM all_booking ab
        WHERE ab.voucher_code IS NOT NULL 
        AND ab.voucher_code COLLATE utf8mb4_unicode_ci != '' COLLATE utf8mb4_unicode_ci
        AND ab.voucher_code COLLATE utf8mb4_unicode_ci != '-' COLLATE utf8mb4_unicode_ci
        AND ab.voucher_code COLLATE utf8mb4_unicode_ci != ' ' COLLATE utf8mb4_unicode_ci
        -- Exclude booking IDs (numeric strings that match booking IDs)
        AND NOT EXISTS (
            SELECT 1 FROM all_booking ab2 
            WHERE CAST(ab2.id AS CHAR) COLLATE utf8mb4_unicode_ci = ab.voucher_code COLLATE utf8mb4_unicode_ci
        )
        AND NOT EXISTS (
            SELECT 1 FROM voucher_codes vc3 
            WHERE vc3.code COLLATE utf8mb4_unicode_ci = ab.voucher_code COLLATE utf8mb4_unicode_ci
        )
        AND NOT EXISTS (
            SELECT 1 FROM all_vouchers av2 
            WHERE av2.voucher_ref COLLATE utf8mb4_unicode_ci = ab.voucher_code COLLATE utf8mb4_unicode_ci
        )
        
        ORDER BY created_at DESC
    `;

    con.query(sql, (err, result) => {
        if (err) {
            console.error('Error fetching voucher codes:', err);
            return res.status(500).json({ success: false, message: 'Database error', error: err.message });
        }

        res.json({ success: true, data: result });
    });
});

// Create new voucher code
app.post('/api/voucher-codes', (req, res) => {
    const {
        code,
        title,
        valid_from,
        valid_until,
        max_uses,
        voucher_type,
        price_paid,
        applicable_locations,
        applicable_experiences,
        applicable_voucher_types
    } = req.body;

    // Validation
    if (!code || !title) {
        return res.status(400).json({ success: false, message: 'Missing required fields: code and title' });
    }

    const sql = `
        INSERT INTO voucher_codes (
            code, title, valid_from, valid_until, max_uses, voucher_type, paid_amount,
            applicable_locations, applicable_experiences, applicable_voucher_types
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `;

    const values = [
        code.toUpperCase(),
        title,
        valid_from || null,
        valid_until || null,
        max_uses || null,
        voucher_type || null,
        price_paid || null,
        applicable_locations || null,
        applicable_experiences || null,
        applicable_voucher_types || null
    ];

    con.query(sql, values, (err, result) => {
        if (err) {
            console.error('Error creating voucher code:', err);
            if (err.code === 'ER_DUP_ENTRY') {
                return res.status(400).json({ success: false, message: 'Voucher code already exists' });
            }
            return res.status(500).json({ success: false, message: 'Database error', error: err.message });
        }

        res.json({ success: true, message: 'Voucher code created successfully', id: result.insertId });
    });
});

// Update voucher code
app.put('/api/voucher-codes/:id', (req, res) => {
    const { id } = req.params;
    const {
        code,
        title,
        valid_from,
        valid_until,
        max_uses,
        voucher_type,
        price_paid,
        applicable_locations,
        applicable_experiences,
        applicable_voucher_types,
        is_active
    } = req.body;

    // Validation
    if (!code || !title) {
        return res.status(400).json({ success: false, message: 'Missing required fields: code and title' });
    }

    const sql = `
        UPDATE voucher_codes SET 
            code = ?, title = ?, valid_from = ?, valid_until = ?, 
            max_uses = ?, voucher_type = ?, paid_amount = ?, applicable_locations = ?, applicable_experiences = ?, 
            applicable_voucher_types = ?, is_active = ?, updated_at = NOW()
        WHERE id = ?
    `;

    const values = [
        code.toUpperCase(),
        title,
        valid_from || null,
        valid_until || null,
        max_uses || null,
        voucher_type || null,
        price_paid || null,
        applicable_locations || null,
        applicable_experiences || null,
        applicable_voucher_types || null,
        is_active !== undefined ? is_active : 1,
        id
    ];

    con.query(sql, values, (err, result) => {
        if (err) {
            console.error('Error updating voucher code:', err);
            return res.status(500).json({ success: false, message: 'Database error', error: err.message });
        }

        if (result.affectedRows === 0) {
            return res.status(404).json({ success: false, message: 'Voucher code not found' });
        }

        res.json({ success: true, message: 'Voucher code updated successfully' });
    });
});

// Delete voucher code
app.delete('/api/voucher-codes/:id', (req, res) => {
    const { id } = req.params;

    const sql = 'DELETE FROM voucher_codes WHERE id = ?';
    con.query(sql, [id], (err, result) => {
        if (err) {
            console.error('Error deleting voucher code:', err);
            return res.status(500).json({ success: false, message: 'Database error', error: err.message });
        }

        if (result.affectedRows === 0) {
            return res.status(404).json({ success: false, message: 'Voucher code not found' });
        }

        res.json({ success: true, message: 'Voucher code deleted successfully' });
    });
});

// Validate voucher code
app.post('/api/voucher-codes/validate', (req, res) => {
    const {
        code,
        location,
        experience,
        voucher_type,
        booking_amount
    } = req.body;

    console.log('Voucher validation request:', { code, location, experience, voucher_type, booking_amount });

    if (!code) {
        return res.status(400).json({ success: false, message: 'Voucher code is required' });
    }

    // Enforce single-use for codes (Voucher Codes Management entries)
    const sql = `
        SELECT * FROM voucher_codes 
        WHERE code = ? AND is_active = 1
        AND (valid_from IS NULL OR valid_from <= NOW())
        AND (valid_until IS NULL OR valid_until >= NOW())
        AND (
            (max_uses IS NULL AND COALESCE(current_uses,0) < 1) OR
            (max_uses IS NOT NULL AND COALESCE(current_uses,0) < max_uses)
        )
        AND (source_type = 'admin_created' OR source_type = 'user_generated')
    `;

    console.log('SQL query:', sql);
    console.log('SQL params:', [code.toUpperCase()]);

    con.query(sql, [code.toUpperCase()], (err, result) => {
        if (err) {
            console.error('Error validating voucher code:', err);
            return res.status(500).json({ success: false, message: 'Database error', error: err.message });
        }

        console.log('Database result:', result);

        if (result.length === 0) {
            console.log('No voucher_codes match. Falling back to all_vouchers/all_booking for voucher_ref/voucher_code...');
            // Query vouchers - order by expires DESC to get the one with latest expiry date (in case of duplicates)
            const fallbackSql = `
                SELECT * FROM (
                    SELECT 
                        v.id,
                        v.voucher_ref AS code_from_vouchers,
                        CASE WHEN v.expires IS NOT NULL THEN v.expires ELSE DATE_ADD(v.created_at, INTERVAL 24 MONTH) END AS computed_expires,
                        v.expires,
                        v.redeemed,
                        v.experience_type,
                        v.voucher_type,
                        NULL AS actual_voucher_type,
                        v.numberOfPassengers,
                        NULL AS pax,
                        v.created_at,
                        v.name,
                        NULL AS location,
                        v.preferred_location,
                        v.paid,
                        'voucher_ref' AS code_source
                    FROM all_vouchers v
                    WHERE UPPER(v.voucher_ref) = UPPER(?)
                    ORDER BY v.expires DESC, v.created_at DESC
                    LIMIT 1
                ) AS voucher_result
                UNION ALL
                SELECT * FROM (
                    SELECT 
                        b.id,
                        b.voucher_code AS code_from_vouchers,
                        NULL AS computed_expires,
                        b.expires,
                        NULL AS redeemed,
                        b.experience AS experience_type,
                        b.voucher_type AS voucher_type,
                        NULL AS actual_voucher_type,
                        NULL AS numberOfPassengers,
                        b.pax,
                        b.created_at,
                        b.name,
                        b.location,
                        NULL AS preferred_location,
                        b.paid,
                        'booking_voucher_code' AS code_source
                    FROM all_booking b
                    WHERE UPPER(b.voucher_code) = UPPER(?)
                    ORDER BY b.created_at DESC
                    LIMIT 1
                ) AS booking_result
                LIMIT 1
            `;
            con.query(fallbackSql, [code, code], (fbErr, fbRows) => {
                if (fbErr) {
                    console.error('Error in voucher fallback lookup:', fbErr);
                    return res.json({ success: false, message: 'Invalid or expired voucher code' });
                }
                if (!fbRows || fbRows.length === 0) {
                    return res.json({ success: false, message: 'Invalid or expired voucher code' });
                }
                const row = fbRows[0];
                // Basic checks for voucher_ref path
                if (row.code_source === 'voucher_ref') {
                    const now = new Date();
                    now.setHours(0, 0, 0, 0); // Reset time for accurate date comparison
                    
                    // Parse expires date properly - handle various formats
                    let exp = null;
                    if (row.computed_expires) {
                        const expDate = row.computed_expires;
                        // Check if it's already a Date object from MySQL
                        if (expDate instanceof Date) {
                            exp = expDate;
                        } else if (typeof expDate === 'string') {
                            // Try parsing as ISO format first, then DD/MM/YYYY
                            exp = new Date(expDate);
                            if (isNaN(exp.getTime())) {
                                // Try DD/MM/YYYY format
                                const parts = expDate.split(/[\/\-\.]/);
                                if (parts.length === 3) {
                                    // Assume DD/MM/YYYY format
                                    exp = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
                                }
                            }
                        }
                    }
                    
                    console.log('=== VOUCHER EXPIRY DEBUG ===');
                    console.log('Voucher code:', code);
                    console.log('Raw computed_expires:', row.computed_expires);
                    console.log('Parsed exp date:', exp);
                    console.log('Now:', now);
                    console.log('Is exp valid date?', exp && !isNaN(exp.getTime()));
                    if (exp && !isNaN(exp.getTime())) {
                        console.log('now > exp?', now > exp);
                    }
                    
                    // Check if voucher is redeemed - only reject if explicitly "yes" or "1" or true
                    const redeemedValue = row.redeemed ? String(row.redeemed).toLowerCase().trim() : '';
                    if (redeemedValue === 'yes' || redeemedValue === '1' || redeemedValue === 'true') {
                        return res.json({ success: false, message: 'Voucher already redeemed' });
                    }
                    // If redeemed is "No", "0", "false", or NULL, allow redemption
                    // Only check expiry if exp is a valid date
                    if (exp && !isNaN(exp.getTime())) {
                        exp.setHours(0, 0, 0, 0); // Reset time for accurate date comparison
                        if (now > exp) {
                            console.log('Voucher EXPIRED:', code);
                            return res.json({ success: false, message: 'Voucher code has expired' });
                        }
                    }
                    console.log('Voucher NOT expired:', code);
                }
                // Also validate when the code originates from booking table
                else if (row.code_source === 'booking_voucher_code') {
                    const now = new Date();
                    now.setHours(0, 0, 0, 0); // Reset time for accurate date comparison
                    
                    // Prefer explicit expires; otherwise compute 24 months from created_at if available
                    let exp = null;
                    if (row.expires) {
                        const expDate = row.expires;
                        // Handle various date formats
                        if (expDate instanceof Date) {
                            exp = expDate;
                        } else if (typeof expDate === 'string') {
                            exp = new Date(expDate);
                            if (isNaN(exp.getTime())) {
                                // Try DD/MM/YYYY format
                                const parts = expDate.split(/[\/\-\.]/);
                                if (parts.length === 3) {
                                    exp = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
                                }
                            }
                        }
                    } else if (row.created_at) {
                        const created = new Date(row.created_at);
                        if (!isNaN(created.getTime())) {
                            exp = new Date(created.getTime());
                            exp.setMonth(exp.getMonth() + 24);
                        }
                    }
                    
                    console.log('=== BOOKING VOUCHER EXPIRY DEBUG ===');
                    console.log('Voucher code:', code);
                    console.log('Raw expires:', row.expires);
                    console.log('Parsed exp date:', exp);
                    
                    // First check if voucher has expired - only if exp is valid
                    if (exp && !isNaN(exp.getTime())) {
                        exp.setHours(0, 0, 0, 0);
                        if (now > exp) {
                            return res.json({ success: false, message: 'Voucher code has expired. The expiration date has passed.' });
                        }
                    }
                    
                    // If code already exists on a booking, treat as redeemed/used
                    return res.json({ success: false, message: 'Voucher already redeemed' });
                }
                // Treat as valid for redeem flow
                // Build title: "name - voucher_type - location"
                const voucherName = row.name || 'Guest';
                const voucherType = row.voucher_type || row.actual_voucher_type || '';
                const voucherLocation = row.preferred_location || row.location || '';
                const titleParts = [voucherName];
                if (voucherType) titleParts.push(voucherType);
                if (voucherLocation) titleParts.push(voucherLocation);
                const title = titleParts.join(' - ');
                
                // Format valid_until date
                const validUntil = row.computed_expires || row.expires || null;
                const validUntilFormatted = validUntil ? new Date(validUntil).toISOString() : null;
                return res.json({
                    success: true,
                    message: 'Voucher code is valid',
                    data: {
                        code: code.toUpperCase(),
                        source: row.code_source,
                        // Prefer canonical fields if available
                        experience_type: row.experience_type || null,
                        voucher_type: row.voucher_type || row.actual_voucher_type || null,
                        // Provide expires for both voucher and booking sourced codes
                        expires: row.computed_expires || row.expires || null,
                        redeemed: row.redeemed || null,
                        final_amount: row.paid || booking_amount || 0, // Use voucher's paid amount, fallback to booking_amount
                        voucher_amount: row.paid || null, // Original voucher amount
                        numberOfPassengers: row.numberOfPassengers || row.pax || null,
                        // Frontend display fields
                        title: title,
                        name: voucherName,
                        location: voucherLocation,
                        discount_type: 'percentage', // Show as percentage for voucher redemption
                        discount_value: 0.00, // No discount for voucher redemption (0.00% off)
                        valid_until: validUntilFormatted
                    }
                });
            });
            return; // prevent continuing
        }

        const voucher = result[0];

        console.log('Voucher found:', {
            id: voucher.id,
            code: voucher.code,
            source_type: voucher.source_type,
            is_active: voucher.is_active,
            valid_from: voucher.valid_from,
            valid_until: voucher.valid_until,
            current_uses: voucher.current_uses,
            max_uses: voucher.max_uses
        });

        // For user generated codes, skip strict validation checks
        if (voucher.source_type === 'user_generated') {
            console.log('User generated voucher code - skipping strict validation checks');
        } else {
            // Check location restrictions (only for admin created codes)
            if (voucher.applicable_locations && location) {
                const locations = voucher.applicable_locations.split(',');
                if (!locations.includes(location)) {
                    return res.json({ success: false, message: 'Voucher code not valid for this location' });
                }
            }

            // Check experience restrictions (only for admin created codes)
            if (voucher.applicable_experiences && experience) {
                const experiences = voucher.applicable_experiences.split(',');
                if (!experiences.includes(experience)) {
                    return res.json({ success: false, message: 'Voucher code not valid for this experience' });
                }
            }

            // Check voucher type restrictions (only for admin created codes)
            if (voucher.applicable_voucher_types && voucher_type) {
                const types = voucher.applicable_voucher_types.split(',');
                if (!types.includes(voucher_type)) {
                    return res.json({ success: false, message: 'Voucher code not valid for this voucher type' });
                }
            }
        }

        // Try to enrich response with voucher details from all_vouchers/all_booking
        const detailsSql = `
            SELECT 
                v.experience_type,
                v.book_flight,
                v.voucher_type AS actual_voucher_type,
                v.voucher_type_detail,
                v.paid,
                v.redeemed,
                v.offer_code,
                v.voucher_ref,
                v.numberOfPassengers,
                v.created_at,
                v.expires
            FROM all_vouchers v
            WHERE v.voucher_ref = ?
            ORDER BY v.created_at DESC
            LIMIT 1
        `;
        con.query(detailsSql, [voucher.code], (dErr, dRows) => {
            if (dErr) {
                console.warn('Voucher detail lookup failed:', dErr.message);
            }
            let enriched = null;
            if (dRows && dRows.length > 0) {
                const v = dRows[0];
                
                // Extract voucher_type_detail from various sources
                let voucherTypeDetail = v.voucher_type_detail || null;
                
                // If voucher_type_detail is null, try to extract from title
                if (!voucherTypeDetail && voucher.title) {
                    const title = voucher.title.toLowerCase();
                    if (title.includes('weekday morning')) {
                        voucherTypeDetail = 'Weekday Morning';
                    } else if (title.includes('flexible weekday')) {
                        voucherTypeDetail = 'Flexible Weekday';
                    } else if (title.includes('any day') || title.includes('anytime')) {
                        voucherTypeDetail = 'Any Day Flight';
                    } else if (title.includes('private charter')) {
                        voucherTypeDetail = 'Private Charter';
                    } else if (title.includes('proposal flight')) {
                        voucherTypeDetail = 'Proposal Flight';
                    }
                }
                
                // If still null, try to extract from voucher_type field
                if (!voucherTypeDetail && v.actual_voucher_type) {
                    const voucherType = v.actual_voucher_type.toLowerCase();
                    if (voucherType.includes('weekday morning')) {
                        voucherTypeDetail = 'Weekday Morning';
                    } else if (voucherType.includes('flexible weekday')) {
                        voucherTypeDetail = 'Flexible Weekday';
                    } else if (voucherType.includes('any day') || voucherType.includes('anytime')) {
                        voucherTypeDetail = 'Any Day Flight';
                    } else if (voucherType.includes('private charter')) {
                        voucherTypeDetail = 'Private Charter';
                    } else if (voucherType.includes('proposal flight')) {
                        voucherTypeDetail = 'Proposal Flight';
                    }
                }
                
                // If still null, try to extract from book_flight
                if (!voucherTypeDetail && v.book_flight) {
                    const bookFlight = v.book_flight.toLowerCase();
                    if (bookFlight.includes('weekday morning')) {
                        voucherTypeDetail = 'Weekday Morning';
                    } else if (bookFlight.includes('flexible weekday')) {
                        voucherTypeDetail = 'Flexible Weekday';
                    } else if (bookFlight.includes('any day') || bookFlight.includes('anytime')) {
                        voucherTypeDetail = 'Any Day Flight';
                    } else if (bookFlight.includes('private charter')) {
                        voucherTypeDetail = 'Private Charter';
                    } else if (bookFlight.includes('proposal flight')) {
                        voucherTypeDetail = 'Proposal Flight';
                    }
                }
                
                enriched = {
                    experience: v.experience_type || null,
                    book_flight: v.book_flight || null,
                    paid: v.paid || 0,
                    redeemed: v.redeemed || null,
                    offer_code: v.offer_code || null,
                    voucher_ref: v.voucher_ref || voucher.code,
                    numberOfVouchers: v.numberOfPassengers || null,
                    created: v.created_at || null,
                    expires: v.expires || null,
                    voucher_type_detail: voucherTypeDetail // Use extracted voucher type detail
                };
            } else {
                // If no voucher found in all_vouchers, try to extract from voucher.title
                let voucherTypeDetail = null;
                if (voucher.title) {
                    const title = voucher.title.toLowerCase();
                    if (title.includes('weekday morning')) {
                        voucherTypeDetail = 'Weekday Morning';
                    } else if (title.includes('flexible weekday')) {
                        voucherTypeDetail = 'Flexible Weekday';
                    } else if (title.includes('any day') || title.includes('anytime')) {
                        voucherTypeDetail = 'Any Day Flight';
                    } else if (title.includes('private charter')) {
                        voucherTypeDetail = 'Private Charter';
                    } else if (title.includes('proposal flight')) {
                        voucherTypeDetail = 'Proposal Flight';
                    }
                }
                
                if (voucherTypeDetail) {
                    enriched = {
                        voucher_type_detail: voucherTypeDetail
                    };
                }
            }

            // Voucher code is valid (no discount calculation needed)
            const numberOfPassengersValue = voucher.max_uses || enriched?.numberOfVouchers || null;

            // Derive experience_type from voucher_type for Admin Created Codes (Shared vs Private)
            const vcVoucherType = (voucher.voucher_type || '').trim();
            const sharedVoucherTypes = ['Flexible Weekday', 'Flexible Weekday Flight', 'Weekday Morning', 'Weekday Morning Flight', 'Any Day Flight', 'Any Day', 'Anytime'];
            const privateVoucherTypes = ['Private Charter', 'Proposal Flight'];
            const isSharedVoucher = sharedVoucherTypes.some(t => vcVoucherType.toLowerCase() === t.toLowerCase());
            const isPrivateVoucher = privateVoucherTypes.some(t => vcVoucherType.toLowerCase() === t.toLowerCase());
            let derivedExperienceType = voucher.applicable_experiences || enriched?.experience || null;
            if (!derivedExperienceType && vcVoucherType) {
                derivedExperienceType = isPrivateVoucher ? 'Private Charter' : (isSharedVoucher ? 'Shared Flight' : null);
            }
            const voucherTypeDetail = voucher.voucher_type || enriched?.voucher_type_detail || voucher.applicable_voucher_types || null;

            res.json({
                success: true,
                message: 'Voucher code is valid',
                data: {
                    ...voucher,
                    // Keep response shape consistent with getAllVoucherData fields when possible
                    experience_type: derivedExperienceType,
                    voucher_type: voucher.voucher_type || voucher.applicable_voucher_types || enriched?.actual_voucher_type || null,
                    voucher_type_detail: voucherTypeDetail,
                    final_amount: booking_amount, // No discount applied
                    // Use max_uses as numberOfPassengers (max_uses represents Number of Passengers in voucher_codes table)
                    numberOfPassengers: numberOfPassengersValue,
                    // Extra detail block for Redeem Voucher UI
                    detail: enriched
                }
            });
        });
    });
});

// Get voucher code usage
app.get('/api/voucher-codes/:id/usage', (req, res) => {
    const { id } = req.params;

    const sql = `
        SELECT 
            vcu.*,
            ab.booking_reference,
            ab.customer_name,
            ab.customer_email,
            ab.total_amount as original_amount,
            ab.voucher_discount,
            (ab.total_amount - ab.voucher_discount) as final_amount
        FROM voucher_code_usage vcu
        LEFT JOIN all_booking ab ON vcu.booking_id = ab.id
        WHERE vcu.voucher_code_id = ?
        ORDER BY vcu.used_at DESC
    `;

    con.query(sql, [id], (err, result) => {
        if (err) {
            console.error('Error fetching voucher usage:', err);
            return res.status(500).json({ success: false, message: 'Database error', error: err.message });
        }

        res.json({ success: true, data: result });
    });
});

// Simple booking creation for Redeem Voucher
app.post('/api/createRedeemBooking', (req, res) => {
    let {
        activitySelect,
        chooseLocation,
        chooseFlightType,
        passengerData,
        additionalInfo,
        selectedDate: reqSelectedDate,
        selectedTime,
        voucher_code: reqVoucherCode,
        totalPrice = 0,
        activity_id,
        userSessionData,
        source_booking_id
    } = req.body;

    additionalInfo = normalizeAdditionalInfoPayload(additionalInfo);

    // Basic validation
    if (!chooseLocation || !chooseFlightType || !passengerData || !passengerData[0]) {
        return res.status(400).json({ success: false, error: 'Missing required booking information' });
    }

    // Trim voucher code to remove whitespace and tab characters
    const cleanVoucherCode = reqVoucherCode ? String(reqVoucherCode).trim() : 'no-voucher';
    const selectedDate = reqSelectedDate || 'no-date';
    const passengerEmail = passengerData?.[0]?.email || 'no-email';
    // Prevent duplicate requests: use a request ID or combination of key fields
    // Store in-memory to prevent same request from being processed multiple times
    // Create a simpler key for duplicate detection (without timestamp)
    const duplicateKey = `${cleanVoucherCode}-${selectedDate}-${passengerEmail}`;
    
    // Check if this exact request is already being processed (simple in-memory cache)
    // Note: This is a basic protection. For production, consider using Redis or a more robust solution
    if (!global.redeemBookingRequests) {
        global.redeemBookingRequests = new Map(); // Use Map to store timestamp with key
    }
    
    // Check if request is already in progress (within last 10 seconds)
    const existingRequest = global.redeemBookingRequests.get(duplicateKey);
    if (existingRequest && (Date.now() - existingRequest < 10000)) {
        console.warn('⚠️ Duplicate createRedeemBooking request detected, ignoring:', duplicateKey);
        return res.status(400).json({ success: false, error: 'Duplicate request detected. Please wait a moment and try again.' });
    }
    
    // Add request to processing map with current timestamp
    global.redeemBookingRequests.set(duplicateKey, Date.now());
    
    // Clean up old requests (older than 30 seconds) periodically
    setTimeout(() => {
        if (global.redeemBookingRequests) {
            const now = Date.now();
            for (const [key, timestamp] of global.redeemBookingRequests.entries()) {
                if (now - timestamp > 30000) {
                    global.redeemBookingRequests.delete(key);
                }
            }
        }
    }, 30000);
    
    // Use cleanVoucherCode for further processing (convert 'no-voucher' to null)
    const cleanVoucherCodeForValidation = cleanVoucherCode === 'no-voucher' ? null : cleanVoucherCode;

    // Redeem Voucher REQUIRES a valid voucher code - reject if missing
    if (!cleanVoucherCodeForValidation || (typeof cleanVoucherCodeForValidation === 'string' && cleanVoucherCodeForValidation.trim() === '')) {
        if (global.redeemBookingRequests) {
            global.redeemBookingRequests.delete(duplicateKey);
        }
        return res.status(400).json({ success: false, error: 'Voucher code is required for Redeem Voucher bookings. Please enter and validate your voucher code before booking.' });
    }

    // Validate voucher code is not already used (check both voucher_codes and all_vouchers tables)
    if (cleanVoucherCodeForValidation) {
        // First check voucher_codes table
        const checkVoucherCodesSql = `
            SELECT code, is_active, current_uses, max_uses 
            FROM voucher_codes 
            WHERE UPPER(code) = UPPER(?)
            LIMIT 1
        `;

        con.query(checkVoucherCodesSql, [cleanVoucherCodeForValidation], (checkErr, checkResult) => {
            if (checkErr) {
                // If voucher_codes table doesn't exist or query fails, check all_vouchers instead
                console.warn('Warning: Could not check voucher_codes table:', checkErr.message);
                checkAllVouchers();
                return;
            }

            if (checkResult.length > 0) {
                const voucherCode = checkResult[0];
                console.log('=== VOUCHER CODE VALIDATION (voucher_codes) ===');
                console.log('Voucher Code:', voucherCode.code);
                console.log('Is Active:', voucherCode.is_active);
                console.log('Current Uses:', voucherCode.current_uses);
                console.log('Max Uses:', voucherCode.max_uses);

                // Check if inactive (already used)
                if (voucherCode.is_active === 0 || voucherCode.is_active === false) {
                    return res.status(400).json({
                        success: false,
                        error: 'This voucher code has already been used and cannot be redeemed again'
                    });
                }

                // Check if max uses reached
                if (voucherCode.max_uses && voucherCode.current_uses >= voucherCode.max_uses) {
                    return res.status(400).json({
                        success: false,
                        error: 'This voucher code has reached its maximum number of uses'
                    });
                }

                // Voucher is valid, proceed
                createRedeemBookingLogic();
            } else {
                // Not found in voucher_codes, check all_vouchers table
                console.log('Voucher code not found in voucher_codes table, checking all_vouchers...');
                checkAllVouchers();
            }
        });

        // Function to check all_vouchers table
        function checkAllVouchers() {
            const checkAllVouchersSql = `
                SELECT voucher_ref, redeemed, status, name
                FROM all_vouchers 
                WHERE UPPER(voucher_ref) = UPPER(?)
                LIMIT 1
            `;

            con.query(checkAllVouchersSql, [cleanVoucherCodeForValidation], (voucherErr, voucherResult) => {
                if (voucherErr) {
                    console.warn('Warning: Could not check all_vouchers table:', voucherErr.message);
                    // Can't validate, proceed with booking (risky but allows operation)
                    createRedeemBookingLogic();
                    return;
                }

                if (voucherResult.length > 0) {
                    const voucher = voucherResult[0];
                    console.log('=== VOUCHER CODE VALIDATION (all_vouchers) ===');
                    console.log('Voucher Code:', voucher.voucher_ref);
                    console.log('Redeemed:', voucher.redeemed);
                    console.log('Status:', voucher.status);
                    console.log('Name:', voucher.name);

                    // Check if already redeemed by checking voucher_code_usage table
                    // This is more reliable as it tracks which voucher codes were used for which bookings
                    const checkRedeemedBookingSql = `
                        SELECT vcu.id, vcu.booking_id, vc.code
                        FROM voucher_code_usage vcu
                        INNER JOIN voucher_codes vc ON vc.id = vcu.voucher_code_id
                        WHERE UPPER(vc.code) = UPPER(?)
                        AND EXISTS (
                            SELECT 1 FROM all_booking ab 
                            WHERE ab.id = vcu.booking_id 
                            AND (ab.redeemed_voucher = 'Yes' OR ab.redeemed_voucher = 1 OR ab.flight_type_source = 'Redeem Voucher')
                        )
                        LIMIT 1
                    `;
                    
                    con.query(checkRedeemedBookingSql, [cleanVoucherCodeForValidation], (redeemedCheckErr, redeemedCheckResult) => {
                        if (redeemedCheckErr) {
                            console.warn('Warning: Could not check voucher_code_usage for redeemed status:', redeemedCheckErr.message);
                            // Fallback: check all_booking table
                            const fallbackCheckSql = `
                                SELECT id, redeemed_voucher
                                FROM all_booking 
                                WHERE UPPER(voucher_code) = UPPER(?)
                                AND (redeemed_voucher = 'Yes' OR redeemed_voucher = 1)
                                LIMIT 1
                            `;
                            con.query(fallbackCheckSql, [cleanVoucherCodeForValidation], (fallbackErr, fallbackResult) => {
                                if (fallbackErr || (fallbackResult && fallbackResult.length > 0)) {
                                    // Remove request from processing map
                                    if (global.redeemBookingRequests) {
                                        global.redeemBookingRequests.delete(duplicateKey);
                                    }
                                    return res.status(400).json({
                                        success: false,
                                        error: 'This voucher has already been redeemed and cannot be used again'
                                    });
                                }
                                // If we can't check, only block if status is explicitly 'Used'
                                if (voucher.status === 'Used') {
                                    // Remove request from processing map
                                    if (global.redeemBookingRequests) {
                                        global.redeemBookingRequests.delete(duplicateKey);
                                    }
                                    return res.status(400).json({
                                        success: false,
                                        error: 'This voucher has already been redeemed and cannot be used again'
                                    });
                                }
                                // Otherwise, proceed with booking
                                createRedeemBookingLogic();
                            });
                            return;
                        }

                        // If there's a booking with redeemed_voucher = 'Yes', block it
                        if (redeemedCheckResult.length > 0) {
                            console.log('Voucher already redeemed - found booking via voucher_code_usage');
                            // Remove request from processing map
                            if (global.redeemBookingRequests) {
                                global.redeemBookingRequests.delete(duplicateKey);
                            }
                            return res.status(400).json({
                                success: false,
                                error: 'This voucher has already been redeemed and cannot be used again'
                            });
                        }

                        // No redeemed booking found, voucher is valid
                        console.log('Voucher is valid - no redeemed booking found');
                        createRedeemBookingLogic();
                    });
                } else {
                    // Not found in either table - check all_booking for voucher_code
                    console.log('Voucher not found in all_vouchers, checking all_booking...');
                    checkAllBooking();
                }
            });
        }

        // Function to check all_booking table for previously used voucher codes
        function checkAllBooking() {
            const checkBookingSql = `
                SELECT voucher_code, name, redeemed_voucher, created_at
                FROM all_booking 
                WHERE UPPER(voucher_code) = UPPER(?)
                LIMIT 1
            `;

            con.query(checkBookingSql, [cleanVoucherCode], (bookingErr, bookingResult) => {
                if (bookingErr) {
                    console.warn('Warning: Could not check all_booking table:', bookingErr.message);
                    // Can't validate, proceed with booking
                    createRedeemBookingLogic();
                    return;
                }

                if (bookingResult.length > 0) {
                    const booking = bookingResult[0];
                    console.log('=== VOUCHER CODE FOUND IN ALL_BOOKING ===');
                    console.log('Voucher Code:', booking.voucher_code);
                    console.log('Previously used by:', booking.name);
                    console.log('Used on:', booking.created_at);
                    console.log('Redeemed Voucher Status:', booking.redeemed_voucher);

                    // Only block if this booking was created by redeeming a voucher (redeemed_voucher = 'Yes')
                    // If redeemed_voucher is 'No' or NULL, it means this is a regular booking that happened to use
                    // the same voucher_code (which shouldn't happen, but we allow it to avoid false positives)
                    // The key check is: if redeemed_voucher = 'Yes', then this voucher was already redeemed
                    if (booking.redeemed_voucher === 'Yes' || booking.redeemed_voucher === 1) {
                        return res.status(400).json({
                            success: false,
                            error: 'This voucher has already been redeemed and cannot be used again'
                        });
                    }

                    // If redeemed_voucher is not 'Yes', this might be a regular booking with the same code
                    // Check all_vouchers table to see if the voucher itself is redeemed
                    const checkVoucherRedeemedSql = `
                        SELECT redeemed, status
                        FROM all_vouchers 
                        WHERE UPPER(voucher_ref) = UPPER(?)
                        LIMIT 1
                    `;
                    
                    con.query(checkVoucherRedeemedSql, [cleanVoucherCode], (voucherCheckErr, voucherCheckResult) => {
                        if (voucherCheckErr) {
                            console.warn('Warning: Could not check all_vouchers for redeemed status:', voucherCheckErr.message);
                            // If we can't check, allow the booking to proceed
                            createRedeemBookingLogic();
                            return;
                        }

                        if (voucherCheckResult.length > 0) {
                            const voucher = voucherCheckResult[0];
                            // Only block if voucher is explicitly marked as redeemed
                            if (voucher.redeemed === 'Yes' || voucher.status === 'Used') {
                                return res.status(400).json({
                                    success: false,
                                    error: 'This voucher has already been redeemed and cannot be used again'
                                });
                            }
                        }

                        // Voucher not redeemed, proceed with booking
                        console.log('Voucher code found in all_booking but not redeemed, proceeding with new booking');
                        createRedeemBookingLogic();
                    });
                    return;
                }

                // Voucher code not found anywhere, proceed with booking
                console.log('Voucher code not found in any table, proceeding with new booking');
                createRedeemBookingLogic();
            });
        }

        return; // Exit here and continue in callback
    }

    function createRedeemBookingLogic() {
        // Ensure booking name uses the first passenger (Passenger 1) from passengerData
        // passengerData should already be in the correct order (Passenger 1 first, Passenger 2 second, etc.)
        // This matches the order displayed in Flight Voucher Details
        const firstPassenger = passengerData && passengerData.length > 0 ? passengerData[0] : null;
        const passengerName = firstPassenger 
            ? `${firstPassenger.firstName || ''} ${firstPassenger.lastName || ''}`.trim()
            : 'Guest';
        
        // Log passenger data order for debugging
        console.log('🔄 createRedeemBooking - Passenger data order:', passengerData?.map((p, i) => ({
            index: i,
            name: `${p.firstName || ''} ${p.lastName || ''}`.trim()
        })));
        console.log('🔄 createRedeemBooking - Booking name (from Passenger 1):', passengerName);
        
        const now = new Date().toISOString().slice(0, 19).replace('T', ' ');

        // Format booking date
        let bookingDateTime = selectedDate;
        if (selectedDate && selectedTime) {
            let datePart;
            // Handle UTC ISO format (e.g., "2026-04-29T23:00:00.000Z")
            // Parse as local time to avoid timezone conversion
            if (typeof selectedDate === 'string' && selectedDate.includes('T') && selectedDate.endsWith('Z')) {
                // UTC ISO format: parse as local time
                const utcDate = new Date(selectedDate);
                const year = utcDate.getFullYear();
                const month = String(utcDate.getMonth() + 1).padStart(2, '0');
                const day = String(utcDate.getDate()).padStart(2, '0');
                datePart = `${year}-${month}-${day}`;
            } else if (typeof selectedDate === 'string' && selectedDate.includes(' ')) {
                // Already has space (e.g., "2026-04-30 07:00:00")
                datePart = selectedDate.split(' ')[0];
            } else if (typeof selectedDate === 'string' && selectedDate.length >= 10) {
                // Plain date string (e.g., "2026-04-30")
                datePart = selectedDate.substring(0, 10);
            } else {
                datePart = selectedDate;
            }
            bookingDateTime = `${datePart} ${selectedTime}`;
        } else if (selectedDate) {
            // If no selectedTime, use selectedDate as-is (might already include time)
            // Handle UTC ISO format
            if (typeof selectedDate === 'string' && selectedDate.includes('T') && selectedDate.endsWith('Z')) {
                const utcDate = new Date(selectedDate);
                const year = utcDate.getFullYear();
                const month = String(utcDate.getMonth() + 1).padStart(2, '0');
                const day = String(utcDate.getDate()).padStart(2, '0');
                const hour = String(utcDate.getHours()).padStart(2, '0');
                const minute = String(utcDate.getMinutes()).padStart(2, '0');
                const second = String(utcDate.getSeconds()).padStart(2, '0');
                bookingDateTime = `${year}-${month}-${day} ${hour}:${minute}:${second}`;
            } else {
                bookingDateTime = selectedDate;
            }
        } else {
            // Fallback to current timestamp if no date provided
            bookingDateTime = now;
        }

        console.log('=== REDEEM BOOKING DATE FORMAT ===');
        console.log('selectedDate:', selectedDate);
        console.log('selectedTime:', selectedTime);
        console.log('Final bookingDateTime:', bookingDateTime);

        let sourceBookingAdditionalInfo = null;
        const sourceBookingId = source_booking_id && !isNaN(parseInt(source_booking_id, 10))
            ? parseInt(source_booking_id, 10)
            : null;

        const continueCreateRedeemBooking = () => {

        // Get voucher information (created_at, voucher_type, experience_type) and price
        if (cleanVoucherCodeForValidation) {
            // First, get voucher info from all_vouchers table (including paid amount)
            const getVoucherInfoSql = `
            SELECT created_at, voucher_type, experience_type, book_flight, paid, expires
            FROM all_vouchers 
            WHERE UPPER(voucher_ref) = UPPER(?)
            LIMIT 1
        `;

            con.query(getVoucherInfoSql, [cleanVoucherCodeForValidation], (voucherInfoErr, voucherInfoResult) => {
                if (voucherInfoErr) {
                    console.warn('Warning: Could not fetch voucher info:', voucherInfoErr.message);
                    // Voucher bilgisi alınamazsa, sadece fiyat bilgisini al
                    getVoucherPriceOnly();
                    return;
                }

                let voucherCreatedAt = null;
                let voucherType = null;
                let experienceType = null;
                let voucherPaidFromAllVouchers = null;

                if (voucherInfoResult.length > 0) {
                    voucherCreatedAt = voucherInfoResult[0].created_at;
                    voucherType = voucherInfoResult[0].voucher_type;
                    experienceType = voucherInfoResult[0].experience_type;
                    voucherPaidFromAllVouchers = voucherInfoResult[0].paid;
                    console.log('✅ Voucher info found:', {
                        created_at: voucherCreatedAt,
                        voucher_type: voucherType,
                        experience_type: experienceType,
                        paid: voucherPaidFromAllVouchers
                    });
                }

                // Now get price from voucher_codes table (fallback if not in all_vouchers)
                const getVoucherPriceSql = `
            SELECT paid_amount 
            FROM voucher_codes 
            WHERE UPPER(code) = UPPER(?)
            LIMIT 1
        `;

                con.query(getVoucherPriceSql, [cleanVoucherCode], (priceErr, priceResult) => {
                    // Priority: 1. all_vouchers.paid, 2. voucher_codes.paid_amount, 3. totalPrice
                    let voucherOriginalPrice = totalPrice || 0;

                    if (voucherPaidFromAllVouchers != null && voucherPaidFromAllVouchers > 0) {
                        voucherOriginalPrice = parseFloat(voucherPaidFromAllVouchers) || 0;
                        console.log('✅ Found original voucher price from all_vouchers.paid:', voucherOriginalPrice);
                    } else if (!priceErr && priceResult.length > 0 && priceResult[0].paid_amount) {
                        voucherOriginalPrice = parseFloat(priceResult[0].paid_amount) || 0;
                        console.log('✅ Found original voucher price from voucher_codes.paid_amount:', voucherOriginalPrice);
                    } else {
                        console.log('⚠️ Could not find voucher price, using totalPrice:', voucherOriginalPrice);
                    }

                    // Prefer all_vouchers.expires (purchase validity); else created_at + duration
                    let expiresDate = null;
                    if (voucherInfoResult.length > 0) {
                        const vr = voucherInfoResult[0];
                        const chooseFt = vr.experience_type ? { type: vr.experience_type } : chooseFlightType;
                        expiresDate = resolveBookingExpiresFromVoucherRow(vr, chooseFt, null, voucherType);
                        if (expiresDate) {
                            console.log('✅ Expire date from voucher row (expires or created_at+duration):', {
                                storedExpires: vr.expires,
                                voucherCreatedAt: vr.created_at,
                                expiresDate
                            });
                        }
                    }
                    if (voucherCreatedAt && !expiresDate) {
                        // Voucher türüne göre expire süresini belirle
                        let durationMonths = 24; // Default

                        if (experienceType === 'Private Charter') {
                            durationMonths = 18;
                        } else if (experienceType === 'Shared Flight') {
                            // Shared Flight: Any Day Flight = 24 ay, diğerleri = 18 ay
                            if (voucherType === 'Any Day Flight') {
                                durationMonths = 24;
                            } else {
                                durationMonths = 18;
                            }
                        }

                        // Voucher'ın created_at tarihinden itibaren hesapla
                        expiresDate = moment(voucherCreatedAt).add(durationMonths, 'months').format('YYYY-MM-DD HH:mm:ss');
                        console.log('✅ Expire date calculated (legacy from created_at):', {
                            voucherCreatedAt,
                            durationMonths,
                            expiresDate
                        });
                    } else if (!voucherCreatedAt) {
                        // Voucher bilgisi yoksa, bugünden itibaren hesapla
                        if (chooseFlightType && chooseFlightType.type === 'Private Charter') {
                            expiresDate = moment().add(18, 'months').format('YYYY-MM-DD HH:mm:ss');
                        } else if (chooseFlightType && chooseFlightType.type === 'Shared Flight') {
                            // Shared Flight için voucher_type bilgisi yoksa, default 18 ay
                            expiresDate = moment().add(18, 'months').format('YYYY-MM-DD HH:mm:ss');
                        } else {
                            expiresDate = moment().add(24, 'months').format('YYYY-MM-DD HH:mm:ss');
                        }
                        console.log('⚠️ Voucher info not found, using current date for expire calculation');
                    }

                    // Continue with booking creation using the original voucher price, expire date and voucherType
                    createBookingWithPrice(voucherOriginalPrice, expiresDate, voucherType);
                });
            });

            // Fallback function to get only price if voucher info query fails
            function getVoucherPriceOnly() {
                const getVoucherPaidSql = `
                    SELECT paid, created_at, expires, voucher_type, experience_type
                    FROM all_vouchers 
                    WHERE UPPER(voucher_ref) = UPPER(?)
                    LIMIT 1
                `;

                con.query(getVoucherPaidSql, [cleanVoucherCodeForValidation], (voucherPaidErr, voucherPaidResult) => {
                    let voucherOriginalPrice = totalPrice || 0;
                    const voucherRow = (!voucherPaidErr && voucherPaidResult.length > 0) ? voucherPaidResult[0] : null;

                    function resolveExpiresDateFallback() {
                        if (voucherRow) {
                            const chooseFt = voucherRow.experience_type ? { type: voucherRow.experience_type } : chooseFlightType;
                            const fromRow = resolveBookingExpiresFromVoucherRow(voucherRow, chooseFt, null, voucherRow.voucher_type);
                            if (fromRow) return fromRow;
                        }
                        if (chooseFlightType && chooseFlightType.type === 'Private Charter') {
                            return moment().add(18, 'months').format('YYYY-MM-DD HH:mm:ss');
                        }
                        if (chooseFlightType && chooseFlightType.type === 'Shared Flight') {
                            return moment().add(18, 'months').format('YYYY-MM-DD HH:mm:ss');
                        }
                        return moment().add(24, 'months').format('YYYY-MM-DD HH:mm:ss');
                    }

                    function finishWithPrice(price) {
                        const expiresDate = resolveExpiresDateFallback();
                        const vt = voucherRow && voucherRow.voucher_type ? voucherRow.voucher_type : null;
                        createBookingWithPrice(price, expiresDate, vt);
                    }

                    if (voucherRow && voucherRow.paid != null && voucherRow.paid > 0) {
                        voucherOriginalPrice = parseFloat(voucherRow.paid) || 0;
                        console.log('✅ Found original voucher price from all_vouchers.paid (fallback):', voucherOriginalPrice);
                        finishWithPrice(voucherOriginalPrice);
                        return;
                    }

                    const getVoucherPriceSql = `
                SELECT paid_amount 
                FROM voucher_codes 
                WHERE UPPER(code) = UPPER(?)
                LIMIT 1
            `;

                    con.query(getVoucherPriceSql, [cleanVoucherCode], (priceErr, priceResult) => {
                        if (!priceErr && priceResult.length > 0 && priceResult[0].paid_amount) {
                            voucherOriginalPrice = parseFloat(priceResult[0].paid_amount) || 0;
                            console.log('✅ Found original voucher price from voucher_codes.paid_amount (fallback):', voucherOriginalPrice);
                        } else {
                            console.log('⚠️ Could not find voucher price, using totalPrice (fallback):', voucherOriginalPrice);
                        }
                        finishWithPrice(voucherOriginalPrice);
                    });
                });
            }
        } else {
            // No voucher code, use totalPrice and calculate expire from now
            let expiresDate = null;
            if (chooseFlightType && chooseFlightType.type === 'Private Charter') {
                expiresDate = moment().add(18, 'months').format('YYYY-MM-DD HH:mm:ss');
            } else if (chooseFlightType && chooseFlightType.type === 'Shared Flight') {
                expiresDate = moment().add(18, 'months').format('YYYY-MM-DD HH:mm:ss');
            } else {
                expiresDate = moment().add(24, 'months').format('YYYY-MM-DD HH:mm:ss');
            }
            createBookingWithPrice(totalPrice || 0, expiresDate, null);
        }

        function createBookingWithPrice(paidAmount, expiresDateFinal, resolvedVoucherType) {
            console.log('=== CREATING BOOKING WITH PAID AMOUNT:', paidAmount, 'AND EXPIRE DATE:', expiresDateFinal, '===');

            // Generate a new voucher code for this booking (Redeem Voucher creates a Book Flight booking)
            const generateNewVoucherCode = (callback) => {
                const year = new Date().getFullYear().toString().slice(-2); // Get last 2 digits of year
                
                // Map flight types to category codes
                const categoryMap = {
                    'Weekday Morning': 'WM',
                    'Weekday Flex': 'WF',
                    'Anytime': 'AT',
                    'Any Day Flight': 'AT',
                    'Flexible Weekday': 'WF',
                    'Shared Flight': 'AT' // Default for Shared Flight
                };
                
                // Determine category code from resolvedVoucherType or chooseFlightType
                let categoryCode = 'AT'; // Default
                if (resolvedVoucherType && categoryMap[resolvedVoucherType]) {
                    categoryCode = categoryMap[resolvedVoucherType];
                } else if (chooseFlightType && chooseFlightType.type) {
                    // Try to map from flight type
                    const flightTypeMap = {
                        'Private Charter': 'AT',
                        'Shared Flight': 'AT'
                    };
                    categoryCode = flightTypeMap[chooseFlightType.type] || 'AT';
                }
                
                const prefix = 'B'; // 'B' for Book Flight (Redeem Voucher creates a Book Flight booking)
                
                // Generate unique serial (3 characters)
                const generateSerial = () => {
                    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
                    let result = '';
                    for (let i = 0; i < 3; i++) {
                        result += chars.charAt(Math.floor(Math.random() * chars.length));
                    }
                    return result;
                };
                
                // Generate unique voucher code
                let voucherCode;
                let isUnique = false;
                let attempts = 0;
                const maxAttempts = 10;
                
                const tryGenerateCode = () => {
                    if (attempts >= maxAttempts) {
                        console.error('Failed to generate unique voucher code after', maxAttempts, 'attempts');
                        return callback(null);
                    }
                    
                    const serial = generateSerial();
                    voucherCode = `${prefix}${categoryCode}${year}${serial}`;
                    
                    // Check if code already exists in both tables
                    const checkSql = `
                        SELECT id FROM all_vouchers WHERE voucher_ref = ?
                        UNION
                        SELECT id FROM all_booking WHERE voucher_code = ?
                    `;
                    
                    con.query(checkSql, [voucherCode, voucherCode], (checkErr, checkResult) => {
                        if (checkErr) {
                            console.error('Error checking voucher code uniqueness:', checkErr);
                            return callback(null);
                        }
                        
                        if (checkResult.length === 0) {
                            // Code is unique
                            isUnique = true;
                            console.log('✅ Generated new voucher code for Redeem Voucher booking:', voucherCode);
                            callback(voucherCode);
                        } else {
                            // Code exists, try again
                            attempts++;
                            setTimeout(tryGenerateCode, 10);
                        }
                    });
                };
                
                tryGenerateCode();
            };

            // Generate new voucher code first, then create booking
            generateNewVoucherCode((newVoucherCode) => {
                if (!newVoucherCode) {
                    console.warn('⚠️ Failed to generate new voucher code, using redeemed voucher code as fallback');
                    // Fallback to using redeemed voucher code if generation fails
                    createBookingWithGeneratedCode(cleanVoucherCodeForValidation);
                    return;
                }

                // First, ensure the REDEEMED voucher code exists in voucher_codes table (for foreign key constraint)
                // This is the voucher code that will be stored in booking.voucher_code
                const redeemedVoucherCodeTitle = `${passengerName} - Redeemed Flight Voucher - ${chooseLocation}`;
                const redeemedVoucherCodeSql = `
                    INSERT INTO voucher_codes (
                        code, title, valid_from, valid_until, max_uses, current_uses,
                        applicable_locations, applicable_experiences, applicable_voucher_types,
                        is_active, created_at, updated_at, source_type, customer_email, paid_amount
                    ) VALUES (?, ?, NOW(), ?, 1, 1, ?, ?, ?, 0, NOW(), NOW(), 'redeemed_voucher', ?, ?)
                    ON DUPLICATE KEY UPDATE 
                        current_uses = current_uses + 1,
                        is_active = 0,
                        updated_at = NOW()
                `;
                
                const validUntil = expiresDateFinal ? moment(expiresDateFinal).format('YYYY-MM-DD') : moment().add(24, 'months').format('YYYY-MM-DD');
                
                const redeemedVoucherCodeValues = [
                    cleanVoucherCode,
                    redeemedVoucherCodeTitle,
                    validUntil,
                    chooseLocation || null,
                    resolvedVoucherType || null,
                    resolvedVoucherType || null,
                    passengerData[0].email || null,
                    paidAmount || 0
                ];
                
                // Create voucher_codes entry for the redeemed voucher code first
                con.query(redeemedVoucherCodeSql, redeemedVoucherCodeValues, (redeemedVoucherCodeErr) => {
                    if (redeemedVoucherCodeErr) {
                        console.warn('⚠️ Warning: Could not create voucher_codes entry for redeemed voucher code:', redeemedVoucherCodeErr.message);
                        // Continue anyway - will handle foreign key error in fallback
                    } else {
                        console.log('✅ Created/updated voucher_codes entry for redeemed voucher code:', cleanVoucherCode);
                    }
                    
                    // Now create voucher_codes entry for the new voucher code
                    const title = `${passengerName} - Book Flight - ${chooseLocation}`;
                    const voucherCodeSql = `
                        INSERT INTO voucher_codes (
                            code, title, valid_from, valid_until, max_uses, current_uses,
                            applicable_locations, applicable_experiences, applicable_voucher_types,
                            is_active, created_at, updated_at, source_type, customer_email, paid_amount
                        ) VALUES (?, ?, NOW(), ?, 1, 0, ?, ?, ?, 1, NOW(), NOW(), 'redeem_booking', ?, ?)
                    `;
                    
                    const voucherCodeValues = [
                        newVoucherCode,
                        title,
                        validUntil,
                        chooseLocation || null,
                        resolvedVoucherType || null,
                        resolvedVoucherType || null,
                        passengerData[0].email || null,
                        paidAmount || 0
                    ];
                    
                    con.query(voucherCodeSql, voucherCodeValues, (voucherCodeErr) => {
                        if (voucherCodeErr) {
                            console.warn('⚠️ Warning: Could not create voucher_codes entry for new voucher code:', voucherCodeErr.message);
                            // Continue with booking creation even if voucher_codes entry fails
                        } else {
                            console.log('✅ Created voucher_codes entry for new voucher code:', newVoucherCode);
                        }
                        
                        // Proceed with booking creation using the REDEEMED voucher code (cleanVoucherCode)
                        // newVoucherCode is passed to createBookingWithGeneratedCode but booking.voucher_code will use cleanVoucherCode
                        createBookingWithGeneratedCode(newVoucherCode);
                    });
                });
            });

            function createBookingWithGeneratedCode(generatedVoucherCode) {
                // Simple SQL with only essential columns (including expires, flight_attempts, flight_type_source, voucher_type, experience)
                const bookingSql = `
        INSERT INTO all_booking (
            name,
            flight_type, 
            flight_date, 
            pax, 
            location, 
            status, 
            paid, 
            due,
            voucher_code,
            created_at,
            expires,
            email,
            phone,
            activity_id,
            redeemed_voucher,
            flight_attempts,
            flight_type_source,
            voucher_type,
            voucher_type_detail,
            experience
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `;

                // Use actual passenger count from passengerData array
                const actualPaxCount = (Array.isArray(passengerData) && passengerData.length > 0) ? passengerData.length : (parseInt(chooseFlightType.passengerCount) || 1);
                console.log('=== REDEEM BOOKING PAX COUNT DEBUG ===');
                console.log('passengerData.length:', passengerData?.length);
                console.log('chooseFlightType.passengerCount:', chooseFlightType.passengerCount);
                console.log('actualPaxCount (FINAL):', actualPaxCount);
                console.log('activity_id:', activity_id);
                console.log('cleanVoucherCode (redeemed):', cleanVoucherCode);
                console.log('generatedVoucherCode (new):', generatedVoucherCode);
                console.log('paidAmount (original voucher price):', paidAmount);
                console.log('resolvedVoucherType:', resolvedVoucherType || null);

                // Determine status: if flight_date exists, status should be 'Scheduled'
                const initialStatus = (bookingDateTime && bookingDateTime !== null && bookingDateTime !== '' && bookingDateTime !== '0000-00-00 00:00:00') 
                    ? 'Scheduled' 
                    : 'Open';
                const voucherTypeForExperience = String(resolvedVoucherType || '').toLowerCase();
                const forcePrivateCharterExperience = voucherTypeForExperience.includes('private') || voucherTypeForExperience.includes('proposal');
                const normalizedExperienceForBooking = forcePrivateCharterExperience
                    ? 'Private Charter'
                    : (chooseFlightType.type || 'Shared Flight');

                // For redeem voucher bookings, use the NEWLY GENERATED voucher code (generatedVoucherCode) in booking.voucher_code
                // This is the voucher code that will be displayed in the All Bookings table (e.g., BAT26RMJ)
                // The redeemed voucher code (cleanVoucherCode) will be shown in the booking details popup via all_vouchers lookup
                const voucherCodeForBooking = generatedVoucherCode || cleanVoucherCode;
                const bookingValues = [
                    passengerName,
                    normalizedExperienceForBooking,
                    bookingDateTime,
                    actualPaxCount, // Use actual passenger count instead of chooseFlightType.passengerCount
                    chooseLocation,
                    initialStatus, // Set to 'Scheduled' if flight_date exists, otherwise 'Open'
                    paidAmount, // Use original voucher price instead of totalPrice
                    0,
                    voucherCodeForBooking, // Use the NEWLY GENERATED voucher code (generatedVoucherCode) for All Bookings table display
                    now, // created_at
                    expiresDateFinal || null, // expires - calculated from voucher created_at
                    passengerData[0].email || null,
                    (() => {
                        // Combine countryCode and phone for mainPassenger phone
                        const mainPassenger = passengerData[0] || {};
                        let mainPassengerPhone = mainPassenger.phone || null;
                        if (mainPassengerPhone) {
                            mainPassengerPhone = String(mainPassengerPhone).trim();
                            if (!mainPassengerPhone.startsWith('+')) {
                                if (mainPassenger.countryCode) {
                                    let countryCode = String(mainPassenger.countryCode).trim();
                                    if (countryCode && !countryCode.startsWith('+')) {
                                        countryCode = '+' + countryCode;
                                    }
                                    mainPassengerPhone = `${countryCode}${mainPassengerPhone}`.trim();
                                } else {
                                    mainPassengerPhone = `+44${mainPassengerPhone}`.trim();
                                }
                            }
                        }
                        return mainPassengerPhone;
                    })(),
                    activity_id || null,
                    'Yes', // Redeem Voucher bookings always have redeemed_voucher = Yes
                    0, // flight_attempts (always 0 for redeem voucher bookings)
                    'Redeem Voucher', // flight_type_source (always 'Redeem Voucher' for this endpoint)
                    resolvedVoucherType || null,
                    null,
                    normalizedExperienceForBooking // experience field - align with voucher type for private/proposal flows
                ];

                console.log('=== REDEEM BOOKING SQL ===');
                console.log('SQL:', bookingSql);
                console.log('Values:', bookingValues);

                function handleRedeemBookingSuccess(bookingId) {
                    console.log('=== REDEEM BOOKING SUCCESS ===');
                    console.log('✅ Booking created with newly generated voucher code:', generatedVoucherCode);
                    console.log('✅ Redeemed voucher code (for popup display):', cleanVoucherCode);

                    // Ensure voucher_code is set in all_booking (fallback update for safety)
                    // Use newly generated voucher code (generatedVoucherCode) for All Bookings table display
                    if (generatedVoucherCode && generatedVoucherCode.trim()) {
                        con.query(
                            'UPDATE all_booking SET voucher_code = ? WHERE id = ? AND (voucher_code IS NULL OR voucher_code = "")',
                            [generatedVoucherCode.trim(), bookingId],
                            (linkErr) => {
                                if (linkErr) {
                                    console.error('Error linking booking with voucher_code:', linkErr);
                                } else {
                                    console.log('✅ Voucher code linked to Redeem Voucher booking:', generatedVoucherCode.trim());
                                }
                            }
                        );
                    } else {
                        console.warn('⚠️ Warning: Redeem Voucher booking created without voucher_code. Booking ID:', bookingId);
                    }
                    
                    // Link the newly generated voucher code to the booking via voucher_code_usage table
                    // This allows the system to track that a new voucher code was generated for this booking
                    if (generatedVoucherCode && generatedVoucherCode.trim() && bookingId) {
                        // First, get the voucher_code_id from voucher_codes table
                        con.query(
                            'SELECT id FROM voucher_codes WHERE code = ?',
                            [generatedVoucherCode.trim()],
                            (voucherCodeErr, voucherCodeRows) => {
                                if (voucherCodeErr) {
                                    console.error('Error finding voucher_code_id for generated voucher code:', voucherCodeErr);
                                    return;
                                }
                                
                                if (voucherCodeRows && voucherCodeRows.length > 0) {
                                    const voucherCodeId = voucherCodeRows[0].id;
                                    const customerEmail = passengerData && passengerData[0] && passengerData[0].email ? passengerData[0].email : null;
                                    
                                    // Insert into voucher_code_usage to link the new voucher code with the booking
                                    const usageSql = `
                                        INSERT INTO voucher_code_usage (
                                            voucher_code_id, booking_id, customer_email,
                                            discount_applied, original_amount, final_amount
                                        ) VALUES (?, ?, ?, ?, ?, ?)
                                    `;
                                    const usageValues = [
                                        voucherCodeId,
                                        bookingId,
                                        customerEmail || 'unknown@example.com',
                                        0, // discount_applied (no discount for redeem voucher)
                                        paidAmount || 0, // original_amount
                                        paidAmount || 0  // final_amount (same as original for redeem voucher)
                                    ];
                                    
                                    con.query(usageSql, usageValues, (usageErr) => {
                                        if (usageErr) {
                                            console.error('Error linking generated voucher code to booking via voucher_code_usage:', usageErr);
                                        } else {
                                            console.log('✅ Generated voucher code linked to booking via voucher_code_usage:', generatedVoucherCode.trim());
                                        }
                                    });
                                } else {
                                    console.warn('⚠️ Warning: Generated voucher code not found in voucher_codes table:', generatedVoucherCode.trim());
                                }
                            }
                        );
                    }
                    
                    // Also link the REDEEMED voucher code to the booking via voucher_code_usage table
                    // This allows getBookingDetail to show the correct "Redeemed Voucher: Yes GATORAL33" (Gift/Flight voucher ref)
                    if (cleanVoucherCode && cleanVoucherCode.trim() && bookingId) {
                        const linkRedeemedCode = (redeemedVoucherCodeId) => {
                            const customerEmail = passengerData && passengerData[0] && passengerData[0].email ? passengerData[0].email : null;
                            const checkUsageSql = 'SELECT id FROM voucher_code_usage WHERE booking_id = ? AND voucher_code_id = ?';
                            con.query(checkUsageSql, [bookingId, redeemedVoucherCodeId], (checkErr, checkRows) => {
                                if (checkErr) {
                                    console.error('Error checking existing voucher_code_usage for redeemed voucher:', checkErr);
                                    return;
                                }
                                if (!checkRows || checkRows.length === 0) {
                                    const redeemedUsageSql = `
                                        INSERT INTO voucher_code_usage (
                                            voucher_code_id, booking_id, customer_email,
                                            discount_applied, original_amount, final_amount
                                        ) VALUES (?, ?, ?, ?, ?, ?)
                                    `;
                                    const redeemedUsageValues = [
                                        redeemedVoucherCodeId,
                                        bookingId,
                                        customerEmail || 'unknown@example.com',
                                        0,
                                        paidAmount || 0,
                                        paidAmount || 0
                                    ];
                                    con.query(redeemedUsageSql, redeemedUsageValues, (redeemedUsageErr) => {
                                        if (redeemedUsageErr) {
                                            console.error('Error linking redeemed voucher code to booking via voucher_code_usage:', redeemedUsageErr);
                                        } else {
                                            console.log('✅ Redeemed voucher code linked to booking via voucher_code_usage:', cleanVoucherCode.trim());
                                        }
                                    });
                                }
                            });
                        };
                        // First try voucher_codes (case-insensitive)
                        con.query(
                            'SELECT id FROM voucher_codes WHERE UPPER(code) = UPPER(?) LIMIT 1',
                            [cleanVoucherCode.trim()],
                            (redeemedVoucherCodeErr, redeemedVoucherCodeRows) => {
                                if (redeemedVoucherCodeErr) {
                                    console.error('Error finding voucher_code_id for redeemed voucher code:', redeemedVoucherCodeErr);
                                    return;
                                }
                                if (redeemedVoucherCodeRows && redeemedVoucherCodeRows.length > 0) {
                                    linkRedeemedCode(redeemedVoucherCodeRows[0].id);
                                    return;
                                }
                                // Gift vouchers may exist only in all_vouchers.voucher_ref; ensure we have a voucher_codes row and link it
                                con.query(
                                    'SELECT voucher_ref, paid FROM all_vouchers WHERE UPPER(voucher_ref) = UPPER(?) LIMIT 1',
                                    [cleanVoucherCode.trim()],
                                    (avErr, avRows) => {
                                        if (avErr || !avRows || avRows.length === 0) {
                                            console.warn('⚠️ Redeemed voucher code not found in voucher_codes or all_vouchers:', cleanVoucherCode.trim());
                                            return;
                                        }
                                        const codeToInsert = (avRows[0].voucher_ref || cleanVoucherCode).toString().trim();
                                        const paidForVoucher = parseFloat(avRows[0].paid) || paidAmount || 0;
                                        const insertRedeemedSql = `
                                            INSERT INTO voucher_codes (
                                                code, title, valid_from, valid_until, max_uses, current_uses,
                                                applicable_locations, applicable_experiences, applicable_voucher_types,
                                                is_active, created_at, updated_at, source_type, customer_email, paid_amount
                                            ) VALUES (?, ?, NOW(), ?, 1, 1, ?, ?, ?, 0, NOW(), NOW(), 'redeemed_voucher', ?, ?)
                                            ON DUPLICATE KEY UPDATE current_uses = current_uses + 1, is_active = 0, updated_at = NOW()
                                        `;
                                        const validUntil = expiresDateFinal ? moment(expiresDateFinal).format('YYYY-MM-DD') : moment().add(24, 'months').format('YYYY-MM-DD');
                                        con.query(insertRedeemedSql, [
                                            codeToInsert,
                                            'Redeemed (Gift/Flight) - ' + (chooseLocation || ''),
                                            validUntil,
                                            chooseLocation || null,
                                            resolvedVoucherType || null,
                                            resolvedVoucherType || null,
                                            passengerData && passengerData[0] && passengerData[0].email ? passengerData[0].email : null,
                                            paidForVoucher
                                        ], (insErr, insResult) => {
                                            if (insErr) {
                                                console.warn('⚠️ Could not insert redeemed code into voucher_codes:', insErr.message);
                                                return;
                                            }
                                            con.query('SELECT id FROM voucher_codes WHERE UPPER(code) = UPPER(?) LIMIT 1', [codeToInsert], (selErr, selRows) => {
                                                if (selErr || !selRows || selRows.length === 0) {
                                                    console.warn('⚠️ Could not get voucher_code id after insert for:', codeToInsert);
                                                    return;
                                                }
                                                linkRedeemedCode(selRows[0].id);
                                            });
                                        });
                                    }
                                );
                            }
                        );
                    }

                // Save user session data if provided
                if (userSessionData && userSessionData.session_id) {
                    const ipAddress = req.ip || req.headers['x-forwarded-for'] || req.headers['x-real-ip'] || req.connection.remoteAddress || null;
                    const userSessionPayload = {
                        ...userSessionData,
                        booking_id: bookingId,
                        ip_address: ipAddress || userSessionData.ip_address || null,
                        booking_clicks: 1 // Increment booking clicks
                    };

                    // Save user session asynchronously (don't wait for it)
                    axios.post(`${req.protocol}://${req.get('host')}/api/save-user-session`, userSessionPayload)
                        .then(() => {
                            console.log('User session saved successfully for booking:', bookingId);
                        })
                        .catch((err) => {
                            console.error('Error saving user session:', err.message);
                        });
                }

                // Send automatic booking confirmation email
                if (passengerData && passengerData[0] && passengerData[0].email) {
                    sendAutomaticBookingConfirmationEmail(bookingId);
                }

                // Send automatic booking confirmation SMS for "Book Flight Date" bookings (Redeem Voucher creates a booking)
                console.log('========================================');
                console.log('📱 [createRedeemBooking] SMS SEND PROCESS STARTING');
                console.log('📱 [createRedeemBooking] Booking ID:', bookingId);
                console.log('📱 [createRedeemBooking] Calling sendAutomaticBookingConfirmationSms...');
                console.log('========================================');
                
                try {
                    sendAutomaticBookingConfirmationSms(bookingId);
                    console.log('✅ [createRedeemBooking] sendAutomaticBookingConfirmationSms function called successfully');
                } catch (smsError) {
                    console.error('❌ [createRedeemBooking] Error calling sendAutomaticBookingConfirmationSms:', smsError);
                }

                console.log('Booking ID:', bookingId);

                // Update availability if date and time are provided
                if (selectedDate && selectedTime && req.body.activity_id) {
                    // Parse selectedDate string directly to avoid timezone issues
                    // selectedDate is already in format "YYYY-MM-DD HH:mm:ss" from frontend
                    let bookingDate;
                    if (typeof selectedDate === 'string') {
                        // Extract date part (YYYY-MM-DD) from string, avoiding timezone conversion
                        bookingDate = selectedDate.split(' ')[0] || selectedDate.substring(0, 10);
                    } else {
                        // Fallback: use moment but in UTC mode to avoid timezone shifts
                        bookingDate = moment.utc(selectedDate).format('YYYY-MM-DD');
                    }
                    const bookingTime = selectedTime;

                    console.log('=== REDEEM BOOKING AVAILABILITY UPDATE ===');
                    console.log('passengerData RECEIVED:', JSON.stringify(passengerData, null, 2));
                    console.log('passengerData type:', typeof passengerData);
                    console.log('passengerData is Array?', Array.isArray(passengerData));
                    console.log('passengerData length:', passengerData?.length);
                    console.log('chooseFlightType:', JSON.stringify(chooseFlightType, null, 2));
                    console.log('chooseFlightType.passengerCount:', chooseFlightType.passengerCount);

                    // Use actual passenger count from passengerData array (real passenger count entered by user)
                    const actualPassengerCount = (Array.isArray(passengerData) && passengerData.length > 0) ? passengerData.length : (parseInt(chooseFlightType.passengerCount) || 1);

                    console.log('Date:', bookingDate, 'Time:', bookingTime, 'Activity ID:', req.body.activity_id);
                    console.log('Actual Passenger Count (FINAL):', actualPassengerCount);

                    updateSpecificAvailability(bookingDate, bookingTime, req.body.activity_id, actualPassengerCount);
                } else if (selectedDate && selectedTime && chooseLocation) {
                    // Get activity_id first, then update availability
                    // Parse selectedDate string directly to avoid timezone issues
                    // selectedDate is already in format "YYYY-MM-DD HH:mm:ss" from frontend
                    let bookingDate;
                    if (typeof selectedDate === 'string') {
                        // Extract date part (YYYY-MM-DD) from string, avoiding timezone conversion
                        bookingDate = selectedDate.split(' ')[0] || selectedDate.substring(0, 10);
                    } else {
                        // Fallback: use moment but in UTC mode to avoid timezone shifts
                        bookingDate = moment.utc(selectedDate).format('YYYY-MM-DD');
                    }
                    const bookingTime = selectedTime;
                    // Use actual passenger count from passengerData array (real passenger count entered by user)
                    const actualPassengerCount = (Array.isArray(passengerData) && passengerData.length > 0) ? passengerData.length : (parseInt(chooseFlightType.passengerCount) || 1);

                    const activitySql = `SELECT id FROM activity WHERE location = ? AND status = 'Live' LIMIT 1`;
                    con.query(activitySql, [chooseLocation], (activityErr, activityResult) => {
                        if (activityErr) {
                            console.error('Error getting activity_id for redeem availability update:', activityErr);
                        } else if (activityResult.length > 0) {
                            const activityId = activityResult[0].id;

                            console.log('=== REDEEM BOOKING AVAILABILITY UPDATE (alt sorgu) ===');
                            console.log('Date:', bookingDate, 'Time:', bookingTime, 'Activity ID:', activityId);
                            console.log('passengerData length:', passengerData?.length);
                            console.log('chooseFlightType.passengerCount:', chooseFlightType.passengerCount);
                            console.log('Actual Passenger Count (FINAL):', actualPassengerCount);

                            updateSpecificAvailability(bookingDate, bookingTime, activityId, actualPassengerCount);
                        } else {
                            console.error('No activity found for location:', chooseLocation);
                        }
                    });
                }

                // Create passenger records sequentially to preserve order
                // Insert passengers one by one to ensure the database insertion order matches the array order
                if (passengerData && passengerData.length > 0) {
                    const passengerSql = `
                        INSERT INTO passenger (booking_id, first_name, last_name, weight, email, phone)
                        VALUES (?, ?, ?, ?, ?, ?)
                    `;

                    // Filter out passengers without firstName
                    const validPassengers = passengerData.filter(passenger => passenger.firstName);
                    
                    // Insert passengers sequentially using recursive callback pattern
                    const insertPassengerSequentially = (index) => {
                        if (index >= validPassengers.length) {
                            // All passengers inserted, continue with response
                            console.log(`All ${validPassengers.length} passengers created for booking ${bookingId}`);
                            return;
                        }

                        const passenger = validPassengers[index];
                        // Combine countryCode and phone for each passenger
                        let passengerPhone = passenger.phone || null;
                        if (passengerPhone) {
                            passengerPhone = String(passengerPhone).trim();
                            if (!passengerPhone.startsWith('+')) {
                                // Phone doesn't have country code, combine with countryCode if available
                                if (passenger.countryCode) {
                                    let countryCode = String(passenger.countryCode).trim();
                                    // Ensure countryCode starts with + if it doesn't
                                    if (countryCode && !countryCode.startsWith('+')) {
                                        countryCode = '+' + countryCode;
                                    }
                                    passengerPhone = `${countryCode}${passengerPhone}`.trim();
                                    console.log(`[createRedeemBooking] Passenger phone combined with countryCode: ${passengerPhone}`);
                                } else {
                                    // If no countryCode, use default UK code
                                    passengerPhone = `+44${passengerPhone}`.trim();
                                    console.log(`[createRedeemBooking] Passenger phone added default +44: ${passengerPhone}`);
                                }
                            } else {
                                console.log(`[createRedeemBooking] Passenger phone already has country code: ${passengerPhone}`);
                            }
                        }
                        const passengerValues = [
                            bookingId,
                            passenger.firstName,
                            passenger.lastName || '',
                            passenger.weight || '',
                            passenger.email || '',
                            passengerPhone
                        ];

                        con.query(passengerSql, passengerValues, (passengerErr) => {
                            if (passengerErr) {
                                console.error(`Error creating passenger ${index + 1}:`, passengerErr);
                                // Continue with next passenger even if one fails
                                insertPassengerSequentially(index + 1);
                            } else {
                                console.log(`Passenger ${index + 1} created for booking ${bookingId}`);
                                // Insert next passenger
                                insertPassengerSequentially(index + 1);
                            }
                        });
                    };

                    // Start sequential insertion
                    insertPassengerSequentially(0);
                }

                const finalizeRedeemBookingResponse = () => {
                    // Update voucher_codes table to mark as Used
                    if (cleanVoucherCode) {
                        console.log('=== UPDATING VOUCHER_CODES TABLE ===');
                        console.log('Voucher Code:', cleanVoucherCode);

                        // First, mark in all_vouchers table if exists
                        const updateAllVouchersSql = `
                    UPDATE all_vouchers 
                    SET redeemed = 'Yes', status = 'Used'
                    WHERE UPPER(voucher_ref) = UPPER(?)
                `;
                        con.query(updateAllVouchersSql, [cleanVoucherCode], (voucherErr, voucherResult) => {
                            if (voucherErr) {
                                console.warn('Warning: Could not update all_vouchers:', voucherErr.message);
                            } else {
                                console.log('all_vouchers update result:', {
                                    affectedRows: voucherResult.affectedRows,
                                    changedRows: voucherResult.changedRows
                                });
                            }
                        });

                        // Then, update voucher_codes table (if it exists)
                        const updateVoucherCodesSql = `
                    UPDATE voucher_codes 
                    SET current_uses = COALESCE(current_uses, 0) + 1, 
                        is_active = 0
                    WHERE UPPER(code) = UPPER(?)
                `;
                        con.query(updateVoucherCodesSql, [cleanVoucherCode], (codeErr, codeResult) => {
                            if (codeErr) {
                                console.warn('Warning: Could not update voucher_codes:', codeErr.message);
                            } else {
                                console.log('✅ voucher_codes update result:', {
                                    affectedRows: codeResult.affectedRows,
                                    changedRows: codeResult.changedRows,
                                    message: 'Voucher code marked as inactive'
                                });
                            }
                        });
                    }

                    // Remove request from processing map before sending response
                    if (global.redeemBookingRequests) {
                        global.redeemBookingRequests.delete(duplicateKey);
                    }

                    res.json({
                        success: true,
                        message: 'Booking created successfully',
                        bookingId: bookingId,
                        voucher_code: generatedVoucherCode // Return the newly generated voucher code
                    });
                };

                const persistRedeemAdditionalInfoAndRespond = () => {
                    if (!additionalInfo || typeof additionalInfo !== 'object') {
                        finalizeRedeemBookingResponse();
                        return;
                    }

                    console.log('=== SAVING ADDITIONAL INFO ===');
                    console.log('Additional Info:', additionalInfo);

                    const { __requiredKeys, ...rawAdditionalInfo } = normalizeAdditionalInfoPayload(additionalInfo);
                    const meaningfulEntries = Object.entries(rawAdditionalInfo).filter(([, value]) =>
                        hasMeaningfulAdditionalInfoValue(value)
                    );

                    if (meaningfulEntries.length === 0) {
                        console.log('ℹ️ No meaningful additional info payload found for redeem booking.');
                        finalizeRedeemBookingResponse();
                        return;
                    }

                    const redeemAdditionalInfoColumns = resolveBookingAdditionalInfoColumns({
                        additionalInfo,
                        existingBookingRow: sourceBookingAdditionalInfo,
                        preserveExistingLegacy: !!sourceBookingAdditionalInfo
                    });

                    con.query(
                        `UPDATE all_booking
                         SET additional_notes = ?,
                             hear_about_us = ?,
                             ballooning_reason = ?,
                             prefer = ?
                         WHERE id = ?`,
                        [
                            redeemAdditionalInfoColumns.additional_notes,
                            redeemAdditionalInfoColumns.hear_about_us,
                            redeemAdditionalInfoColumns.ballooning_reason,
                            redeemAdditionalInfoColumns.prefer,
                            bookingId
                        ],
                        (legacyUpdateErr) => {
                            if (legacyUpdateErr) {
                                console.error('Error updating redeem booking legacy additional info fields:', legacyUpdateErr);
                            } else {
                                console.log('Redeem booking legacy additional info fields updated successfully:', bookingId);
                            }

                            persistBookingAdditionalInfoPayload({
                                connection: con,
                                bookingId,
                                additionalInfo,
                                logPrefix: '[createRedeemBooking]'
                            }, () => {
                                console.log('✅ createRedeemBooking additional info persisted before response:', bookingId);
                                finalizeRedeemBookingResponse();
                            });
                        }
                    );
                };

                persistRedeemAdditionalInfoAndRespond();
                }

                con.query(bookingSql, bookingValues, (err, result) => {
                    if (err) {
                        console.error('=== REDEEM BOOKING ERROR ===');
                        console.error('Error:', err);

                        // If the error is caused by a missing referenced voucher_code in voucher_codes table,
                        // retry the insert with voucher_code set to NULL so that the booking can still be created.
                        const isForeignKeyVoucherError =
                            err.code === 'ER_NO_REFERENCED_ROW_2' ||
                            (typeof err.message === 'string' &&
                                err.message.includes('a foreign key constraint fails') &&
                                err.message.includes('voucher_code'));

                        if (generatedVoucherCode && isForeignKeyVoucherError) {
                            console.warn('⚠️ Redeem booking failed due to missing voucher_codes row for voucher_code. Retrying insert with NULL voucher_code.');

                            const fallbackValues = [...bookingValues];
                            // voucher_code is at index 8 in bookingValues
                            fallbackValues[8] = null;

                            return con.query(bookingSql, fallbackValues, (fallbackErr, fallbackResult) => {
                                if (fallbackErr) {
                                    // Remove request from processing map on error
                                    if (global.redeemBookingRequests) {
                                        global.redeemBookingRequests.delete(duplicateKey);
                                    }
                                    console.error('❌ Redeem booking fallback insert also failed:', fallbackErr);
                                    return res.status(500).json({
                                        success: false,
                                        error: 'Database query failed to create booking',
                                        details: fallbackErr.message
                                    });
                                }

                                const bookingId = fallbackResult.insertId;
                                console.log('=== REDEEM BOOKING SUCCESS (fallback, voucher_code set to NULL) ===');
                                return handleRedeemBookingSuccess(bookingId);
                            });
                        }

                        // Remove request from processing map on error
                        if (global.redeemBookingRequests) {
                            global.redeemBookingRequests.delete(duplicateKey);
                        }
                        
                        return res.status(500).json({
                            success: false,
                            error: 'Database query failed to create booking',
                            details: err.message
                        });
                    }

                    const bookingId = result.insertId;
                    
                    
                    return handleRedeemBookingSuccess(bookingId);
                });
            } // end of createBookingWithGeneratedCode
        } // end of createBookingWithPrice
        };

        if (sourceBookingId) {
            loadBookingAdditionalInfoSnapshot({
                connection: con,
                bookingId: sourceBookingId,
                callback: (sourceBookingErr, sourceBookingSnapshot) => {
                    if (sourceBookingErr) {
                        console.warn('⚠️ createRedeemBooking could not load source booking additional info:', sourceBookingErr.message);
                    } else if (sourceBookingSnapshot?.bookingRow) {
                        sourceBookingAdditionalInfo = sourceBookingSnapshot.bookingRow;
                        additionalInfo = mergeRebookAdditionalInfoPayload({
                            incomingAdditionalInfo: additionalInfo,
                            existingBookingRow: sourceBookingAdditionalInfo,
                            existingAnswerPayload: sourceBookingSnapshot.answerPayload
                        });
                        console.log('✅ createRedeemBooking merged source booking additional info:', {
                            sourceBookingId,
                            additionalInfoKeys: Object.keys(additionalInfo || {})
                        });
                    }

                    continueCreateRedeemBooking();
                }
            });
            return;
        }

        continueCreateRedeemBooking();
    } // end of createRedeemBookingLogic
});

// One-time backfill: link existing Redeem Voucher bookings to the correct voucher ref (so Booking Details shows e.g. GATORAL33 not GATLHW96Q)
app.post('/api/backfill-redeemed-voucher-codes', (req, res) => {
    const sqlGetRedeemBookings = `
        SELECT id, voucher_code, email, created_at, paid
        FROM all_booking
        WHERE (redeemed_voucher = 'Yes' OR redeemed_voucher = 1)
        AND (flight_type_source = 'Redeem Voucher' OR flight_type_source IS NULL)
        AND id > 0
        ORDER BY id ASC
    `;
    con.query(sqlGetRedeemBookings, [], (err, bookings) => {
        if (err) {
            return res.status(500).json({ success: false, error: err.message });
        }
        const results = { processed: 0, linked: 0, skipped: 0, errors: [] };
        if (!bookings || bookings.length === 0) {
            return res.json({ success: true, message: 'No redeem bookings to backfill', ...results });
        }
        let processed = 0;
        const bookingVoucherCode = (b) => (b.voucher_code || '').toString().trim();
        const next = (index) => {
            if (index >= bookings.length) {
                return res.json({
                    success: true,
                    message: `Backfill complete. Processed: ${results.processed}, linked: ${results.linked}, skipped: ${results.skipped}`,
                    ...results
                });
            }
            const b = bookings[index];
            const bid = b.id;
            const bCode = bookingVoucherCode(b);
            con.query(
                `SELECT vc.id, vc.code FROM voucher_code_usage vcu
                 INNER JOIN voucher_codes vc ON vc.id = vcu.voucher_code_id
                 WHERE vcu.booking_id = ?`,
                [bid],
                (qErr, usageRows) => {
                    if (qErr) {
                        results.errors.push({ booking_id: bid, error: qErr.message });
                        results.processed++;
                        return next(index + 1);
                    }
                    const hasOtherCode = usageRows && usageRows.some((r) => String(r.code || '').trim().toUpperCase() !== (bCode || '').toUpperCase());
                    if (hasOtherCode) {
                        results.skipped++;
                        results.processed++;
                        return next(index + 1);
                    }
                    const findVoucherSql = `
                        SELECT voucher_ref, paid FROM all_vouchers
                        WHERE (redeemed = 'Yes' OR status = 'Used')
                        AND created_at <= ?
                        AND (book_flight = 'Flight Voucher' OR book_flight LIKE '%Gift%')
                        AND (UPPER(TRIM(?)) = '' OR email = ? OR purchaser_email = ? OR recipient_email = ?)
                        ORDER BY created_at DESC
                        LIMIT 1
                    `;
                    con.query(findVoucherSql, [b.created_at || '9999-12-31', b.email || '', b.email || '', b.email || '', b.email || ''], (vErr, vRows) => {
                        if (vErr || !vRows || vRows.length === 0) {
                            results.processed++;
                            results.skipped++;
                            return next(index + 1);
                        }
                        const voucherRef = (vRows[0].voucher_ref || '').toString().trim();
                        if (!voucherRef) {
                            results.processed++;
                            return next(index + 1);
                        }
                        con.query('SELECT id FROM voucher_codes WHERE UPPER(code) = UPPER(?) LIMIT 1', [voucherRef], (cErr, cRows) => {
                            let voucherCodeId = cRows && cRows[0] && cRows[0].id;
                            const doLink = () => {
                                if (!voucherCodeId) return next(index + 1);
                                con.query(
                                    'SELECT id FROM voucher_code_usage WHERE booking_id = ? AND voucher_code_id = ?',
                                    [bid, voucherCodeId],
                                    (uErr, uRows) => {
                                        if (uErr || (uRows && uRows.length > 0)) {
                                            results.processed++;
                                            if (uRows && uRows.length > 0) results.skipped++;
                                            return next(index + 1);
                                        }
                                        const paid = parseFloat(vRows[0].paid) || parseFloat(b.paid) || 0;
                                        con.query(
                                            `INSERT INTO voucher_code_usage (voucher_code_id, booking_id, customer_email, discount_applied, original_amount, final_amount)
                                             VALUES (?, ?, ?, 0, ?, ?)`,
                                            [voucherCodeId, bid, b.email || 'unknown@example.com', paid, paid],
                                            (insErr) => {
                                                if (insErr) {
                                                    results.errors.push({ booking_id: bid, voucher_ref: voucherRef, error: insErr.message });
                                                } else {
                                                    results.linked++;
                                                }
                                                results.processed++;
                                                return next(index + 1);
                                            }
                                        );
                                    }
                                );
                            };
                            if (voucherCodeId) {
                                doLink();
                                return;
                            }
                            con.query(
                                `INSERT INTO voucher_codes (code, paid_amount, is_active, current_uses, max_uses, created_at, updated_at)
                                 VALUES (?, ?, 1, 1, 1, NOW(), NOW())
                                 ON DUPLICATE KEY UPDATE updated_at = NOW()`,
                                [voucherRef, parseFloat(vRows[0].paid) || 0],
                                (insErr) => {
                                    if (insErr) {
                                        results.errors.push({ booking_id: bid, voucher_ref: voucherRef, error: 'voucher_codes insert: ' + insErr.message });
                                        results.processed++;
                                        return next(index + 1);
                                    }
                                    con.query('SELECT id FROM voucher_codes WHERE UPPER(code) = UPPER(?) LIMIT 1', [voucherRef], (sErr, sRows) => {
                                        voucherCodeId = sRows && sRows[0] && sRows[0].id;
                                        doLink();
                                    });
                                }
                            );
                        });
                    });
                }
            );
        };
        next(0);
    });
});

// Mark voucher as redeemed
app.post('/api/redeem-voucher', (req, res) => {
    const { voucher_code, booking_id } = req.body;

    if (!voucher_code) {
        return res.status(400).json({ success: false, message: 'Voucher code is required' });
    }

    // Trim and clean voucher code
    const cleanVoucherCode = voucher_code.trim().toUpperCase();

    console.log('=== MARKING VOUCHER AS REDEEMED ===');
    console.log('Original Voucher Code:', voucher_code);
    console.log('Clean Voucher Code:', cleanVoucherCode);
    console.log('Booking ID:', booking_id);

    // Check both all_vouchers (voucher_ref) and all_booking (voucher_code) tables
    const checkVoucherSql = `
        SELECT 'all_vouchers' as source, id, voucher_ref as code, redeemed, name 
        FROM all_vouchers 
        WHERE UPPER(voucher_ref) = UPPER(?)
        UNION ALL
        SELECT 'all_booking' as source, id, voucher_code as code, 'No' as redeemed, name 
        FROM all_booking 
        WHERE UPPER(voucher_code) = UPPER(?)
        LIMIT 1
    `;

    con.query(checkVoucherSql, [cleanVoucherCode, cleanVoucherCode], (checkErr, checkResult) => {
        if (checkErr) {
            console.error('Error checking voucher existence:', checkErr);
            return res.status(500).json({ success: false, message: 'Database error', error: checkErr.message });
        }

        console.log('=== VOUCHER CHECK RESULT ===');
        console.log('Found vouchers:', checkResult.length);

        if (checkResult.length === 0) {
            console.log('No voucher found with code:', cleanVoucherCode);
            return res.status(404).json({ success: false, message: 'Voucher not found' });
        }

        const voucherRecord = checkResult[0];
        console.log('Voucher details:', {
            source: voucherRecord.source,
            id: voucherRecord.id,
            code: voucherRecord.code,
            current_redeemed_status: voucherRecord.redeemed,
            name: voucherRecord.name
        });

        // Check if already redeemed (only for all_vouchers)
        if (voucherRecord.source === 'all_vouchers' && voucherRecord.redeemed === 'Yes') {
            console.log('Voucher already redeemed');
            return res.status(400).json({ success: false, message: 'Voucher already redeemed' });
        }

        // Update voucher based on source
        let updateVoucherSql;
        if (voucherRecord.source === 'all_vouchers') {
            updateVoucherSql = `
            UPDATE all_vouchers 
                SET redeemed = 'Yes', status = 'Used'
                WHERE UPPER(voucher_ref) = UPPER(?)
            `;
        } else {
            // For all_booking vouchers, we don't update - they're already marked as used
            // Just return success
            console.log('Voucher from all_booking - no need to mark as redeemed');
            return res.json({
                success: true,
                message: 'Voucher successfully redeemed (from booking)'
            });
        }

        console.log('=== EXECUTING UPDATE ===');
        console.log('SQL:', updateVoucherSql);
        console.log('Parameter:', cleanVoucherCode);

        con.query(updateVoucherSql, [cleanVoucherCode], (err, result) => {
            if (err) {
                console.error('=== UPDATE ERROR ===');
                console.error('Error marking voucher as redeemed:', err);
                return res.status(500).json({ success: false, message: 'Database error', error: err.message });
            }

            console.log('=== UPDATE RESULT ===');
            console.log('Voucher redemption update result:', {
                affectedRows: result.affectedRows,
                changedRows: result.changedRows,
                insertId: result.insertId,
                warningCount: result.warningCount
            });

            if (result.affectedRows === 0) {
                console.warn('=== NO ROWS AFFECTED ===');
                console.warn('No voucher found to update with code:', voucher_code);
                return res.json({ success: false, message: 'Voucher not found or already redeemed' });
            }

            console.log('=== SUCCESS ===');
            console.log('Voucher marked as redeemed successfully');
            // Also update voucher_codes table to mark as inactive and increment current_uses
            const updateVoucherCodeSql = `
                UPDATE voucher_codes 
                SET current_uses = COALESCE(current_uses,0) + 1, 
                    is_active = 0
                WHERE UPPER(code) = UPPER(?)
            `;
            con.query(updateVoucherCodeSql, [cleanVoucherCode], (codeErr, codeResult) => {
                if (codeErr) {
                    console.warn('Warning: Could not update voucher_codes:', codeErr.message);
                } else if (codeResult.affectedRows > 0) {
                    console.log('✅ voucher_codes updated successfully - marked as inactive');
                } else {
                    console.log('No matching voucher found in voucher_codes table');
                }
                // Always respond with success even if voucher_codes update fails
                res.json({ success: true, message: 'Voucher marked as redeemed' });
            });
        });
    });
});

