// Get all private charter voucher types
app.get('/api/private-charter-voucher-types', (req, res) => {
    console.log('GET /api/private-charter-voucher-types called');
    console.log('CORS: Request origin:', req.headers.origin);

    // Check if we want only active voucher types (default) or all
    const showOnlyActive = req.query.active !== 'false';
    const requestedLocation = req.query.location;
    const location = normalizeVoucherLocation(requestedLocation);
    const passengers = req.query.passengers ? Number(req.query.passengers) : undefined;

    let sql, params = [];
    if (showOnlyActive) {
        sql = `SELECT * FROM private_charter_voucher_types WHERE is_active = 1 ORDER BY sort_order ASC, created_at DESC`;
        console.log('SQL Query (active only):', sql);
    } else {
        sql = `SELECT * FROM private_charter_voucher_types ORDER BY sort_order ASC, created_at DESC`;
        console.log('SQL Query (all):', sql);
    }

    con.query(sql, params, (err, result) => {
        // Ensure CORS headers are always set, even on error
        setCorsHeaders(req, res);
        
        if (err) {
            console.error('Error fetching private charter voucher types:', err);
            return res.status(500).json({ success: false, message: 'Database error', error: err.message });
        }

        console.log('GET /api/private-charter-voucher-types - Raw query result:');
        result.forEach((item, index) => {
            console.log(`Item ${index + 1}:`, {
                id: item.id,
                title: item.title,
                is_active: item.is_active,
                is_active_type: typeof item.is_active,
                updated_at: item.updated_at
            });
        });

        // For admin view (showOnlyActive = false), return all voucher types
        // For frontend view (showOnlyActive = true), return only active ones
        let finalResult = result.map(v => {
            const pricingPayload = buildPrivateCharterPricingPayload({
                defaultPrice: v.price_per_person,
                title: v.title,
                passengers
            });

            return {
                ...v,
                price_per_person: pricingPayload.effective_price ?? v.price_per_person,
                original_price: pricingPayload.original_price ?? formatNumericPrice(v.price_per_person),
                sale_price: pricingPayload.sale_price,
                has_sale_price: pricingPayload.has_sale_price
            };
        });

        // If location is provided, enrich price_per_person from activity.private_charter_pricing
        console.log('Private charter location query:', { requestedLocation, normalizedLocation: location });

        if (location) {
            const actSql = `
                SELECT
                    id,
                    activity_name,
                    location,
                    private_charter_pricing,
                    private_charter_sale_pricing,
                    private_charter_from_price,
                    private_charter_from_sale_price
                FROM activity
                WHERE status = "Live" AND location = ?
                ORDER BY id DESC
                LIMIT 1
            `;
            con.query(actSql, [location], (aErr, aRes) => {
                if (aErr) {
                    console.error('Error fetching activity for pricing:', aErr);
                } else if (aRes && aRes.length > 0) {
                    const normalize = (s) => (s || '').toString().trim().toLowerCase().replace(/\s+/g, ' ');
                    const selectedPassengers = [2, 3, 4].includes(passengers)
                        ? String(passengers)
                        : (passengers >= 5 ? '8' : '2');
                    // Map titles to prices (tolerant)
                    finalResult = finalResult.map(v => {
                        const pricingPayload = buildPrivateCharterPricingPayload({
                            defaultPrice: v.price_per_person,
                            pricingMapRaw: aRes[0].private_charter_pricing,
                            salePricingMapRaw: aRes[0].private_charter_sale_pricing,
                            title: v.title || '',
                            passengers: selectedPassengers
                        });

                        const hasActivityPricing =
                            getTieredPricingEntryForTitle(aRes[0].private_charter_pricing, v.title || '') !== undefined ||
                            getTieredPricingEntryForTitle(aRes[0].private_charter_sale_pricing, v.title || '') !== undefined;

                        return {
                            ...v,
                            price_per_person: pricingPayload.effective_price ?? v.price_per_person,
                            original_price: pricingPayload.original_price ?? formatNumericPrice(v.price_per_person),
                            sale_price: pricingPayload.sale_price,
                            has_sale_price: pricingPayload.has_sale_price,
                            // Activity modal group pricing is "per person". These tier values should be interpreted as pp.
                            price_unit: hasActivityPricing ? 'pp' : (v.price_unit || 'pp')
                        };
                    });
                }
                console.log('Query result:', result);
                console.log('Show only active:', showOnlyActive);
                console.log('Result length:', result ? result.length : 'undefined');
                console.log('Final result length:', finalResult ? finalResult.length : 'undefined');
                
                // Ensure CORS headers are set before sending response in nested callback
                setCorsHeaders(req, res);
                console.log('✅ CORS: Headers set in /api/private-charter-voucher-types (location branch) response');
                
                return res.json({ success: true, data: finalResult });
            });
            return; // prevent double send
        }

        console.log('Query result:', result);
        console.log('Show only active:', showOnlyActive);
        console.log('Result length:', result ? result.length : 'undefined');
        console.log('Final result length:', finalResult ? finalResult.length : 'undefined');
        console.log('✅ CORS: Headers set in /api/private-charter-voucher-types response');

        res.json({ success: true, data: finalResult });
    });
});

