// Function to save payment history from Stripe session
async function savePaymentHistory(session, bookingId, voucherId, voucherRef = null) {
    try {
        const sessionId = session.id;
        const paymentIntentId = session.payment_intent;
        const amountTotal = session.amount_total ? session.amount_total / 100 : 0; // Convert from cents
        const currency = session.currency || 'GBP';

        let charge = null;
        let paymentMethod = null;
        let cardLast4 = null;
        let cardBrand = null;
        let walletType = null;
        let fingerprint = null;
        let origin = null;
        let cardPresent = false;
        let chargeId = null;
        let payoutId = null;
        let paymentStatus = 'pending';
        let arrivingOn = null;

        // Get payment intent details
        if (paymentIntentId) {
            try {
                const paymentIntent = await stripe.paymentIntents.retrieve(paymentIntentId);
                paymentStatus = paymentIntent.status === 'succeeded' ? 'succeeded' : paymentIntent.status;

                // Get charge data from payment intent. In newer Stripe API responses the
                // charge may only be exposed via latest_charge rather than charges.data.
                if (paymentIntent.latest_charge) {
                    try {
                        charge = typeof paymentIntent.latest_charge === 'string'
                            ? await stripe.charges.retrieve(paymentIntent.latest_charge)
                            : paymentIntent.latest_charge;
                    } catch (latestChargeError) {
                        console.warn('Could not retrieve latest charge from payment intent:', latestChargeError.message);
                    }
                }

                if (!charge && paymentIntent.charges && paymentIntent.charges.data && paymentIntent.charges.data.length > 0) {
                    charge = paymentIntent.charges.data[0];
                }

                if (charge) {
                    chargeId = charge.id;

                    // Get payment method details
                    if (charge.payment_method_details) {
                        const pmDetails = charge.payment_method_details;

                        if (pmDetails.card) {
                            cardLast4 = pmDetails.card.last4;
                            cardBrand = pmDetails.card.brand;
                            fingerprint = pmDetails.card.fingerprint;
                        }

                        if (pmDetails.type === 'card') {
                            cardPresent = pmDetails.card?.present || false;
                        }

                        // Check for wallet type
                        if (pmDetails.type === 'card' && pmDetails.card?.wallet) {
                            walletType = pmDetails.card.wallet.type;
                        }
                    }

                    // Get origin from charge
                    if (charge.payment_method_details?.card?.country) {
                        origin = charge.payment_method_details.card.country;
                    }

                    // Get payout information if available
                    if (charge.balance_transaction) {
                        try {
                            const balanceTransaction = await stripe.balanceTransactions.retrieve(charge.balance_transaction);
                            if (balanceTransaction.available_on) {
                                arrivingOn = new Date(balanceTransaction.available_on * 1000).toISOString().split('T')[0];
                            }
                            if (balanceTransaction.reporting_category === 'charge') {
                                // Try to get payout ID from balance transaction
                                if (balanceTransaction.payout) {
                                    payoutId = balanceTransaction.payout;
                                }
                            }
                        } catch (btError) {
                            console.warn('Could not retrieve balance transaction:', btError.message);
                        }
                    }
                }
            } catch (piError) {
                console.warn('Could not retrieve payment intent:', piError.message);
            }
        }

        // Insert payment history (try with voucher_id and voucher_ref first, fall back without if columns don't exist)
        const insertPaymentHistoryWithVoucher = `
            INSERT INTO payment_history (
                booking_id, voucher_id, voucher_ref, stripe_session_id, stripe_charge_id, stripe_payment_intent_id,
                amount, currency, card_last4, card_brand, wallet_type, transaction_id,
                payout_id, payment_status, fingerprint, origin, card_present, arriving_on
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        `;
        
        const insertPaymentHistoryWithoutVoucher = `
            INSERT INTO payment_history (
                booking_id, stripe_session_id, stripe_charge_id, stripe_payment_intent_id,
                amount, currency, card_last4, card_brand, wallet_type, transaction_id,
                payout_id, payment_status, fingerprint, origin, card_present, arriving_on
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        `;

        const paymentHistoryBookingId = bookingId || ((voucherId || voucherRef) ? 0 : null);

        // Try inserting with voucher_id and voucher_ref first
        await new Promise((resolve) => {
            con.query(
                insertPaymentHistoryWithVoucher,
                [
                    paymentHistoryBookingId,
                    voucherId || null,
                    voucherRef || null,
                    sessionId,
                    chargeId,
                    paymentIntentId,
                    amountTotal,
                    currency,
                    cardLast4,
                    cardBrand,
                    walletType,
                    chargeId, // transaction_id
                    payoutId,
                    paymentStatus,
                    fingerprint,
                    origin,
                    cardPresent ? 1 : 0,
                    arrivingOn
                ],
                (err, result) => {
                    if (err) {
                        // If voucher_id/voucher_ref columns don't exist, try without them
                        if (err.code === 'ER_BAD_FIELD_ERROR') {
                            console.log('ℹ️ voucher_id/voucher_ref columns not found in payment_history, inserting without them');
                            con.query(
                                insertPaymentHistoryWithoutVoucher,
                                [
                                    paymentHistoryBookingId,
                                    sessionId,
                                    chargeId,
                                    paymentIntentId,
                                    amountTotal,
                                    currency,
                                    cardLast4,
                                    cardBrand,
                                    walletType,
                                    chargeId, // transaction_id
                                    payoutId,
                                    paymentStatus,
                                    fingerprint,
                                    origin,
                                    cardPresent ? 1 : 0,
                                    arrivingOn
                                ],
                                (err2, result2) => {
                                    if (err2) {
                                        console.error('Error saving payment history (fallback):', err2);
                                    } else {
                                        console.log('✅ Payment history saved successfully (without voucher_id/voucher_ref), ID:', result2.insertId);
                                    }
                                    resolve();
                                }
                            );
                        } else {
                            console.error('Error saving payment history:', err);
                            resolve();
                        }
                    } else {
                        console.log('✅ Payment history saved successfully, ID:', result.insertId);
                        resolve();
                    }
                }
            );
        });
    } catch (error) {
        console.error('Error in savePaymentHistory:', error);
    }
}

function getAuthoritativeStripeAmounts(session, fallbackValue = 0) {
    const fallbackAmount = Number.isFinite(Number(fallbackValue)) ? Number(fallbackValue) : 0;
    const totalCents = session?.amount_total;
    const subtotalCents = session?.amount_subtotal;
    const discountCents = session?.total_details?.amount_discount;

    const paidAmount = Number.isFinite(Number(totalCents))
        ? Number(totalCents) / 100
        : fallbackAmount;
    const subtotalAmount = Number.isFinite(Number(subtotalCents))
        ? Number(subtotalCents) / 100
        : paidAmount;
    const discountAmount = Number.isFinite(Number(discountCents))
        ? Number(discountCents) / 100
        : Math.max(0, subtotalAmount - paidAmount);

    return {
        paidAmount,
        subtotalAmount,
        discountAmount
    };
}

function syncAuthoritativeAmountsToSessionStore(storeData, amounts) {
    if (!storeData || !amounts) return;

    const paidAmount = Number.isFinite(Number(amounts.paidAmount)) ? Number(amounts.paidAmount) : 0;
    const subtotalAmount = Number.isFinite(Number(amounts.subtotalAmount)) ? Number(amounts.subtotalAmount) : paidAmount;
    const discountAmount = Number.isFinite(Number(amounts.discountAmount))
        ? Number(amounts.discountAmount)
        : Math.max(0, subtotalAmount - paidAmount);

    storeData.actualPaidAmount = paidAmount;
    storeData.actualSubtotalAmount = subtotalAmount;
    storeData.discountAmount = discountAmount;

    if (storeData.bookingData) {
        storeData.bookingData = {
            ...storeData.bookingData,
            actualPaidAmount: paidAmount,
            actualSubtotalAmount: subtotalAmount,
            discountAmount
        };
    }

    if (storeData.voucherData) {
        storeData.voucherData = {
            ...storeData.voucherData,
            paid: paidAmount,
            subtotal: subtotalAmount,
            total: paidAmount,
            original_amount: paidAmount,
            amount: paidAmount,
            discountAmount
        };
    }
}

function getAuthoritativePaidAmountFromSessionStore(storeData) {
    if (!storeData) return 0;
    if (storeData.manualBooking) return 0;

    const candidates = [
        storeData.actualPaidAmount,
        storeData.bookingData?.actualPaidAmount,
        storeData.voucherData?.paid,
        storeData.totalPrice
    ];

    for (const candidate of candidates) {
        if (candidate === 0) return 0;
        if (candidate !== null && candidate !== undefined && Number.isFinite(Number(candidate))) {
            return Number(candidate);
        }
    }

    return 0;
}

let hasLoggedGoogleAdsApiUploadDisabled = false;

/**
 * Helper function to send Google Ads conversion after successful payment
 * This is called from the webhook after payment is confirmed
 * 
 * @param {Object} session - Stripe checkout session object
 * @param {string} transactionId - Unique transaction ID (payment intent ID or session ID)
 * @param {number} value - Transaction value in currency units (not cents)
 * @param {string} currency - Currency code (e.g., 'GBP')
 */
async function sendGoogleAdsConversionIfNeeded(session, transactionId, value, currency = 'GBP') {
    try {
        const apiUploadEnabled = String(process.env.GOOGLE_ADS_API_UPLOAD_ENABLED || '').toLowerCase() === 'true';
        if (!apiUploadEnabled) {
            const infoMessage = 'Skipping server-side Google Ads API upload because GOOGLE_ADS_API_UPLOAD_ENABLED is not true. Client-side Google tag purchase conversion remains active.';
            console.log('ℹ️', infoMessage);
            if (!hasLoggedGoogleAdsApiUploadDisabled) {
                saveErrorLog('info', infoMessage, null, 'googleAds.sendConversionIfNeeded');
                hasLoggedGoogleAdsApiUploadDisabled = true;
            }
            return { success: false, reason: 'api_upload_disabled' };
        }

        // Extract funnel_type, experience_type, product_type for GA_Purchase_Completed
        const funnelType = session.metadata?.funnel_type || 'booking';
        const experienceType = session.metadata?.experience_type || 'shared';
        const productType = session.metadata?.product_type || '';
        
        console.log('📊 [Google Ads] sendGoogleAdsConversionIfNeeded called:', {
            transactionId,
            value,
            currency,
            sessionId: session?.id,
            hasMetadata: !!session?.metadata,
            funnelType,
            experienceType,
            productType
        });
        
        // Extract Google Ads IDs from session metadata
        const gclid = session.metadata?.gclid || null;
        const wbraid = session.metadata?.wbraid || null;
        const gbraid = session.metadata?.gbraid || null;

        console.log('📊 [Google Ads] Extracted IDs from metadata:', {
            gclid: gclid ? `${gclid.substring(0, 10)}...` : null,
            wbraid: wbraid ? `${wbraid.substring(0, 10)}...` : null,
            gbraid: gbraid ? `${gbraid.substring(0, 10)}...` : null,
            fullMetadata: session.metadata
        });

        if (!gclid && !wbraid && !gbraid) {
            const infoMessage = `Skipping Google Ads click conversion upload because no gclid/wbraid/gbraid was captured. Transaction ID: ${transactionId}`;
            console.log('ℹ️', infoMessage);
            
            // Log to database for visibility
            saveErrorLog('info', infoMessage, null, 'googleAds.sendConversionIfNeeded');
            return { success: false, reason: 'missing_click_id' };
        }

        console.log('📊 [Google Ads] Proceeding with conversion send...');

        // Send conversion to Google Ads (GA_Purchase_Completed - Primary conversion)
        // Use funnel_type + experience_type to select conversion action: GA_Flight_Purchase_*, GA_Voucher_Purchase_*
        const conversionResult = await sendGoogleAdsConversion({
            transactionId: transactionId,
            value: value,
            currency: currency,
            gclid: gclid,
            wbraid: wbraid,
            gbraid: gbraid,
            conversionDateTime: new Date().toISOString(),
            allowTestPayments: false, // Don't allow test payments in production webhooks
            funnelType,
            experienceType,
            productType
        });

        if (conversionResult.success) {
            const successMessage = `Google Ads conversion sent successfully. Transaction ID: ${transactionId}, Value: ${value} ${currency}, Has gclid: ${!!gclid}`;
            console.log('✅', successMessage);
            
            // Log success to database
            saveErrorLog('info', successMessage, JSON.stringify(conversionResult.response || {}, null, 2), 'googleAds.sendConversionIfNeeded');
        } else {
            const warningMessage = `Google Ads conversion failed. Transaction ID: ${transactionId}, Reason: ${conversionResult.reason || 'unknown'}`;
            console.warn('⚠️', warningMessage, {
                transactionId,
                reason: conversionResult.reason,
                error: conversionResult.error
            });
            
            // Save warning to logs database
            const warningDetails = conversionResult.reason 
                ? `Reason: ${conversionResult.reason}. ${conversionResult.error ? `Error: ${JSON.stringify(conversionResult.error)}` : ''}`
                : 'Unknown reason';
            saveErrorLog('warning', `${warningMessage}. ${warningDetails}`, null, 'googleAds.sendConversionIfNeeded');
        }
    } catch (error) {
        // Log error but don't throw - we don't want to break the payment flow
        const errorMessage = `Error sending Google Ads conversion. Transaction ID: ${transactionId || 'unknown'}, Error: ${error.message}`;
        console.error('❌', errorMessage);
        
        // Save error to logs database
        const errorDetails = error.response?.data 
            ? JSON.stringify(error.response.data) 
            : error.message || 'Unknown error';
        const stackTrace = error.stack || `${error.name}: ${error.message}`;
        saveErrorLog('error', `Google Ads Conversion: ${errorMessage}. Value: ${value}, Currency: ${currency}, Details: ${errorDetails}`, stackTrace, 'googleAds.sendConversionIfNeeded');
    }
}

// Stripe Webhook endpoint
app.post('/api/stripe-webhook', express.raw({ type: 'application/json' }), async (req, res) => {
    console.log('🔔 Stripe webhook endpoint hit!');
    console.log('🔔 Webhook body length:', req.body ? req.body.length : 'undefined');
    console.log('🔔 Webhook headers:', req.headers);

    const sig = req.headers['stripe-signature'];
    let event;

    try {
        // Webhook signature verification
        if (!process.env.STRIPE_WEBHOOK_SECRET) {
            console.error('STRIPE_WEBHOOK_SECRET environment variable is not set');
            return res.status(500).send('Webhook configuration error');
        }

        console.log('Webhook secret:', process.env.STRIPE_WEBHOOK_SECRET);
        event = stripe.webhooks.constructEvent(req.body, sig, process.env.STRIPE_WEBHOOK_SECRET);
        console.log('Webhook signature verified successfully');
        console.log('Webhook event type:', event.type);
        console.log('Webhook event ID:', event.id);
    } catch (err) {
        console.error('Webhook signature verification failed:', err.message);
        return res.status(400).send(`Webhook Error: ${err.message}`);
    }

    try {
        if (event.type === 'checkout.session.completed') {
            const session = event.data.object;
            console.log('✅ Webhook: Checkout session completed:', session.id);
            console.log('✅ Webhook: Session metadata:', session.metadata);

            const session_id = session.id;
            console.log('Using session ID:', session_id);

            const storeData = stripeSessionStore[session_id];
            console.log('Store data found:', !!storeData);
            console.log('Store data content:', storeData);

            if (!storeData) {
                console.error('Stripe session store data not found for session_id:', session_id);
                console.log('Available session IDs in store:', Object.keys(stripeSessionStore));
                return res.status(400).send('Session data not found');
            }

            // Duplicate kontrolü - aynı session için birden fazla işlem yapılmasını engelle
            if (storeData.processed) {
                console.log('Session already processed, skipping:', session_id);
                return res.json({ received: true, message: 'Session already processed' });
            }

            // Session ID kontrolü - session data var mı kontrol et
            // For extend_voucher type, we don't need bookingData or voucherData
            if (!storeData.bookingData && !storeData.voucherData && !storeData.extendVoucherData && !storeData.customerPortalUpsellData && !storeData.voucherUpgradeData) {
                console.log('❌ No booking/voucher/extendVoucher/customerPortalUpsell/voucherUpgrade data found for session:', session_id);
                console.log('❌ Store data type:', storeData.type);
                console.log('❌ Store data keys:', Object.keys(storeData));
                return res.status(400).send('No booking/voucher/extendVoucher/customerPortalUpsell/voucherUpgrade data found');
            }

            console.log('🔄 Processing webhook for session:', session_id, 'Type:', storeData.type);
            console.log('🔄 Store data keys:', Object.keys(storeData));
            if (storeData.extendVoucherData) {
                console.log('🔄 Extend voucher data present:', JSON.stringify(storeData.extendVoucherData, null, 2));
            }

            try {
                if (storeData.type === 'booking') {
                    // If already processed with a booking id, still save payment history
                    if (storeData.bookingData?.booking_id) {
                        console.log('Webhook: booking already created for session, saving payment history only.');
                        const existingBookingId = storeData.bookingData.booking_id;
                        await savePaymentHistory(session, existingBookingId, null);

                        // Update booking with stripe_session_id if not already set
                        con.query(
                            'UPDATE all_booking SET stripe_session_id = ? WHERE id = ? AND (stripe_session_id IS NULL OR stripe_session_id = "")',
                            [session_id, existingBookingId],
                            (err) => {
                                if (err) {
                                    console.error('Error updating booking with stripe_session_id:', err);
                                } else {
                                    console.log('✅ Booking updated with stripe_session_id');
                                }
                            }
                        );
                        return res.json({ received: true });
                    }
                    console.log('Creating booking via webhook:', storeData.bookingData);
                    // Pass userSessionData to bookingData for createBookingFromWebhook
                    if (storeData.userSessionData) {
                        storeData.bookingData = storeData.bookingData || {};
                        storeData.bookingData.userSessionData = storeData.userSessionData;
                    }
                    const bookingAmounts = getAuthoritativeStripeAmounts(
                        session,
                        storeData.totalPrice || storeData.bookingData?.totalPrice || 0
                    );
                    syncAuthoritativeAmountsToSessionStore(storeData, bookingAmounts);
                    // Direct database insertion instead of HTTP call - pass session_id for payment tracking
                    const bookingId = await createBookingFromWebhook(storeData.bookingData, session_id);
                    console.log('Webhook booking creation completed, ID:', bookingId, 'Session ID:', session_id);

                    // Save payment information
                    await savePaymentHistory(session, bookingId, null);

                    // Send Google Ads conversion tracking (server-side)
                    // Use payment intent ID if available (string or expanded object), otherwise session ID
                    const pi = session.payment_intent;
                    const transactionId = (typeof pi === 'string' ? pi : pi?.id) || session.id;
                    const conversionValue = bookingAmounts.paidAmount;
                    const conversionCurrency = session.currency?.toUpperCase() || 'GBP';
                    
                    // Send conversion asynchronously (don't block webhook response)
                    sendGoogleAdsConversionIfNeeded(session, transactionId, conversionValue, conversionCurrency)
                        .catch((err) => {
                            const errorMessage = `Error in Google Ads conversion (non-blocking) for booking ${bookingId || 'unknown'}. Transaction ID: ${transactionId}`;
                            console.error('❌', errorMessage, err.message);
                            
                            // Log error to database
                            const errorDetails = err.response?.data 
                                ? JSON.stringify(err.response.data) 
                                : err.message || 'Unknown error';
                            const stackTrace = err.stack || `${err.name}: ${err.message}`;
                            saveErrorLog('error', `${errorMessage}. Details: ${errorDetails}`, stackTrace, 'googleAds.webhook.booking');
                        });

                    // Save user session data if provided
                    if (storeData.userSessionData && storeData.userSessionData.session_id && bookingId) {
                        const ipAddress = req.ip || req.headers['x-forwarded-for'] || req.headers['x-real-ip'] || req.connection.remoteAddress || null;
                        const userSessionPayload = {
                            ...storeData.userSessionData,
                            booking_id: bookingId,
                            ip_address: ipAddress || storeData.userSessionData.ip_address || null,
                            booking_clicks: 1 // Increment booking clicks
                        };

                        // Save user session asynchronously
                        axios.post(`${req.protocol}://${req.get('host')}/api/save-user-session`, userSessionPayload)
                            .then(() => {
                                console.log('User session saved successfully for booking:', bookingId);
                            })
                            .catch((err) => {
                                console.error('Error saving user session:', err.message);
                            });
                    }

                    // Mark processed and store created id to avoid duplicate creation by fallback
                    storeData.processed = true;
                    if (!storeData.bookingData) storeData.bookingData = {};
                    storeData.bookingData.booking_id = bookingId;
                    return res.json({ received: true });
                } else if (storeData.type === 'voucher') {
                    console.log('Creating voucher via webhook:', storeData.voucherData);
                    console.log('=== WEBHOOK VOUCHER DATA DEBUG ===');
                    console.log('storeData.voucherData.numberOfPassengers:', storeData.voucherData.numberOfPassengers);
                    console.log('typeof storeData.voucherData.numberOfPassengers:', typeof storeData.voucherData.numberOfPassengers);
                    console.log('storeData.voucherData.additionalInfo:', storeData.voucherData.additionalInfo);
                    console.log('storeData.voucherData.additional_information_json:', storeData.voucherData.additional_information_json);
                    console.log('storeData.voucherData.additional_information:', storeData.voucherData.additional_information);
                    console.log('typeof storeData.voucherData.additionalInfo:', typeof storeData.voucherData.additionalInfo);
                    console.log('storeData.voucherData.additionalInfo keys:', storeData.voucherData.additionalInfo ? Object.keys(storeData.voucherData.additionalInfo) : 'additionalInfo is null/undefined');
                    console.log('storeData.voucherData.add_to_booking_items:', storeData.voucherData.add_to_booking_items);
                    console.log('typeof storeData.voucherData.add_to_booking_items:', typeof storeData.voucherData.add_to_booking_items);
                    console.log('storeData.voucherData.add_to_booking_items length:', storeData.voucherData.add_to_booking_items ? storeData.voucherData.add_to_booking_items.length : 'add_to_booking_items is null/undefined');

                    // Check if voucher was already created to prevent duplicate creation
                    if (storeData.voucherData?.voucher_id) {
                        console.log('Webhook: voucher already created for session, skipping. ID:', storeData.voucherData.voucher_id);
                        return res.json({ received: true });
                    }

                    // Webhook creates the voucher, voucher code generation will be done by createBookingFromSession
                    console.log('Creating voucher via webhook, voucher code generation will be done by createBookingFromSession');

                    const voucherAmounts = getAuthoritativeStripeAmounts(
                        session,
                        storeData.totalPrice || storeData.voucherData?.paid || 0
                    );
                    syncAuthoritativeAmountsToSessionStore(storeData, voucherAmounts);

                    // Log the voucher data before creation
                    logToFile('Creating voucher from webhook with data:', {
                        additionalInfo: storeData.voucherData.additionalInfo,
                        additional_information_json: storeData.voucherData.additional_information_json,
                        add_to_booking_items: storeData.voucherData.add_to_booking_items
                    });

                    // Ensure paid/amount fields are persisted into voucherData before creation
                    storeData.voucherData = {
                        ...storeData.voucherData,
                        paid: voucherAmounts.paidAmount,
                        subtotal: voucherAmounts.subtotalAmount,
                        total: voucherAmounts.paidAmount,
                        original_amount: voucherAmounts.paidAmount,
                        amount: voucherAmounts.paidAmount
                    };

                    // Direct database insertion instead of HTTP call
                    const voucherId = await createVoucherFromWebhook(storeData.voucherData);
                    console.log('Webhook voucher creation completed, ID:', voucherId);

                    // Store voucher ID in session data to prevent duplicate creation
                    storeData.voucherData.voucher_id = voucherId;

                    // Send Google Ads conversion tracking (server-side)
                    // Use payment intent ID if available (string or expanded object), otherwise session ID
                    const piVoucher = session.payment_intent;
                    const transactionId = (typeof piVoucher === 'string' ? piVoucher : piVoucher?.id) || session.id;
                    const conversionValue = voucherAmounts.paidAmount || Number(storeData.totalPrice || 0);
                    const conversionCurrency = session.currency?.toUpperCase() || 'GBP';
                    
                    // Send conversion asynchronously (don't block webhook response)
                    sendGoogleAdsConversionIfNeeded(session, transactionId, conversionValue, conversionCurrency)
                        .catch((err) => {
                            const errorMessage = `Error in Google Ads conversion (non-blocking) for voucher ${voucherId || 'unknown'}. Transaction ID: ${transactionId}`;
                            console.error('❌', errorMessage, err.message);
                            
                            // Log error to database
                            const errorDetails = err.response?.data 
                                ? JSON.stringify(err.response.data) 
                                : err.message || 'Unknown error';
                            const stackTrace = err.stack || `${err.name}: ${err.message}`;
                            saveErrorLog('error', `${errorMessage}. Details: ${errorDetails}`, stackTrace, 'googleAds.webhook.voucher');
                        });

                    // Persist Stripe amounts into voucher row to power receipt fields
                    // Try to update subtotal, total, original_amount if columns exist, otherwise just update paid
                    if (voucherId && resolvedPaidAmount != null) {
                        // First try to update all amount fields
                        const updateSql = `
                            UPDATE all_vouchers 
                            SET paid = ?, subtotal = IFNULL(subtotal, ?), total = IFNULL(total, ?), original_amount = IFNULL(original_amount, ?)
                            WHERE id = ?
                        `;
                        con.query(updateSql, [resolvedPaidAmount, resolvedSubtotalAmount, resolvedPaidAmount, resolvedPaidAmount, voucherId], (err) => {
                            if (err) {
                                // If columns don't exist, just update paid
                                if (err.code === 'ER_BAD_FIELD_ERROR') {
                                    console.warn('⚠️ Amount columns (subtotal, total, original_amount) not found in database, updating only paid field');
                                    con.query('UPDATE all_vouchers SET paid = ? WHERE id = ?', [resolvedPaidAmount, voucherId], (err2) => {
                                        if (err2) {
                                            console.error('Error updating voucher paid amount from Stripe session:', err2);
                                        } else {
                                            console.log('✅ Voucher paid amount updated from Stripe session:', { voucherId, resolvedPaidAmount });
                                        }
                                    });
                                } else {
                                    console.error('Error updating voucher amounts from Stripe session:', err);
                                }
                            } else {
                                console.log('✅ Voucher amounts updated from Stripe session:', { voucherId, resolvedPaidAmount, resolvedSubtotalAmount });
                            }
                        });
                    }

                    // Send Flight Voucher Confirmation email in webhook (only once)
                    console.log('🔍 [WEBHOOK] Checking Flight Voucher email eligibility:', {
                        voucherId: voucherId,
                        voucher_type: storeData.voucherData.voucher_type,
                        book_flight: storeData.voucherData.book_flight,
                        email: storeData.voucherData.email,
                        purchaser_email: storeData.voucherData.purchaser_email
                    });
                    
                    const voucherTypeCheck = storeData.voucherData.voucher_type && !storeData.voucherData.voucher_type.toLowerCase().includes('gift');
                    // Check both book_flight and voucher_type for Flight Voucher identification
                    const bookFlightCheck = storeData.voucherData.book_flight && (storeData.voucherData.book_flight.toLowerCase().includes('flight voucher') || storeData.voucherData.book_flight.toLowerCase().includes('buy flight voucher'));
                    const voucherTypeIsFlightVoucher = storeData.voucherData.voucher_type && storeData.voucherData.voucher_type.toLowerCase().includes('flight voucher');
                    // Flight Voucher if: book_flight contains flight voucher (primary check) OR (voucher_type exists, is not gift, and is flight voucher)
                    // This ensures "Buy Flight Voucher" works even if voucher_type is null/empty
                    const isFlightVoucher = bookFlightCheck || (voucherTypeCheck && voucherTypeIsFlightVoucher);
                    
                    console.log('🔍 [WEBHOOK] Flight Voucher check results:', {
                        voucherTypeCheck: voucherTypeCheck,
                        bookFlightCheck: bookFlightCheck,
                        voucherTypeIsFlightVoucher: voucherTypeIsFlightVoucher,
                        isFlightVoucher: isFlightVoucher,
                        book_flight: storeData.voucherData.book_flight,
                        voucher_type: storeData.voucherData.voucher_type
                    });
                    
                    if (isFlightVoucher) {
                        try {
                            console.log('📧 [WEBHOOK] Sending automatic Flight Voucher Confirmation email from webhook for voucher ID:', voucherId);
                            const contactOverride = {
                                purchaser_email: storeData.voucherData.purchaser_email || storeData.voucherData.email,
                                purchaser_name: storeData.voucherData.purchaser_name || storeData.voucherData.name,
                                purchaser_phone: storeData.voucherData.phone || storeData.voucherData.mobile,
                                purchaser_mobile: storeData.voucherData.mobile || storeData.voucherData.phone
                            };
                            console.log('📧 [WEBHOOK] Contact override data:', JSON.stringify(contactOverride));
                            await sendAutomaticFlightVoucherConfirmationEmail(voucherId, contactOverride);
                            
                            // Send automatic Flight Voucher Confirmation SMS
                            console.log('========================================');
                            console.log('📱 [WEBHOOK] SMS SEND PROCESS STARTING FOR FLIGHT VOUCHER');
                            console.log('📱 [WEBHOOK] Voucher ID:', voucherId);
                            console.log('📱 [WEBHOOK] Calling sendAutomaticFlightVoucherConfirmationSms...');
                            console.log('========================================');
                            
                            try {
                                await sendAutomaticFlightVoucherConfirmationSms(voucherId, contactOverride);
                                console.log('✅ [WEBHOOK] sendAutomaticFlightVoucherConfirmationSms function called successfully');
                            } catch (smsError) {
                                console.error('❌ [WEBHOOK] Error calling sendAutomaticFlightVoucherConfirmationSms:', smsError);
                            }
                        } catch (emailErr) {
                            console.error('❌ [WEBHOOK] Error sending Flight Voucher Confirmation email from webhook:', emailErr?.message || emailErr);
                            console.error('❌ [WEBHOOK] Error stack:', emailErr?.stack);
                        }
                    } else {
                        if (!isFlightVoucher) {
                            console.log('⏭️ [WEBHOOK] Skipping Flight Voucher email - not identified as Flight Voucher');
                        }
                    }

                    // Send Gift Voucher Confirmation email in webhook (only once)
                    const isGiftVoucher = (storeData.voucherData.voucher_type && storeData.voucherData.voucher_type.toLowerCase().includes('gift')) ||
                        (storeData.voucherData.book_flight && storeData.voucherData.book_flight.toLowerCase().includes('gift'));
                    if (isGiftVoucher && !storeData.voucherData.gift_email_sent) {
                        try {
                            console.log('📧 Sending automatic Gift Voucher Confirmation email from webhook for voucher ID:', voucherId);
                            const contactOverride = {
                                purchaser_email: storeData.voucherData.purchaser_email || storeData.voucherData.email,
                                purchaser_name: storeData.voucherData.purchaser_name || storeData.voucherData.name,
                                purchaser_phone: storeData.voucherData.phone || storeData.voucherData.mobile,
                                purchaser_mobile: storeData.voucherData.mobile || storeData.voucherData.phone
                            };
                            sendAutomaticGiftVoucherConfirmationEmail(voucherId, contactOverride);
                            // Mark that email was sent to prevent duplicate in fallback
                            storeData.voucherData.gift_email_sent = true;
                            
                            // Send automatic Gift Voucher Confirmation SMS
                            console.log('========================================');
                            console.log('📱 [WEBHOOK] SMS SEND PROCESS STARTING FOR GIFT VOUCHER');
                            console.log('📱 [WEBHOOK] Voucher ID:', voucherId);
                            console.log('📱 [WEBHOOK] Calling sendAutomaticGiftVoucherConfirmationSms...');
                            console.log('========================================');
                            
                            try {
                                sendAutomaticGiftVoucherConfirmationSms(voucherId, contactOverride);
                                console.log('✅ [WEBHOOK] sendAutomaticGiftVoucherConfirmationSms function called successfully');
                            } catch (smsError) {
                                console.error('❌ [WEBHOOK] Error calling sendAutomaticGiftVoucherConfirmationSms:', smsError);
                            }
                        } catch (emailErr) {
                            console.error('Error sending Gift Voucher Confirmation email from webhook:', emailErr?.message || emailErr);
                        }
                    }

                    // Save payment history for voucher purchase
                    // Use voucher ID as the reference since there's no booking yet
                    try {
                        console.log('💳 [WEBHOOK] Saving payment history for voucher purchase, voucher ID:', voucherId);
                        // Get voucher_ref for the voucher
                        let voucherRef = null;
                        if (voucherId) {
                            try {
                                const [voucherRows] = await con.promise().query('SELECT voucher_ref FROM all_vouchers WHERE id = ?', [voucherId]);
                                if (voucherRows && voucherRows.length > 0) {
                                    voucherRef = voucherRows[0].voucher_ref;
                                }
                            } catch (err) {
                                console.warn('Could not fetch voucher_ref:', err.message);
                            }
                        }
                        await savePaymentHistory(session, null, voucherId, voucherRef);
                        
                        // Also update all_vouchers with stripe_session_id for payment tracking
                        const updateVoucherSession = `UPDATE all_vouchers SET stripe_session_id = ? WHERE id = ?`;
                        con.query(updateVoucherSession, [session.id, voucherId], (err) => {
                            if (err) {
                                // Column might not exist, that's OK
                                if (err.code !== 'ER_BAD_FIELD_ERROR') {
                                    console.error('Error updating voucher with stripe_session_id:', err);
                                }
                            } else {
                                console.log('✅ Voucher updated with stripe_session_id:', session.id);
                            }
                        });
                    } catch (paymentHistoryError) {
                        console.error('❌ Error saving payment history for voucher:', paymentHistoryError);
                    }

                    // Mark session as processed to prevent duplicate calls
                    storeData.processed = true;

                    // Webhook does NOT generate voucher code - this will be done by createBookingFromSession
                    console.log('Voucher code generation skipped in webhook - will be done by createBookingFromSession');

                    // Immediately return to prevent further processing
                    return res.json({ received: true });
                } else if (storeData.type === CUSTOMER_PORTAL_UPSELL_SESSION_TYPE) {
                    if (storeData.customerPortalUpsellData?.applied) {
                        console.log('Customer portal upsell already applied for session:', session_id);
                        return res.json({ received: true });
                    }

                    const upsellResult = await applyCustomerPortalUpsell(session, storeData);
                    console.log('✅ Webhook: Customer portal upsell applied:', upsellResult);
                    storeData.processed = true;
                    return res.json({ received: true });
                } else if (storeData.type === CUSTOMER_PORTAL_VOUCHER_UPGRADE_SESSION_TYPE) {
                    if (storeData.voucherUpgradeData?.applied) {
                        console.log('Customer portal voucher upgrade already applied for session:', session_id);
                        return res.json({ received: true });
                    }

                    const upgradeResult = await applyCustomerPortalVoucherUpgrade(session, storeData);
                    console.log('✅ Webhook: Customer portal voucher upgrade applied:', upgradeResult);
                    storeData.processed = true;
                    return res.json({ received: true });
                } else if (storeData.type === 'extend_voucher') {
                    console.log('🔄 Webhook: Extending voucher via webhook');
                    console.log('🔄 Webhook: Extend voucher data:', JSON.stringify(storeData.extendVoucherData, null, 2));
                    
                    if (!storeData.extendVoucherData) {
                        console.error('❌ Webhook: Extend voucher data not found in session store');
                        return res.status(400).json({ received: false, message: 'Extend voucher data not found' });
                    }

                    const { bookingId, months, passengerCount } = storeData.extendVoucherData;
                    
                    console.log('🔄 Webhook: Parsed extend voucher data:', { bookingId, months, passengerCount });
                    
                    if (!bookingId || !months || months <= 0) {
                        console.error('❌ Webhook: Invalid extend voucher data:', storeData.extendVoucherData);
                        return res.status(400).json({ received: false, message: 'Invalid extend voucher data' });
                    }
                    
                    console.log(`✅ Webhook: Processing extend voucher - Booking ID: ${bookingId}, Months: ${months}, Passengers: ${passengerCount}`);

                    try {
                        // Get booking and voucher information
                        const bookingInfo = await new Promise((resolve, reject) => {
                            con.query(`
                                SELECT 
                                    b.id,
                                    b.voucher_code,
                                    b.expires AS booking_expires,
                                    b.email,
                                    b.created_at,
                                    v.id AS voucher_id,
                                    v.expires AS voucher_expires,
                                    v.voucher_ref AS voucher_table_ref
                                FROM all_booking b
                                LEFT JOIN all_vouchers v ON v.voucher_ref = b.voucher_code
                                WHERE b.id = ? LIMIT 1
                            `, [bookingId], (err, rows) => {
                                if (err) {
                                    console.error('❌ Webhook: Error querying booking info:', err);
                                    reject(err);
                                } else if (rows && rows.length > 0) {
                                    resolve(rows[0]);
                                } else {
                                    console.error('❌ Webhook: No booking found for ID:', bookingId);
                                    resolve(null);
                                }
                            });
                        });

                        if (!bookingInfo) {
                            console.error('❌ Webhook: Booking not found for extend voucher:', bookingId);
                            return res.status(404).json({ received: false, message: 'Booking not found' });
                        }

                        console.log('🔍 Webhook: Booking info retrieved:', {
                            bookingId: bookingInfo.id,
                            bookingExpires: bookingInfo.booking_expires,
                            voucherId: bookingInfo.voucher_id,
                            voucherExpires: bookingInfo.voucher_expires,
                            voucherCode: bookingInfo.voucher_code,
                            voucherTableRef: bookingInfo.voucher_table_ref
                        });

                        // Determine current expiry date - prioritize booking expires, then voucher expires, then calculate from created_at
                        let currentExpires = null;
                        
                        if (bookingInfo.booking_expires) {
                            currentExpires = new Date(bookingInfo.booking_expires);
                            console.log('📅 Webhook: Using booking expires date:', currentExpires.toISOString().split('T')[0]);
                        } else if (bookingInfo.voucher_expires) {
                            currentExpires = new Date(bookingInfo.voucher_expires);
                            console.log('📅 Webhook: Using voucher expires date:', currentExpires.toISOString().split('T')[0]);
                        } else if (bookingInfo.created_at) {
                            // Calculate from created_at + 24 months default
                            currentExpires = new Date(bookingInfo.created_at);
                            currentExpires.setMonth(currentExpires.getMonth() + 24);
                            console.log('📅 Webhook: Calculated expires from created_at + 24 months:', currentExpires.toISOString().split('T')[0]);
                        } else {
                            console.error('❌ Webhook: No expiry date found, using current date + 24 months');
                            currentExpires = new Date();
                            currentExpires.setMonth(currentExpires.getMonth() + 24);
                        }

                        // Calculate new expiry date - add months to current expiry date
                        const newExpires = new Date(currentExpires);
                        const currentYear = newExpires.getFullYear();
                        const currentMonth = newExpires.getMonth();
                        const currentDay = newExpires.getDate();
                        
                        // Add months (12 months = 1 year)
                        const newYear = currentYear + Math.floor((currentMonth + months) / 12);
                        const newMonth = (currentMonth + months) % 12;
                        
                        // Create new date with proper year and month
                        const calculatedDate = new Date(newYear, newMonth, currentDay);
                        
                        // Use calculated date or fallback to setMonth if calculation fails
                        if (isNaN(calculatedDate.getTime())) {
                            console.warn('⚠️ Webhook: Date calculation failed, using setMonth fallback');
                            newExpires.setMonth(newExpires.getMonth() + months);
                        } else {
                            newExpires.setFullYear(newYear);
                            newExpires.setMonth(newMonth);
                            newExpires.setDate(currentDay);
                        }
                        
                        const newExpiresFormatted = newExpires.toISOString().split('T')[0];

                        console.log('📅 Webhook: Extending expiry date:', {
                            oldExpires: currentExpires.toISOString().split('T')[0],
                            oldExpiresFormatted: `${currentDay}/${currentMonth + 1}/${currentYear}`,
                            newExpires: newExpiresFormatted,
                            newExpiresFormatted: `${newExpires.getDate()}/${newExpires.getMonth() + 1}/${newExpires.getFullYear()}`,
                            months: months,
                            calculation: `${currentYear}-${currentMonth + 1}-${currentDay} + ${months} months = ${newExpires.getFullYear()}-${newExpires.getMonth() + 1}-${newExpires.getDate()}`
                        });

                        // ALWAYS update all_booking.expires (this is what Customer Portal and Booking Details use)
                        await new Promise((resolve, reject) => {
                            console.log(`🔄 Webhook: Executing UPDATE all_booking SET expires = '${newExpiresFormatted}' WHERE id = ${bookingInfo.id}`);
                            con.query(
                                'UPDATE all_booking SET expires = ? WHERE id = ?',
                                [newExpiresFormatted, bookingInfo.id],
                                (err, result) => {
                                    if (err) {
                                        console.error('❌ Webhook: Error updating all_booking.expires:', err);
                                        console.error('❌ Webhook: Error details:', JSON.stringify(err));
                                        reject(err);
                                    } else {
                                        console.log('✅ Webhook: Updated all_booking.expires for booking', bookingInfo.id, 'to', newExpiresFormatted);
                                        console.log('✅ Webhook: Update result - affectedRows:', result.affectedRows, 'changedRows:', result.changedRows);
                                        // Verify the update by querying the database
                                        con.query('SELECT expires FROM all_booking WHERE id = ?', [bookingInfo.id], (verifyErr, verifyRows) => {
                                            if (verifyErr) {
                                                console.error('❌ Webhook: Error verifying update:', verifyErr);
                                            } else if (verifyRows && verifyRows.length > 0) {
                                                console.log('✅ Webhook: Verified - expires in DB is now:', verifyRows[0].expires);
                                            }
                                        });
                                        resolve();
                                    }
                                }
                            );
                        });

                        // Also update all_vouchers.expires if voucher exists
                        if (bookingInfo.voucher_id) {
                            await new Promise((resolve, reject) => {
                                con.query(
                                    'UPDATE all_vouchers SET expires = ? WHERE id = ?',
                                    [newExpiresFormatted, bookingInfo.voucher_id],
                                    (err, result) => {
                                        if (err) {
                                            console.error('❌ Webhook: Error updating all_vouchers.expires:', err);
                                            // Don't reject, just log error - booking update is more important
                                        } else {
                                            console.log('✅ Webhook: Updated all_vouchers.expires for voucher', bookingInfo.voucher_id, 'to', newExpiresFormatted);
                                        }
                                        resolve();
                                    }
                                );
                            });
                        } else {
                            console.log('ℹ️ Webhook: No voucher_id found, skipping all_vouchers update');
                        }

                        // Save payment history
                        await savePaymentHistory(session, bookingId, null);

                        console.log('✅ Webhook: Voucher extended successfully:', {
                            bookingId: bookingInfo.id,
                            voucherId: bookingInfo.voucher_id || 'N/A',
                            oldExpires: currentExpires.toISOString().split('T')[0],
                            newExpires: newExpiresFormatted,
                            months: months,
                            updatedTables: ['all_booking', bookingInfo.voucher_id ? 'all_vouchers' : 'none'].filter(t => t !== 'none')
                        });

                        // Mark session as processed
                        storeData.processed = true;
                        return res.json({ received: true });
                    } catch (error) {
                        console.error('❌ Error extending voucher via webhook:', error);
                        return res.status(500).json({ received: false, message: error.message || 'Failed to extend voucher' });
                    }
                }

                // Retain session data for a grace period so fallback createBookingFromSession can read it
                // Automatically clean up after 15 minutes to avoid memory growth
                if (storeData) {
                    try {
                        storeData.cleanupAt = Date.now() + (15 * 60 * 1000);
                        setTimeout(() => {
                            if (stripeSessionStore[session_id] && stripeSessionStore[session_id].cleanupAt <= Date.now()) {
                                delete stripeSessionStore[session_id];
                                console.log('Session data auto-cleaned after grace period for:', session_id);
                            }
                        }, 15 * 60 * 1000);
                        console.log('Session data retained for 15 minutes for fallback:', session_id);
                    } catch (e) {
                        console.warn('Failed to schedule session cleanup:', e);
                    }
                }
            } catch (error) {
                console.error('Error processing webhook:', error);
                
                // Save error to logs database
                const errorMessage = `Stripe Webhook: Error processing checkout.session.completed for session ${session_id || 'unknown'}`;
                const errorDetails = error.response?.data 
                    ? JSON.stringify(error.response.data) 
                    : error.message || 'Unknown error';
                const stackTrace = error.stack || `${error.name}: ${error.message}`;
                saveErrorLog('error', `${errorMessage}. Type: ${storeData?.type || 'unknown'}, Details: ${errorDetails}`, stackTrace, 'stripe.webhook.checkout.session.completed');
                
                // Hata durumunda processed flag'ini geri al
                storeData.processed = false;
                return res.status(500).send('Internal server error');
            }
        } else if (event.type === 'payment_intent.succeeded') {
            // Handle payment_intent.succeeded to capture payments from different devices/sessions
            const paymentIntent = event.data.object;
            console.log('✅ Webhook: Payment intent succeeded:', paymentIntent.id);
            console.log('✅ Webhook: Payment intent metadata:', paymentIntent.metadata);

            try {
                // Try to find booking by metadata
                let bookingId = null;
                let voucherId = null;

                if (paymentIntent.metadata) {
                    if (paymentIntent.metadata.booking_id) {
                        bookingId = parseInt(paymentIntent.metadata.booking_id);
                    } else if (paymentIntent.metadata.bookingId) {
                        bookingId = parseInt(paymentIntent.metadata.bookingId);
                    }
                    if (paymentIntent.metadata.voucher_id) {
                        voucherId = parseInt(paymentIntent.metadata.voucher_id);
                    } else if (paymentIntent.metadata.voucherId) {
                        voucherId = parseInt(paymentIntent.metadata.voucherId);
                    }
                }

                // If no booking ID in metadata, try to find by customer email and amount
                if (!bookingId && paymentIntent.receipt_email) {
                    const paymentAmount = paymentIntent.amount ? (paymentIntent.amount / 100) : null; // Convert from cents to dollars
                    
                    // First try exact email match
                    let [bookingRows] = await con.promise().query(
                        'SELECT id, paid FROM all_booking WHERE email = ? ORDER BY created_at DESC LIMIT 10',
                        [paymentIntent.receipt_email]
                    );
                    
                    // If we have amount, try to match by email + amount (within 1% tolerance)
                    if (paymentAmount && bookingRows && bookingRows.length > 0) {
                        const matchedBooking = bookingRows.find(b => {
                            const bookingPaid = parseFloat(b.paid) || 0;
                            const diff = Math.abs(bookingPaid - paymentAmount);
                            const tolerance = Math.max(bookingPaid * 0.01, 0.10); // 1% or 10 cents, whichever is larger
                            return diff <= tolerance;
                        });
                        
                        if (matchedBooking) {
                            bookingId = matchedBooking.id;
                            console.log(`[PaymentIntent] Found booking by email + amount match: ${bookingId} (amount: ${paymentAmount}, booking paid: ${matchedBooking.paid})`);
                        } else if (bookingRows.length === 1) {
                            // If only one booking with this email, use it
                            bookingId = bookingRows[0].id;
                            console.log(`[PaymentIntent] Found booking by email (single match): ${bookingId}`);
                        }
                    } else if (bookingRows && bookingRows.length > 0) {
                        // No amount match, but we have email matches - use the most recent one
                        bookingId = bookingRows[0].id;
                        console.log(`[PaymentIntent] Found booking by email (most recent): ${bookingId}`);
                    }
                }
                
                // Also try customer_email if receipt_email didn't work
                if (!bookingId && paymentIntent.customer_email) {
                    const paymentAmount = paymentIntent.amount ? (paymentIntent.amount / 100) : null;
                    
                    let [bookingRows] = await con.promise().query(
                        'SELECT id, paid FROM all_booking WHERE email = ? ORDER BY created_at DESC LIMIT 10',
                        [paymentIntent.customer_email]
                    );
                    
                    if (paymentAmount && bookingRows && bookingRows.length > 0) {
                        const matchedBooking = bookingRows.find(b => {
                            const bookingPaid = parseFloat(b.paid) || 0;
                            const diff = Math.abs(bookingPaid - paymentAmount);
                            const tolerance = Math.max(bookingPaid * 0.01, 0.10);
                            return diff <= tolerance;
                        });
                        
                        if (matchedBooking) {
                            bookingId = matchedBooking.id;
                            console.log(`[PaymentIntent] Found booking by customer_email + amount: ${bookingId}`);
                        } else if (bookingRows.length === 1) {
                            bookingId = bookingRows[0].id;
                            console.log(`[PaymentIntent] Found booking by customer_email (single match): ${bookingId}`);
                        }
                    } else if (bookingRows && bookingRows.length > 0) {
                        bookingId = bookingRows[0].id;
                        console.log(`[PaymentIntent] Found booking by customer_email (most recent): ${bookingId}`);
                    }
                }

                // Check if payment history already exists for this payment intent
                if (paymentIntent.id) {
                    const [existingPayments] = await con.promise().query(
                        'SELECT id FROM payment_history WHERE stripe_payment_intent_id = ?',
                        [paymentIntent.id]
                    );

                    if (existingPayments && existingPayments.length > 0) {
                        console.log(`[PaymentIntent] Payment history already exists for payment intent ${paymentIntent.id}`);
                        return res.json({ received: true, message: 'Payment already recorded' });
                    }
                }

                // Try to get checkout session from payment intent
                let session = null;
                if (paymentIntent.metadata && paymentIntent.metadata.checkout_session_id) {
                    try {
                        session = await stripe.checkout.sessions.retrieve(paymentIntent.metadata.checkout_session_id);
                        console.log(`[PaymentIntent] Retrieved checkout session: ${session.id}`);
                    } catch (sessionError) {
                        console.warn(`[PaymentIntent] Could not retrieve checkout session: ${sessionError.message}`);
                    }
                }

                // If we have a session, use it; otherwise create a mock session from payment intent
                if (!session) {
                    session = {
                        id: `pi_${paymentIntent.id}`,
                        payment_intent: paymentIntent.id,
                        amount_total: paymentIntent.amount,
                        currency: paymentIntent.currency,
                        payment_status: 'paid'
                    };
                }

                // Save payment history
                if (bookingId || voucherId) {
                    // Get voucher_ref for the voucher
                    let voucherRef = null;
                    if (voucherId) {
                        try {
                            const [voucherRows] = await con.promise().query('SELECT voucher_ref FROM all_vouchers WHERE id = ?', [voucherId]);
                            if (voucherRows && voucherRows.length > 0) {
                                voucherRef = voucherRows[0].voucher_ref;
                            }
                        } catch (err) {
                            console.warn('Could not fetch voucher_ref:', err.message);
                        }
                    }
                    await savePaymentHistory(session, bookingId, voucherId, voucherRef);
                    console.log(`✅ [PaymentIntent] Payment history saved for booking ${bookingId || 'N/A'}, voucher ${voucherId || 'N/A'}`);
                } else {
                    console.warn(`⚠️ [PaymentIntent] Could not determine booking/voucher ID for payment intent ${paymentIntent.id}`);
                    // Still try to save with null booking/voucher - might be linked later via sync
                    await savePaymentHistory(session, null, null);
                }
            } catch (piError) {
                console.error('Error processing payment_intent.succeeded:', piError);
                
                // Save error to logs database
                const errorMessage = `Stripe Webhook: Error processing payment_intent.succeeded for payment intent ${paymentIntent?.id || 'unknown'}`;
                const errorDetails = piError.response?.data 
                    ? JSON.stringify(piError.response.data) 
                    : piError.message || 'Unknown error';
                const stackTrace = piError.stack || `${piError.name}: ${piError.message}`;
                saveErrorLog('error', `${errorMessage}. Details: ${errorDetails}`, stackTrace, 'stripe.webhook.payment_intent.succeeded');
                
                // Don't fail the webhook - just log the error
            }
        } else {
            console.log('Webhook event type not handled:', event.type);
        }

        res.json({ received: true });
    } catch (error) {
        console.error('Webhook processing error:', error);
        
        // Save error to logs database
        const errorMessage = `Stripe Webhook: General processing error for event type ${event?.type || 'unknown'}`;
        const errorDetails = error.response?.data 
            ? JSON.stringify(error.response.data) 
            : error.message || 'Unknown error';
        const stackTrace = error.stack || `${error.name}: ${error.message}`;
        saveErrorLog('error', `${errorMessage}. Details: ${errorDetails}`, stackTrace, 'stripe.webhook.general');
        
        res.status(500).send('Webhook processing failed');
    }
});

