// ===== Activity pricing cache (used for passenger inference) =====
const DEFAULT_LOCATION_KEY = '__default__';
const ACTIVITY_PRICING_REFRESH_INTERVAL = 5 * 60 * 1000;
const SHARED_VOUCHER_ALIAS_MAP = {
    'weekday morning': 'weekday_morning_price',
    'weekday morning flight': 'weekday_morning_price',
    'weekday morning voucher': 'weekday_morning_price',
    'flexible weekday': 'flexible_weekday_price',
    'flexible weekday flight': 'flexible_weekday_price',
    'flexible weekday voucher': 'flexible_weekday_price',
    'flexible weekday (shared flight)': 'flexible_weekday_price',
    'any day flight': 'any_day_flight_price',
    'any day': 'any_day_flight_price'
};
const CUSTOMER_PORTAL_SHARED_PRICE_FALLBACK_MAP = {
    'weekday morning': 180,
    'weekday morning flight': 180,
    'weekday morning voucher': 180,
    'flexible weekday': 200,
    'flexible weekday flight': 200,
    'flexible weekday voucher': 200,
    'flexible weekday (shared flight)': 200,
    'any day flight': 220,
    'any day': 220
};

let sharedVoucherPriceCache = {};
let privateCharterPriceCache = {};
let lastActivityPricingRefresh = 0;

const parsePositiveInt = (value) => {
    const parsed = Number.parseInt(value, 10);
    return Number.isFinite(parsed) && parsed > 0 ? parsed : null;
};

const tryParseJson = (raw) => {
    if (!raw || typeof raw !== 'string') return raw;
    try {
        return JSON.parse(raw);
    } catch (_) {
        return raw;
    }
};

const normalizeAdditionalInfoPayload = (value) => {
    const parsedValue = tryParseJson(value);
    if (!parsedValue || typeof parsedValue !== 'object' || Array.isArray(parsedValue)) {
        return {};
    }
    return { ...parsedValue };
};

const hasMeaningfulAdditionalInfoValue = (value) => {
    if (value === undefined || value === null) return false;
    if (typeof value === 'string') return value.trim() !== '';
    if (typeof value === 'number') return Number.isFinite(value);
    if (typeof value === 'boolean') return true;
    if (Array.isArray(value)) return value.length > 0;
    if (typeof value === 'object') return Object.keys(value).length > 0;
    return false;
};

const trimStringOrNull = (value) => {
    if (typeof value !== 'string') return null;
    const trimmed = value.trim();
    return trimmed || null;
};

const getAdditionalInfoValue = (additionalInfo, keys = []) => {
    const normalized = normalizeAdditionalInfoPayload(additionalInfo);

    for (const key of keys) {
        const value = normalized[key];
        if (!hasMeaningfulAdditionalInfoValue(value)) continue;
        if (typeof value === 'string') {
            return value.trim();
        }
        if (value && typeof value === 'object' && !Array.isArray(value)) {
            return { ...value };
        }
        if (Array.isArray(value)) {
            return [...value];
        }
        return value;
    }

    return null;
};

const normalizePreferForStorage = (value) => {
    if (!hasMeaningfulAdditionalInfoValue(value)) {
        return null;
    }

    if (value && typeof value === 'object' && !Array.isArray(value)) {
        const selectedValues = Object.keys(value).filter(key => value[key]);
        return selectedValues.length > 0 ? selectedValues.join(', ') : null;
    }

    if (typeof value === 'string') {
        return value.trim() || null;
    }

    return String(value).trim() || null;
};

const buildExistingBookingAdditionalInfoPayload = (bookingRow) => {
    const existingPayload = normalizeAdditionalInfoPayload(bookingRow?.additional_information_json);

    if (!hasMeaningfulAdditionalInfoValue(existingPayload.notes) && trimStringOrNull(bookingRow?.additional_notes)) {
        existingPayload.notes = trimStringOrNull(bookingRow.additional_notes);
    }
    if (
        !hasMeaningfulAdditionalInfoValue(existingPayload.hearAboutUs) &&
        !hasMeaningfulAdditionalInfoValue(existingPayload.hear_about_us) &&
        trimStringOrNull(bookingRow?.hear_about_us)
    ) {
        existingPayload.hearAboutUs = trimStringOrNull(bookingRow.hear_about_us);
    }
    if (
        !hasMeaningfulAdditionalInfoValue(existingPayload.reason) &&
        !hasMeaningfulAdditionalInfoValue(existingPayload.ballooning_reason) &&
        trimStringOrNull(bookingRow?.ballooning_reason)
    ) {
        existingPayload.reason = trimStringOrNull(bookingRow.ballooning_reason);
    }
    if (!hasMeaningfulAdditionalInfoValue(existingPayload.prefer) && trimStringOrNull(bookingRow?.prefer)) {
        existingPayload.prefer = trimStringOrNull(bookingRow.prefer);
    }

    return existingPayload;
};

const buildAdditionalInfoAnswerPayloadFromRows = (rows = []) => {
    return rows.reduce((payload, row) => {
        const questionId = parsePositiveInt(row?.question_id);
        if (!questionId || !hasMeaningfulAdditionalInfoValue(row?.answer)) {
            return payload;
        }

        const key = `question_${questionId}`;
        if (payload[key] !== undefined) {
            return payload;
        }

        payload[key] = typeof row.answer === 'string' ? row.answer.trim() : row.answer;
        return payload;
    }, {});
};

const loadBookingAdditionalInfoSnapshot = ({ connection, bookingId, callback }) => {
    const parsedBookingId = parsePositiveInt(bookingId);
    if (!parsedBookingId) {
        callback(null, {
            bookingRow: null,
            answerPayload: {}
        });
        return;
    }

    connection.query(
        `SELECT
            paid,
            additional_notes,
            hear_about_us,
            ballooning_reason,
            prefer,
            additional_information_json
        FROM all_booking
        WHERE id = ?`,
        [parsedBookingId],
        (bookingErr, bookingRows = []) => {
            if (bookingErr) {
                callback(bookingErr, {
                    bookingRow: null,
                    answerPayload: {}
                });
                return;
            }

            connection.query(
                `SELECT question_id, answer
                FROM additional_information_answers
                WHERE booking_id = ?`,
                [parsedBookingId],
                (newAnswersErr, newAnswerRows = []) => {
                    if (newAnswersErr) {
                        console.warn('⚠️ loadBookingAdditionalInfoSnapshot could not load additional_information_answers:', newAnswersErr.message);
                        callback(null, {
                            bookingRow: bookingRows[0] || null,
                            answerPayload: {}
                        });
                        return;
                    }

                    connection.query(
                        `SELECT question_id, answer
                        FROM additional_info_answers
                        WHERE booking_id = ?`,
                        [parsedBookingId],
                        (legacyAnswersErr, legacyAnswerRows = []) => {
                            if (legacyAnswersErr) {
                                console.warn('⚠️ loadBookingAdditionalInfoSnapshot could not load additional_info_answers:', legacyAnswersErr.message);
                            }

                            callback(null, {
                                bookingRow: bookingRows[0] || null,
                                answerPayload: buildAdditionalInfoAnswerPayloadFromRows([
                                    ...newAnswerRows,
                                    ...(legacyAnswersErr ? [] : legacyAnswerRows)
                                ])
                            });
                        }
                    );
                }
            );
        }
    );
};

const mergeRebookAdditionalInfoPayload = ({ incomingAdditionalInfo, existingBookingRow, existingAnswerPayload = {} }) => {
    return {
        ...buildExistingBookingAdditionalInfoPayload(existingBookingRow),
        ...normalizeAdditionalInfoPayload(existingAnswerPayload),
        ...normalizeAdditionalInfoPayload(incomingAdditionalInfo)
    };
};

const persistBookingAdditionalInfoPayload = ({
    connection,
    bookingId,
    additionalInfo,
    logPrefix = '[additionalInfo]'
}, callback = () => {}) => {
    if (!additionalInfo || typeof additionalInfo !== 'object') {
        callback();
        return;
    }

    try {
        const { __requiredKeys, ...rawAdditionalInfo } = normalizeAdditionalInfoPayload(additionalInfo);
        const meaningfulEntries = Object.entries(rawAdditionalInfo).filter(([, value]) =>
            hasMeaningfulAdditionalInfoValue(value)
        );

        if (meaningfulEntries.length === 0) {
            console.log(`ℹ️ ${logPrefix} No meaningful additionalInfo payload to persist; existing booking additional info left unchanged.`);
            callback();
            return;
        }

        const legacyAnswers = [];
        const newAnswers = [];
        const jsonData = {};

        meaningfulEntries.forEach(([key, value]) => {
            if (!hasMeaningfulAdditionalInfoValue(value)) return;

            if (key.startsWith('question_')) {
                const questionId = parsePositiveInt(key.replace('question_', ''));
                if (!questionId) return;

                const normalizedAnswer = typeof value === 'string' ? value.trim() : value;
                legacyAnswers.push([bookingId, questionId, normalizedAnswer]);
                newAnswers.push([bookingId, questionId, normalizedAnswer]);
                jsonData[key] = normalizedAnswer;
                return;
            }

            if (typeof value === 'string') {
                jsonData[key] = value.trim();
                return;
            }

            if (Array.isArray(value)) {
                jsonData[key] = [...value];
                return;
            }

            if (value && typeof value === 'object') {
                jsonData[key] = { ...value };
                return;
            }

            jsonData[key] = value;
        });

        const finalizeJsonUpdate = () => {
            const jsonPayload = Object.keys(jsonData).length > 0 ? JSON.stringify(jsonData) : null;
            connection.query(
                'UPDATE all_booking SET additional_information_json = ? WHERE id = ?',
                [jsonPayload, bookingId],
                (jsonErr) => {
                    if (jsonErr) {
                        console.error(`Error updating all_booking.additional_information_json ${logPrefix}:`, jsonErr);
                    }
                    callback();
                }
            );
        };

        const insertNewAnswers = () => {
            if (newAnswers.length === 0) {
                finalizeJsonUpdate();
                return;
            }

            connection.query(
                'INSERT INTO additional_information_answers (booking_id, question_id, answer) VALUES ?',
                [newAnswers],
                (newErr) => {
                    if (newErr) {
                        console.error(`Error saving additional_information_answers ${logPrefix}:`, newErr);
                    }
                    finalizeJsonUpdate();
                }
            );
        };

        const insertLegacyAnswers = () => {
            if (legacyAnswers.length === 0) {
                insertNewAnswers();
                return;
            }

            connection.query(
                'INSERT INTO additional_info_answers (booking_id, question_id, answer) VALUES ?',
                [legacyAnswers],
                (legacyErr) => {
                    if (legacyErr) {
                        console.error(`Error saving legacy additional_info_answers ${logPrefix}:`, legacyErr);
                    }
                    insertNewAnswers();
                }
            );
        };

        if (legacyAnswers.length > 0 || newAnswers.length > 0) {
            connection.query(
                'DELETE FROM additional_info_answers WHERE booking_id = ?',
                [bookingId],
                (deleteLegacyErr) => {
                    if (deleteLegacyErr) {
                        console.error(`Error clearing legacy additional_info_answers ${logPrefix}:`, deleteLegacyErr);
                    }

                    connection.query(
                        'DELETE FROM additional_information_answers WHERE booking_id = ?',
                        [bookingId],
                        (deleteNewErr) => {
                            if (deleteNewErr) {
                                console.error(`Error clearing additional_information_answers ${logPrefix}:`, deleteNewErr);
                            }
                            insertLegacyAnswers();
                        }
                    );
                }
            );
            return;
        }

        console.log(`ℹ️ ${logPrefix} No question_* answers in payload; existing additional info answer rows left unchanged.`);
        finalizeJsonUpdate();
    } catch (error) {
        console.error(`Error while saving ${logPrefix} additionalInfo:`, error);
        callback();
    }
};

const resolveBookingAdditionalInfoColumns = ({
    additionalInfo,
    existingBookingRow = null,
    preserveExistingLegacy = false
} = {}) => {
    const existingAdditionalNotes = trimStringOrNull(existingBookingRow?.additional_notes);
    const existingHearAboutUs = trimStringOrNull(existingBookingRow?.hear_about_us);
    const existingReason = trimStringOrNull(existingBookingRow?.ballooning_reason);
    const existingPrefer = trimStringOrNull(existingBookingRow?.prefer);

    const resolvedNotes = getAdditionalInfoValue(additionalInfo, ['notes']);
    const resolvedHearAboutUs = getAdditionalInfoValue(additionalInfo, ['hearAboutUs', 'hear_about_us']);
    const resolvedReason = getAdditionalInfoValue(additionalInfo, ['reason', 'ballooning_reason']);
    const resolvedPrefer = normalizePreferForStorage(getAdditionalInfoValue(additionalInfo, ['prefer']));

    return {
        additional_notes:
            (preserveExistingLegacy && existingAdditionalNotes) ||
            trimStringOrNull(resolvedNotes) ||
            existingAdditionalNotes ||
            null,
        hear_about_us:
            (preserveExistingLegacy && existingHearAboutUs) ||
            trimStringOrNull(resolvedHearAboutUs) ||
            existingHearAboutUs ||
            null,
        ballooning_reason:
            (preserveExistingLegacy && existingReason) ||
            trimStringOrNull(resolvedReason) ||
            existingReason ||
            null,
        prefer:
            (preserveExistingLegacy && existingPrefer) ||
            resolvedPrefer ||
            existingPrefer ||
            null
    };
};

const safeArrayLength = (value) => {
    if (!value) return null;
    const maybeArray = tryParseJson(value);
    if (Array.isArray(maybeArray)) {
        return maybeArray.filter(item => item !== undefined && item !== null).length || maybeArray.length;
    }
    return null;
};

const toNumberOrNull = (value) => {
    if (value === undefined || value === null) return null;
    if (typeof value === 'number') {
        return Number.isFinite(value) ? value : null;
    }
    if (typeof value === 'string') {
        const normalized = value.replace(',', '.');
        const parsed = Number(normalized);
        return Number.isFinite(parsed) ? parsed : null;
    }
    return null;
};

const normalizeLocationKey = (location) => {
    if (!location || typeof location !== 'string') return DEFAULT_LOCATION_KEY;
    const trimmed = location.trim();
    return trimmed ? trimmed.toLowerCase() : DEFAULT_LOCATION_KEY;
};

const normalizeVoucherTitle = (title) => {
    if (!title) return '';
    let normalized = String(title).trim().toLowerCase();

    // Customer portal bookings can surface labels like
    // "Shared - Any Day Voucher"; map these to pricing aliases.
    normalized = normalized.replace(/^shared\s*-\s*/i, '').trim();

    if (normalized.includes('any day') && normalized.includes('voucher')) {
        return 'any day flight';
    }
    if (normalized.includes('weekday morning') && normalized.includes('voucher')) {
        return 'weekday morning';
    }
    if (normalized.includes('flexible weekday') && normalized.includes('voucher')) {
        return 'flexible weekday';
    }

    return normalized;
};

const buildSharedPricingEntry = (row) => {
    const entry = {};
    Object.entries(SHARED_VOUCHER_ALIAS_MAP).forEach(([alias, column]) => {
        const price = toNumberOrNull(row[column]);
        if (price) {
            entry[alias] = price;
        }
    });
    return entry;
};

const parsePrivateCharterPricing = (raw) => {
    if (!raw) return null;
    let data = raw;
    try {
        if (typeof data === 'string') {
            data = JSON.parse(data);
        }
    } catch (err) {
        console.warn('Failed to parse private_charter_pricing:', err?.message || err);
        return null;
    }
    if (!data || typeof data !== 'object') return null;
    const normalized = {};
    Object.entries(data).forEach(([title, value]) => {
        const normalizedTitle = normalizeVoucherTitle(title);
        if (!normalizedTitle) return;
        if (value && typeof value === 'object') {
            const paxMap = {};
            Object.entries(value).forEach(([pax, groupPrice]) => {
                const parsed = toNumberOrNull(groupPrice);
                if (parsed) {
                    paxMap[String(pax)] = parsed;
                }
            });
            if (Object.keys(paxMap).length > 0) {
                normalized[normalizedTitle] = paxMap;
            }
        } else {
            const parsedSingle = toNumberOrNull(value);
            if (parsedSingle) {
                normalized[normalizedTitle] = { '2': parsedSingle };
            }
        }
    });
    return Object.keys(normalized).length > 0 ? normalized : null;
};

const refreshActivityPricingCache = (force = false) => {
    const now = Date.now();
    if (!force && now - lastActivityPricingRefresh < ACTIVITY_PRICING_REFRESH_INTERVAL) {
        return Promise.resolve();
    }
    return new Promise((resolve, reject) => {
        const sql = `
            SELECT location, weekday_morning_price, flexible_weekday_price, any_day_flight_price, private_charter_pricing
            FROM activity
            WHERE status = 'Live'
        `;
        con.query(sql, (err, rows) => {
            if (err) {
                console.error('Failed to refresh activity pricing cache:', err);
                return reject(err);
            }
            const nextShared = {};
            const nextPrivate = {};
            const aggregateShared = {};
            const aggregatePrivate = {};
            rows.forEach((row) => {
                const locationKey = normalizeLocationKey(row.location);
                const sharedEntry = buildSharedPricingEntry(row);
                if (Object.keys(sharedEntry).length > 0) {
                    nextShared[locationKey] = sharedEntry;
                    Object.entries(sharedEntry).forEach(([alias, price]) => {
                        if (aggregateShared[alias] == null) {
                            aggregateShared[alias] = price;
                        }
                    });
                }
                const privateEntry = parsePrivateCharterPricing(row.private_charter_pricing);
                if (privateEntry) {
                    nextPrivate[locationKey] = privateEntry;
                    Object.entries(privateEntry).forEach(([title, paxMap]) => {
                        if (!aggregatePrivate[title]) {
                            aggregatePrivate[title] = paxMap;
                        }
                    });
                }
            });
            if (Object.keys(aggregateShared).length > 0) {
                nextShared[DEFAULT_LOCATION_KEY] = aggregateShared;
            }
            if (Object.keys(aggregatePrivate).length > 0) {
                nextPrivate[DEFAULT_LOCATION_KEY] = aggregatePrivate;
            }
            sharedVoucherPriceCache = nextShared;
            privateCharterPriceCache = nextPrivate;
            lastActivityPricingRefresh = Date.now();
            resolve();
        });
    });
};

// Warm the cache on startup and refresh periodically
refreshActivityPricingCache(true).catch((err) => {
    console.error('Initial activity pricing cache load failed:', err?.message || err);
});
const pricingRefreshInterval = setInterval(() => {
    refreshActivityPricingCache().catch((err) => {
        console.error('Activity pricing cache refresh failed:', err?.message || err);
    });
}, ACTIVITY_PRICING_REFRESH_INTERVAL);
if (pricingRefreshInterval && pricingRefreshInterval.unref) {
    pricingRefreshInterval.unref();
}

const getSharedVoucherPriceFromCache = (voucherTitle, location) => {
    const normalizedTitle = normalizeVoucherTitle(voucherTitle);
    if (!normalizedTitle) return null;
    const locationKey = normalizeLocationKey(location);
    const locationPrices = sharedVoucherPriceCache[locationKey];
    if (locationPrices && locationPrices[normalizedTitle]) {
        return locationPrices[normalizedTitle];
    }
    const fallback = sharedVoucherPriceCache[DEFAULT_LOCATION_KEY];
    return fallback ? fallback[normalizedTitle] || null : null;
};

const resolveCustomerPortalSharedSeatPrice = async (voucherTitle, location) => {
    const normalizedTitle = normalizeVoucherTitle(voucherTitle);
    if (!normalizedTitle) return null;

    let resolvedPrice = getSharedVoucherPriceFromCache(normalizedTitle, location);
    if (resolvedPrice != null) {
        return roundCurrency(resolvedPrice);
    }

    try {
        await refreshActivityPricingCache(true);
        resolvedPrice = getSharedVoucherPriceFromCache(normalizedTitle, location);
        if (resolvedPrice != null) {
            return roundCurrency(resolvedPrice);
        }
    } catch (error) {
        console.warn('Customer Portal - Shared pricing cache refresh failed:', error?.message || error);
    }

    const activityQueries = location
        ? [
            {
                sql: `
                    SELECT weekday_morning_price, flexible_weekday_price, any_day_flight_price
                    FROM activity
                    WHERE status = 'Live' AND location = ?
                    ORDER BY id DESC
                    LIMIT 1
                `,
                params: [location]
            },
            {
                sql: `
                    SELECT weekday_morning_price, flexible_weekday_price, any_day_flight_price
                    FROM activity
                    WHERE status = 'Live'
                    ORDER BY id DESC
                    LIMIT 1
                `,
                params: []
            }
        ]
        : [
            {
                sql: `
                    SELECT weekday_morning_price, flexible_weekday_price, any_day_flight_price
                    FROM activity
                    WHERE status = 'Live'
                    ORDER BY id DESC
                    LIMIT 1
                `,
                params: []
            }
        ];

    for (const query of activityQueries) {
        try {
            const rows = await runPoolQuery(query.sql, query.params);
            if (!rows || rows.length === 0) continue;
            const rowPricing = buildSharedPricingEntry(rows[0]);
            const rowPrice = rowPricing[normalizedTitle];
            if (rowPrice != null) {
                return roundCurrency(rowPrice);
            }
        } catch (error) {
            console.warn('Customer Portal - Shared pricing lookup query failed:', error?.message || error);
        }
    }

    const staticFallbackPrice = CUSTOMER_PORTAL_SHARED_PRICE_FALLBACK_MAP[normalizedTitle];
    if (staticFallbackPrice != null) {
        return roundCurrency(staticFallbackPrice);
    }

    return null;
};

const getPrivateCharterPricingFromCache = (voucherTitle, location) => {
    const normalizedTitle = normalizeVoucherTitle(voucherTitle);
    if (!normalizedTitle) return null;
    const locationKey = normalizeLocationKey(location);
    const locationPricing = privateCharterPriceCache[locationKey];
    if (locationPricing && locationPricing[normalizedTitle]) {
        return locationPricing[normalizedTitle];
    }
    const fallback = privateCharterPriceCache[DEFAULT_LOCATION_KEY];
    return fallback ? fallback[normalizedTitle] || null : null;
};

const inferPrivateCharterPassengersFromPrice = (voucherTitle, location, totalPrice) => {
    if (!totalPrice || Number(totalPrice) <= 0) return null;
    const normalizedTotal = Number(totalPrice);

    // First try exact match with voucher title
    const pricing = getPrivateCharterPricingFromCache(voucherTitle, location);
    if (pricing) {
        for (const [pax, price] of Object.entries(pricing)) {
            const parsedPrice = Number(price);
            if (!Number.isFinite(parsedPrice) || parsedPrice <= 0) continue;
            if (Math.abs(parsedPrice - normalizedTotal) < 0.01) {
                const paxInt = parsePositiveInt(pax);
                if (paxInt) {
                    console.log(`[inferPrivateCharterPassengersFromPrice] Found exact match: ${paxInt} passengers for price ${normalizedTotal}`);
                    return paxInt;
                }
            }
        }
    }

    // If no exact match, try to find in all Private Charter pricing entries
    // This handles cases where voucher title doesn't match exactly (e.g., "Private Charter Flights" vs "Private Charter Flights (8 passengers)")
    const locationKey = normalizeLocationKey(location);
    const locationPricing = privateCharterPriceCache[locationKey] || privateCharterPriceCache[DEFAULT_LOCATION_KEY] || {};

    for (const [title, paxMap] of Object.entries(locationPricing)) {
        // Check if this title is related to Private Charter (fuzzy match)
        const titleLower = title.toLowerCase();
        const voucherTitleLower = (voucherTitle || '').toLowerCase();
        if (titleLower.includes('private') && titleLower.includes('charter')) {
            for (const [pax, price] of Object.entries(paxMap)) {
                const parsedPrice = Number(price);
                if (!Number.isFinite(parsedPrice) || parsedPrice <= 0) continue;
                if (Math.abs(parsedPrice - normalizedTotal) < 0.01) {
                    const paxInt = parsePositiveInt(pax);
                    if (paxInt) {
                        console.log(`[inferPrivateCharterPassengersFromPrice] Found match in alternative title "${title}": ${paxInt} passengers for price ${normalizedTotal}`);
                        return paxInt;
                    }
                }
            }
        }
    }

    console.log(`[inferPrivateCharterPassengersFromPrice] No match found for price ${normalizedTotal} with title "${voucherTitle}"`);
    return null;
};

