const CUSTOMER_PORTAL_FLIGHT_ATTEMPT_NOTIFICATION_DEFAULT_MAP = CUSTOMER_PORTAL_FLIGHT_ATTEMPT_NOTIFICATION_DEFAULTS.reduce((accumulator, definition) => {
    accumulator[definition.attempt_bucket] = definition;
    return accumulator;
}, {});

const roundCurrency = (value) => {
    const parsed = Number(value) || 0;
    return Math.round(parsed * 100) / 100;
};

const runPoolQuery = (sql, params = []) => new Promise((resolve, reject) => {
    con.query(sql, params, (err, rows) => {
        if (err) {
            reject(err);
        } else {
            resolve(rows);
        }
    });
});

const getExistingTableColumns = async (tableName) => {
    try {
        const rows = await runPoolQuery('SHOW COLUMNS FROM ??', [tableName]);
        return new Set((rows || []).map((row) => row.Field));
    } catch (error) {
        console.warn(`Could not inspect table columns for ${tableName}:`, error?.message || error);
        return new Set();
    }
};

const isCustomerPortalSharedBooking = (booking = {}) => {
    const haystack = `${booking.flight_type || ''} ${booking.experience || ''}`.toLowerCase();
    return !haystack.includes('private');
};

const getOrdinalSuffix = (dayNumber) => {
    const normalizedDay = Number(dayNumber) || 0;
    if (normalizedDay >= 11 && normalizedDay <= 13) {
        return 'th';
    }

    switch (normalizedDay % 10) {
        case 1:
            return 'st';
        case 2:
            return 'nd';
        case 3:
            return 'rd';
        default:
            return 'th';
    }
};

const formatInviteFriendsExperienceDate = (flightDate, timeSlot = null) => {
    if (!flightDate || !dayjs(flightDate).isValid()) {
        return null;
    }

    let formattedDate = dayjs(flightDate);
    if (timeSlot) {
        const parsedTime = dayjs(`2000-01-01 ${timeSlot}`);
        if (parsedTime.isValid()) {
            formattedDate = formattedDate
                .hour(parsedTime.hour())
                .minute(parsedTime.minute())
                .second(parsedTime.second());
        }
    }

    const dayOfMonth = formattedDate.date();
    return `${formattedDate.format('dddd')} ${dayOfMonth}${getOrdinalSuffix(dayOfMonth)} ${formattedDate.format('MMMM h:mmA')}`;
};

const buildInviteFriendsShareMessage = ({ location, experienceDateTime, bookingUrl = BOOK_SITE_BASE_URL }) => {
    return [
        `Hello! We're booked on a shared balloon ride with Fly Away Ballooning in ${location || 'Somerset'} on ${experienceDateTime || 'our scheduled flight'}.`,
        "There are still spaces left on our flight if you'd like to join us.",
        'You can book here:',
        bookingUrl,
        `Use the discount code ${INVITE_FRIENDS_DISCOUNT_CODE} to get 10% off your booking.`
    ].join('\n');
};

const buildInviteFriendsShareLinks = (shareMessage) => {
    if (!shareMessage) {
        return null;
    }

    const encodedMessage = encodeURIComponent(shareMessage);
    const emailSubject = encodeURIComponent('Join us on our balloon flight');

    return {
        whatsapp: `https://wa.me/?text=${encodedMessage}`,
        sms: `sms:?&body=${encodedMessage}`,
        email: `mailto:?subject=${emailSubject}&body=${encodedMessage}`
    };
};

const getCustomerPortalFlightAttemptBucket = (flightAttempts) => {
    const attempts = Number.parseInt(flightAttempts, 10);
    if (!Number.isFinite(attempts) || attempts < 3) {
        return null;
    }

    if (attempts === 3) return 'attempt_3';
    if (attempts === 4) return 'attempt_4';
    if (attempts === 5) return 'attempt_5';
    return 'attempt_6_plus';
};

const getCustomerPortalAttemptsRemainingBeforeExtension = (flightAttempts) => {
    const attempts = Number.parseInt(flightAttempts, 10);
    if (!Number.isFinite(attempts) || attempts <= 0) {
        return CUSTOMER_PORTAL_ATTEMPT_EXTENSION_THRESHOLD;
    }

    return Math.max(0, CUSTOMER_PORTAL_ATTEMPT_EXTENSION_THRESHOLD - attempts);
};

const applyCustomerPortalFlightAttemptTemplate = (templateHtml, replacements = {}) => {
    let nextTemplate = String(templateHtml || '');

    Object.entries(replacements).forEach(([key, value]) => {
        const placeholder = new RegExp(`{{\\s*${key}\\s*}}`, 'gi');
        nextTemplate = nextTemplate.replace(placeholder, String(value ?? ''));
    });

    return nextTemplate;
};

const buildCustomerPortalFlightAttemptNotification = async ({
    booking,
    flightAttempts,
    isFlightVoucher = false,
    isVoucherRedeemed = false
}) => {
    if (!booking) {
        return null;
    }

    if (isFlightVoucher && !isVoucherRedeemed) {
        return null;
    }

    const attemptBucket = getCustomerPortalFlightAttemptBucket(flightAttempts);
    if (!attemptBucket) {
        return null;
    }

    const attempts = Number.parseInt(flightAttempts, 10);
    const remainingAttempts = getCustomerPortalAttemptsRemainingBeforeExtension(attempts);
    const fallbackDefinition = CUSTOMER_PORTAL_FLIGHT_ATTEMPT_NOTIFICATION_DEFAULT_MAP[attemptBucket];
    let configRows = [];
    try {
        configRows = await runPoolQuery(
            `
                SELECT id, attempt_bucket, admin_label, body_html, is_active, sort_order, updated_at
                FROM customer_portal_flight_attempt_notifications
                WHERE attempt_bucket = ?
                LIMIT 1
            `,
            [attemptBucket]
        );
    } catch (error) {
        console.warn('Could not load customer portal flight attempt notification config, using defaults:', error?.message);
    }
    const config = configRows && configRows.length > 0
        ? configRows[0]
        : fallbackDefinition;

    if (!config || Number(config.is_active) === 0) {
        return null;
    }

    return {
        visible: true,
        attemptBucket,
        attemptCount: attempts,
        attemptsRemainingBeforeExtension: remainingAttempts,
        label: config.admin_label || fallbackDefinition?.admin_label || 'Flight Attempt Notification',
        bodyHtml: applyCustomerPortalFlightAttemptTemplate(
            config.body_html || fallbackDefinition?.body_html || '',
            {
                attempts_remaining: remainingAttempts,
                flight_attempts_remaining: remainingAttempts,
                attempt_number: attempts
            }
        )
    };
};

const getCustomerPortalUpsellDiscount = (voucherTitle, regularSeatPrice) => {
    const normalizedTitle = normalizeVoucherTitle(voucherTitle);
    if (!normalizedTitle) return null;

    const isSupportedSharedVoucher =
        normalizedTitle.includes('weekday morning') ||
        normalizedTitle.includes('flexible weekday') ||
        normalizedTitle.includes('any day');

    const parsedRegularSeatPrice = Number(regularSeatPrice);
    if (!isSupportedSharedVoucher || !Number.isFinite(parsedRegularSeatPrice) || parsedRegularSeatPrice <= 0) {
        return null;
    }

    return roundCurrency(parsedRegularSeatPrice * CUSTOMER_PORTAL_UPSELL_DISCOUNT_RATE);
};

const CUSTOMER_PORTAL_PRIVATE_UPGRADE_TARGET_PRICE = 1800;

const buildCustomerPortalPrivateUpgradeDescription = (amount) =>
    `Your flight is eligible for a private upgrade. Enjoy your own private balloon for an additional £${roundCurrency(amount).toFixed(2)}.`;

const resolveCustomerPortalPrivateEightPassengerPrice = (voucherTitle, location) => {
    const directPricing = getPrivateCharterPricingFromCache(voucherTitle, location);
    if (directPricing && directPricing['8']) {
        return roundCurrency(directPricing['8']);
    }

    const locationKey = normalizeLocationKey(location);
    const locationPricing = privateCharterPriceCache[locationKey] || privateCharterPriceCache[DEFAULT_LOCATION_KEY] || {};
    const normalizedTitle = normalizeVoucherTitle(voucherTitle);

    for (const [title, paxMap] of Object.entries(locationPricing)) {
        if (!paxMap || typeof paxMap !== 'object') continue;
        const priceForEight = toNumberOrNull(paxMap['8']);
        if (!priceForEight) continue;

        if (
            normalizedTitle &&
            (title === normalizedTitle || title.includes(normalizedTitle) || normalizedTitle.includes(title))
        ) {
            return roundCurrency(priceForEight);
        }
    }

    for (const paxMap of Object.values(locationPricing)) {
        if (!paxMap || typeof paxMap !== 'object') continue;
        const fallbackEightPrice = toNumberOrNull(paxMap['8']);
        if (fallbackEightPrice) {
            return roundCurrency(fallbackEightPrice);
        }
    }

    return null;
};

const getCustomerPortalCapacityForSlot = async () => {
    return BALLOON_210_CAPACITY;
};

const getCustomerPortalSlotMetrics = async ({ booking, bookingPassengerCount, location, flightDate }) => {
    const effectiveLocation = location || booking.location || null;
    const bookingDate = flightDate && dayjs(flightDate).isValid()
        ? dayjs(flightDate).format('YYYY-MM-DD')
        : null;
    const bookingTime = booking.time_slot
        ? dayjs(`2000-01-01 ${booking.time_slot}`).format('HH:mm:ss')
        : (flightDate && dayjs(flightDate).isValid() ? dayjs(flightDate).format('HH:mm:ss') : null);
    const capacity = await getCustomerPortalCapacityForSlot({
        activityId: booking.activity_id || null,
        location: effectiveLocation,
        bookingDate,
        bookingTime
    });

    if (!bookingDate || !bookingTime || String(booking.status || '').toLowerCase() === 'cancelled') {
        return {
            capacity,
            totalPassengers: bookingPassengerCount,
            remainingSeats: Math.max(0, capacity - bookingPassengerCount),
            totalBookings: 1,
            hasOtherBookings: false,
            isScheduled: false
        };
    }

    const slotRows = await runPoolQuery(
        `
            SELECT
                COALESCE(SUM(pax), 0) AS total_passengers,
                COUNT(*) AS total_bookings
            FROM all_booking
            WHERE DATE(flight_date) = DATE(?)
              AND location = ?
              AND COALESCE(NULLIF(time_slot, ''), TIME_FORMAT(flight_date, '%H:%i:%s')) = ?
              AND (status IS NULL OR TRIM(LOWER(status)) NOT IN ('cancelled'))
              AND (manual_status_override IS NULL OR TRIM(LOWER(manual_status_override)) NOT IN ('cancelled'))
              AND (? IS NULL OR activity_id = ?)
        `,
        [
            bookingDate,
            effectiveLocation,
            bookingTime,
            booking.activity_id || null,
            booking.activity_id || null
        ]
    );

    const totalPassengers = slotRows && slotRows.length > 0
        ? Number(slotRows[0].total_passengers) || bookingPassengerCount
        : bookingPassengerCount;
    const totalBookings = slotRows && slotRows.length > 0
        ? Number(slotRows[0].total_bookings) || 1
        : 1;

    return {
        capacity,
        totalPassengers,
        remainingSeats: Math.max(0, capacity - totalPassengers),
        totalBookings,
        hasOtherBookings: Math.max(0, totalBookings - 1) > 0,
        isScheduled: true
    };
};

const buildInviteFriendsData = async ({
    booking,
    passengers,
    location,
    flightDate,
    isFlightVoucher
}) => {
    if (!booking || isFlightVoucher || !isCustomerPortalSharedBooking(booking)) {
        return null;
    }

    const bookingStatus = String(booking.status || '').toLowerCase();
    if (bookingStatus === 'cancelled') {
        return null;
    }

    if (flightDate && dayjs(flightDate).isValid() && dayjs(flightDate).isBefore(dayjs(), 'day')) {
        return null;
    }

    const bookingPassengerCount = Array.isArray(passengers) && passengers.length > 0
        ? passengers.length
        : (parsePositiveInt(booking.pax) || 0);
    const effectiveLocation = location || booking.location || null;
    const slotMetrics = await getCustomerPortalSlotMetrics({
        booking,
        bookingPassengerCount,
        location: effectiveLocation,
        flightDate
    });
    const isScheduled = !!(flightDate && dayjs(flightDate).isValid());
    const remainingSeats = isScheduled ? Math.max(0, slotMetrics.remainingSeats) : null;
    const isEnabled = Boolean(isScheduled && remainingSeats > 0);
    const formattedExperienceDateTime = isScheduled
        ? formatInviteFriendsExperienceDate(flightDate, booking.time_slot || null)
        : null;
    const shareMessage = isEnabled
        ? buildInviteFriendsShareMessage({
            location: effectiveLocation,
            experienceDateTime: formattedExperienceDateTime,
            bookingUrl: BOOK_SITE_BASE_URL
        })
        : null;

    return {
        visible: !isScheduled || remainingSeats > 0,
        enabled: isEnabled,
        disabled: !isEnabled,
        availableSpaces: remainingSeats,
        capacity: slotMetrics.capacity,
        title: isScheduled
            ? `🎈 ${remainingSeats} Space${remainingSeats === 1 ? '' : 's'} Left on Your Flight`
            : 'Invite Friends',
        description: !isScheduled
            ? 'Invite Friends becomes available once your shared flight has been scheduled.'
            : (remainingSeats > 0
                ? 'Share an invite and give your friends 10% off their balloon flight.'
                : 'This shared flight is currently full, so Invite Friends is unavailable right now.'),
        buttonLabel: 'Invite Friends',
        discountCode: INVITE_FRIENDS_DISCOUNT_CODE,
        bookingUrl: BOOK_SITE_BASE_URL,
        location: effectiveLocation,
        experienceDateTime: formattedExperienceDateTime,
        shareMessage,
        shareLinks: buildInviteFriendsShareLinks(shareMessage)
    };
};

const buildCustomerPortalSeasonSaverUpgradeOffer = async (booking, effectiveLocation) => {
    const isSeasonSaver = booking.season_saver === 1 || booking.season_saver === '1' || booking.season_saver === true;
    if (!isSeasonSaver) return null;

    const bookingStatus = String(booking.status || '').toLowerCase();
    if (bookingStatus === 'cancelled') return null;

    const paidAmount = Number(booking.paid) || 0;
    const addOnsAmount = Number(booking.add_to_booking_items_total_price) || 0;
    const weatherRefundAmount = Number(booking.weather_refund_total_price) || 0;
    const basePaid = Math.max(0, paidAmount - addOnsAmount - weatherRefundAmount);
    const pax = parseInt(booking.pax) || 1;

    // Get current standard Flexible Weekday price from activity table
    let standardPrice = null;
    try {
        const activityRows = await new Promise((resolve, reject) => {
            const loc = effectiveLocation || booking.location || '';
            con.query(
                "SELECT flexible_weekday_price FROM activity WHERE location = ? AND status = 'Live' LIMIT 1",
                [loc],
                (err, rows) => err ? reject(err) : resolve(rows)
            );
        });
        if (activityRows && activityRows.length > 0 && activityRows[0].flexible_weekday_price) {
            standardPrice = parseFloat(activityRows[0].flexible_weekday_price);
        }
    } catch (e) {
        console.error('Error fetching standard price for season saver upgrade:', e);
    }

    if (!standardPrice || standardPrice <= 0) {
        standardPrice = 220; // fallback
    }

    const standardTotal = roundCurrency(standardPrice * pax);
    const upgradeCost = roundCurrency(Math.max(standardTotal - basePaid, 0));

    if (upgradeCost <= 0) return null;

    return {
        eligible: true,
        mode: 'season_saver_upgrade',
        title: '☘️ Upgrade to Standard',
        description: `Remove Season Saver restrictions and upgrade to a Standard Flexible Weekday voucher for £${upgradeCost.toFixed(2)}.`,
        buttonLabel: 'Upgrade',
        requiredPassengerCount: 0,
        totalCharge: upgradeCost,
        standardPrice,
        standardTotal,
        currentPaid: basePaid,
        pax,
        voucherType: 'Flexible Weekday'
    };
};

const buildCustomerPortalUpsellOffer = async ({
    booking,
    passengers,
    voucherType,
    location,
    flightDate,
    isFlightVoucher
}) => {
    // Check for Season Saver upgrade first
    const seasonSaverOffer = await buildCustomerPortalSeasonSaverUpgradeOffer(booking, location);
    if (seasonSaverOffer) return seasonSaverOffer;

    if (!booking || isFlightVoucher || !isCustomerPortalSharedBooking(booking)) {
        return null;
    }

    const bookingStatus = String(booking.status || '').toLowerCase();
    if (bookingStatus === 'cancelled') {
        return null;
    }

    if (flightDate && dayjs(flightDate).isValid() && dayjs(flightDate).isBefore(dayjs(), 'day')) {
        return null;
    }

    const bookingPassengerCount = Array.isArray(passengers) && passengers.length > 0
        ? passengers.length
        : (parsePositiveInt(booking.pax) || 0);

    if (!bookingPassengerCount || bookingPassengerCount >= BALLOON_210_CAPACITY) {
        return null;
    }

    const effectiveLocation = location || booking.location || null;
    const slotMetrics = await getCustomerPortalSlotMetrics({
        booking,
        bookingPassengerCount,
        location: effectiveLocation,
        flightDate
    });

    if (slotMetrics.remainingSeats <= 0) {
        return null;
    }

    const effectiveVoucherType = voucherType || booking.voucher_type_detail || booking.voucher_type || '';
    const regularSeatPrice = await resolveCustomerPortalSharedSeatPrice(effectiveVoucherType, effectiveLocation);
    const discountAmount = getCustomerPortalUpsellDiscount(effectiveVoucherType, regularSeatPrice);
    const discountedSeatPrice = regularSeatPrice != null && discountAmount != null
        ? roundCurrency(Math.max(regularSeatPrice - discountAmount, 0))
        : null;
    const currentBookingPaidTotal = roundCurrency(
        Math.max(
            0,
            (Number(booking.paid) || 0) -
            (Number(booking.add_to_booking_items_total_price) || 0) -
            (Number(booking.weather_refund_total_price) || 0)
        )
    );
    const currentBookingBaseTotal = roundCurrency(
        Math.max(
            0,
            (Number(booking.paid) || 0) +
            (Number(booking.due) || 0) -
            (Number(booking.add_to_booking_items_total_price) || 0) -
            (Number(booking.weather_refund_total_price) || 0)
        )
    );

    const shouldShowPrivateUpgrade = slotMetrics.isScheduled &&
        [6, 7].includes(bookingPassengerCount) &&
        !slotMetrics.hasOtherBookings;

    if (shouldShowPrivateUpgrade) {
        // Private upgrade must always target the fixed 8-passenger private charter price.
        // Do not derive this from shared seat pricing, otherwise amounts drift (e.g. £1600 instead of £1800).
        const resolvedPrivateEightPrice = resolveCustomerPortalPrivateEightPassengerPrice('Private Charter', effectiveLocation);
        const privateEightPrice = roundCurrency(
            Number.isFinite(Number(resolvedPrivateEightPrice))
                ? Number(resolvedPrivateEightPrice)
                : CUSTOMER_PORTAL_PRIVATE_UPGRADE_TARGET_PRICE
        );
        const privateUpgradeDifference = privateEightPrice != null
            ? roundCurrency(Math.max(privateEightPrice - currentBookingPaidTotal, 0))
            : null;

        if (privateEightPrice != null && privateUpgradeDifference && privateUpgradeDifference > 0) {
            return {
                eligible: true,
                mode: 'private_upgrade',
                title: '🎈Make it Private',
                description: buildCustomerPortalPrivateUpgradeDescription(privateUpgradeDifference),
                buttonLabel: 'Upgrade',
                requiredPassengerCount: slotMetrics.remainingSeats,
                totalCharge: privateUpgradeDifference,
                currentBookingBaseTotal: currentBookingPaidTotal,
                privateEightPrice,
                remainingSeats: slotMetrics.remainingSeats,
                slotPassengerCount: slotMetrics.totalPassengers,
                bookingPassengerCount,
                capacity: slotMetrics.capacity,
                hasOtherBookings: slotMetrics.hasOtherBookings,
                scheduled: slotMetrics.isScheduled,
                voucherType: effectiveVoucherType
            };
        }
    }

    const oddPassengerScenarios = [1, 3, 5, 7];
    const shouldShowSingleDiscount = oddPassengerScenarios.includes(bookingPassengerCount) && (
        !slotMetrics.isScheduled ||
        bookingPassengerCount === 7 ||
        slotMetrics.totalPassengers % 2 === 1
    );

    if (!shouldShowSingleDiscount || regularSeatPrice == null || discountAmount == null || discountedSeatPrice == null || discountedSeatPrice <= 0) {
        return null;
    }

    return {
        eligible: true,
        mode: 'single_discount',
        title: '🎈Bring a Friend & Save',
        description: CUSTOMER_PORTAL_SINGLE_DISCOUNT_DESCRIPTION,
        buttonLabel: 'Add Passenger',
        requiredPassengerCount: 1,
        totalCharge: discountedSeatPrice,
        discountAmount,
        regularSeatPrice,
        discountedSeatPrice,
        remainingSeats: slotMetrics.remainingSeats,
        slotPassengerCount: slotMetrics.totalPassengers,
        bookingPassengerCount,
        capacity: slotMetrics.capacity,
        hasOtherBookings: slotMetrics.hasOtherBookings,
        scheduled: slotMetrics.isScheduled,
        voucherType: effectiveVoucherType
    };
};

const normalizeCustomerPortalVoucherUpgradeType = (value) => {
    const normalized = normalizeVoucherTitle(value);
    if (!normalized) return null;

    if (normalized.includes('weekday morning')) {
        return 'weekday_morning';
    }
    if (normalized.includes('flexible weekday')) {
        return 'flexible_weekday';
    }
    if (
        normalized.includes('any day') ||
        normalized.includes('anyday') ||
        normalized.includes('anytime')
    ) {
        return 'any_day_flight';
    }

    return null;
};

const getCustomerPortalVoucherUpgradeLabel = (typeKey) =>
    CUSTOMER_PORTAL_VOUCHER_UPGRADE_LABELS[typeKey] || '';

const parseVoucherPassengerDetailsCount = (rawValue) => {
    if (!rawValue) return null;

    let parsed = rawValue;
    for (let attempt = 0; attempt < 3; attempt += 1) {
        if (typeof parsed !== 'string') break;
        try {
            parsed = JSON.parse(parsed);
        } catch (_) {
            break;
        }
    }

    if (Array.isArray(parsed)) {
        return parsed.length || null;
    }

    if (parsed && typeof parsed === 'object') {
        if (Array.isArray(parsed.passengers)) {
            return parsed.passengers.length || null;
        }
        if (Array.isArray(parsed.passengerData)) {
            return parsed.passengerData.length || null;
        }
        const numericCount = parsePositiveInt(parsed.numberOfPassengers || parsed.passenger_count || parsed.pax);
        if (numericCount) {
            return numericCount;
        }
    }

    return null;
};

const resolveCustomerPortalVoucherPassengerCount = ({ booking, voucher, portalBooking }) => {
    const candidates = [
        booking?.pax,
        portalBooking?.pax,
        voucher?.numberOfPassengers,
        voucher?.number_of_passengers,
        voucher?.pax,
        parseVoucherPassengerDetailsCount(voucher?.voucher_passenger_details),
        parseVoucherPassengerDetailsCount(portalBooking?.voucher_passenger_details)
    ];

    for (const candidate of candidates) {
        const parsed = parsePositiveInt(candidate);
        if (parsed) {
            return parsed;
        }
    }

    return 1;
};

const decodeCustomerPortalTokenParts = (token) => {
    if (!token || typeof token !== 'string') {
        return [];
    }

    let decodedToken = token;
    try {
        decodedToken = decodeURIComponent(decodedToken);
    } catch (_) {}

    try {
        const base64Token = decodedToken.replace(/-/g, '+').replace(/_/g, '/');
        return Buffer.from(base64Token, 'base64').toString('utf8').split('|');
    } catch (_) {
        return [];
    }
};

const resolveCustomerPortalVoucherUpgradeContext = async (token, req = null) => {
    if (!token || typeof token !== 'string') {
        throw new Error('A valid customer portal token is required.');
    }

    const internalBaseUrl = process.env.INTERNAL_API_BASE_URL || `http://127.0.0.1:${process.env.PORT || 3002}`;
    const portalResponse = await axios.get(`${internalBaseUrl}/api/customer-portal-booking/${encodeURIComponent(token)}`);
    const portalBooking = portalResponse?.data?.data || null;

    if (!portalResponse?.data?.success || !portalBooking) {
        throw new Error('Booking not found for this customer portal session.');
    }

    const tokenParts = decodeCustomerPortalTokenParts(token);
    const tokenFirstPart = String(tokenParts[0] || '').trim();
    const syntheticVoucherId = tokenFirstPart.startsWith('voucher-')
        ? parsePositiveInt(tokenFirstPart.replace('voucher-', ''))
        : null;
    const tokenVoucherRef = String(tokenParts[1] || '').trim() || null;
    const voucherRefCandidates = [
        portalBooking.voucher_ref,
        portalBooking.voucher_code,
        tokenVoucherRef
    ].map((value) => String(value || '').trim()).filter(Boolean);
    const voucherRef = voucherRefCandidates[0] || null;

    let voucher = null;
    if (voucherRef) {
        const voucherRows = await runPoolQuery(
            'SELECT * FROM all_vouchers WHERE UPPER(voucher_ref) = UPPER(?) LIMIT 1',
            [voucherRef]
        );
        voucher = voucherRows?.[0] || null;
    }
    if (!voucher && syntheticVoucherId) {
        const voucherRows = await runPoolQuery('SELECT * FROM all_vouchers WHERE id = ? LIMIT 1', [syntheticVoucherId]);
        voucher = voucherRows?.[0] || null;
    }

    let booking = null;
    const effectiveVoucherRef = voucher?.voucher_ref || voucherRef;
    if (effectiveVoucherRef) {
        const bookingRows = await runPoolQuery(
            'SELECT * FROM all_booking WHERE UPPER(voucher_code) = UPPER(?) ORDER BY created_at DESC LIMIT 1',
            [effectiveVoucherRef]
        );
        booking = bookingRows?.[0] || null;
    }
    if (!booking && portalBooking.id && !portalBooking.is_flight_voucher) {
        const bookingRows = await runPoolQuery('SELECT * FROM all_booking WHERE id = ? LIMIT 1', [portalBooking.id]);
        booking = bookingRows?.[0] || null;
    }

    const currentTypeCandidates = [
        booking?.voucher_type_detail,
        booking?.voucher_type,
        voucher?.voucher_type_detail,
        voucher?.voucher_type,
        portalBooking?.voucher_type_detail,
        portalBooking?.voucher_type
    ];
    let currentType = null;
    let currentTypeRaw = '';
    for (const candidate of currentTypeCandidates) {
        const normalizedType = normalizeCustomerPortalVoucherUpgradeType(candidate);
        if (normalizedType) {
            currentType = normalizedType;
            currentTypeRaw = String(candidate || '').trim();
            break;
        }
    }

    const passengerCount = resolveCustomerPortalVoucherPassengerCount({ booking, voucher, portalBooking });
    const location = (
        portalBooking.location ||
        booking?.location ||
        voucher?.preferred_location ||
        voucher?.location ||
        null
    );

    return {
        portalBooking,
        booking,
        voucher,
        voucherRef: effectiveVoucherRef || voucherRef,
        currentType,
        currentTypeLabel: getCustomerPortalVoucherUpgradeLabel(currentType) || currentTypeRaw,
        passengerCount,
        location
    };
};

const buildCustomerPortalVoucherUpgradeOptions = async (context) => {
    if (!context?.currentType) {
        return [];
    }

    const targetTypes = CUSTOMER_PORTAL_VOUCHER_UPGRADE_RULES[context.currentType] || [];
    if (targetTypes.length === 0) {
        return [];
    }

    const currentLabel = getCustomerPortalVoucherUpgradeLabel(context.currentType);
    const currentUnitPrice = await resolveCustomerPortalSharedSeatPrice(currentLabel, context.location);
    if (!currentUnitPrice || currentUnitPrice <= 0) {
        return [];
    }

    const passengerCount = Math.max(1, parsePositiveInt(context.passengerCount) || 1);
    const options = [];

    for (const targetType of targetTypes) {
        const targetLabel = getCustomerPortalVoucherUpgradeLabel(targetType);
        const targetUnitPrice = await resolveCustomerPortalSharedSeatPrice(targetLabel, context.location);
        if (!targetUnitPrice || targetUnitPrice <= currentUnitPrice) {
            continue;
        }

        const totalCharge = roundCurrency((targetUnitPrice - currentUnitPrice) * passengerCount);
        if (totalCharge <= 0) {
            continue;
        }

        options.push({
            targetType,
            targetLabel,
            currentType: context.currentType,
            currentLabel,
            currentUnitPrice: roundCurrency(currentUnitPrice),
            targetUnitPrice: roundCurrency(targetUnitPrice),
            passengerCount,
            totalCharge,
            amountPence: Math.round(totalCharge * 100)
        });
    }

    return options;
};

const updateVoucherUpgradeRecord = async ({
    tableName,
    whereSql,
    whereParams,
    targetLabel,
    amount,
    includeOriginalAmount = false,
    includePaidAmount = false
}) => {
    const columns = await getExistingTableColumns(tableName);
    if (columns.size === 0) return;

    const setClauses = [];
    const params = [];

    if (columns.has('voucher_type')) {
        setClauses.push('voucher_type = ?');
        params.push(targetLabel);
    }
    if (columns.has('voucher_type_detail')) {
        setClauses.push('voucher_type_detail = ?');
        params.push(targetLabel);
    }
    if (includeOriginalAmount && columns.has('original_amount')) {
        const bookingTotalExpression = columns.has('due')
            ? 'COALESCE(paid, 0) + COALESCE(due, 0)'
            : 'COALESCE(paid, 0)';
        setClauses.push(`original_amount = ROUND(GREATEST(COALESCE(original_amount, 0), ${bookingTotalExpression}) + ?, 2)`);
        params.push(amount);
    }
    if (tableName === 'all_vouchers') {
        ['total', 'subtotal', 'original_amount'].forEach((columnName) => {
            if (columns.has(columnName)) {
                setClauses.push(`${columnName} = ROUND(GREATEST(COALESCE(${columnName}, 0), COALESCE(paid, 0)) + ?, 2)`);
                params.push(amount);
            }
        });
    }
    if (columns.has('paid')) {
        setClauses.push('paid = ROUND(COALESCE(paid, 0) + ?, 2)');
        params.push(amount);
    }
    if (includePaidAmount && columns.has('paid_amount')) {
        setClauses.push('paid_amount = ROUND(COALESCE(paid_amount, 0) + ?, 2)');
        params.push(amount);
    }

    if (setClauses.length === 0) return;

    await runPoolQuery(
        `UPDATE ${tableName} SET ${setClauses.join(', ')} WHERE ${whereSql}`,
        [...params, ...whereParams]
    );
};

const updateVoucherUpgradePassengerTickets = async ({ bookingId, fromLabel, targetLabel }) => {
    if (!bookingId) return;

    const passengerColumns = await getExistingTableColumns('passenger');
    if (!passengerColumns.has('ticket_type')) return;

    const aliases = [
        fromLabel,
        `${fromLabel} Flight`,
        `${fromLabel} Voucher`,
        normalizeVoucherTitle(fromLabel)
    ].map((value) => String(value || '').trim().toLowerCase()).filter(Boolean);

    if (aliases.length === 0) return;

    const placeholders = aliases.map(() => '?').join(', ');
    await runPoolQuery(
        `
            UPDATE passenger
            SET ticket_type = ?
            WHERE booking_id = ?
              AND (
                ticket_type IS NULL
                OR TRIM(ticket_type) = ''
                OR LOWER(TRIM(ticket_type)) IN (${placeholders})
              )
        `,
        [targetLabel, bookingId, ...aliases]
    );
};

const applyCustomerPortalVoucherUpgrade = async (session, storeData) => {
    const upgradeData = storeData?.voucherUpgradeData;
    if (!upgradeData?.token || !upgradeData?.toType) {
        throw new Error('Customer portal voucher upgrade data is incomplete');
    }

    if (upgradeData.applied) {
        return {
            success: true,
            bookingId: upgradeData.bookingId || null,
            voucherId: upgradeData.voucherId || null,
            mode: 'voucher_upgrade'
        };
    }

    const context = await resolveCustomerPortalVoucherUpgradeContext(upgradeData.token);
    const options = await buildCustomerPortalVoucherUpgradeOptions(context);
    const targetType = normalizeCustomerPortalVoucherUpgradeType(upgradeData.toType) || upgradeData.toType;
    const selectedOption = options.find((option) => option.targetType === targetType);

    if (!selectedOption) {
        throw new Error('This voucher upgrade is no longer available.');
    }

    const authoritativeAmounts = getAuthoritativeStripeAmounts(session, selectedOption.totalCharge);
    const paidAmount = roundCurrency(authoritativeAmounts.paidAmount || selectedOption.totalCharge || 0);

    if (paidAmount <= 0) {
        throw new Error('Invalid voucher upgrade payment amount');
    }

    const bookingId = context.booking?.id || upgradeData.bookingId || null;
    const voucherId = context.voucher?.id || upgradeData.voucherId || null;
    const voucherRef = context.voucherRef || upgradeData.voucherRef || null;
    const fromLabel = context.currentTypeLabel || upgradeData.fromLabel || selectedOption.currentLabel;
    const targetLabel = selectedOption.targetLabel || upgradeData.toLabel;

    if (bookingId) {
        await updateVoucherUpgradeRecord({
            tableName: 'all_booking',
            whereSql: 'id = ?',
            whereParams: [bookingId],
            targetLabel,
            amount: paidAmount,
            includeOriginalAmount: true
        });
        await updateVoucherUpgradePassengerTickets({ bookingId, fromLabel, targetLabel });
    }

    if (voucherId) {
        await updateVoucherUpgradeRecord({
            tableName: 'all_vouchers',
            whereSql: 'id = ?',
            whereParams: [voucherId],
            targetLabel,
            amount: paidAmount
        });
    } else if (voucherRef) {
        await updateVoucherUpgradeRecord({
            tableName: 'all_vouchers',
            whereSql: 'UPPER(voucher_ref) = UPPER(?)',
            whereParams: [voucherRef],
            targetLabel,
            amount: paidAmount
        });
    }

    if (voucherRef) {
        await updateVoucherUpgradeRecord({
            tableName: 'voucher_codes',
            whereSql: 'UPPER(code) = UPPER(?)',
            whereParams: [voucherRef],
            targetLabel,
            amount: paidAmount,
            includePaidAmount: true
        });
    }

    await savePaymentHistory(session, bookingId || null, voucherId || null, voucherRef || null);
    await runPoolQuery(
        'UPDATE payment_history SET refund_comment = ? WHERE stripe_session_id = ?',
        [`Voucher Upgrade: ${fromLabel} to ${targetLabel}`, session.id]
    ).catch((error) => {
        if (error?.code !== 'ER_BAD_FIELD_ERROR') {
            console.warn('Could not annotate voucher upgrade payment history:', error?.message || error);
        }
    });

    storeData.processed = true;
    storeData.voucherUpgradeData = {
        ...upgradeData,
        applied: true,
        bookingId,
        booking_id: bookingId,
        voucherId,
        voucher_id: voucherId,
        voucherRef,
        voucher_ref: voucherRef,
        fromLabel,
        toLabel: targetLabel,
        totalAmount: paidAmount
    };

    return {
        success: true,
        bookingId,
        voucherId,
        voucherRef,
        fromLabel,
        toLabel: targetLabel,
        paidAmount,
        mode: 'voucher_upgrade'
    };
};

const distributeAmountAcrossPassengers = (totalAmount, passengerCount) => {
    const safePassengerCount = Math.max(1, passengerCount || 1);
    const totalPennies = Math.round((Number(totalAmount) || 0) * 100);
    const basePennies = Math.floor(totalPennies / safePassengerCount);
    const remainder = totalPennies - (basePennies * safePassengerCount);

    return Array.from({ length: safePassengerCount }, (_, index) => {
        const amountInPennies = basePennies + (index < remainder ? 1 : 0);
        return roundCurrency(amountInPennies / 100);
    });
};

const applyCustomerPortalUpsell = async (session, storeData) => {
    const upsellData = storeData?.customerPortalUpsellData;

    const isSeasonSaverUpgradeApply = upsellData?.offerSnapshot?.mode === 'season_saver_upgrade';
    if (!upsellData?.bookingId || (!isSeasonSaverUpgradeApply && (!Array.isArray(upsellData.passengers) || upsellData.passengers.length === 0))) {
        throw new Error('Customer portal upsell data is incomplete');
    }

    const bookingRows = await runPoolQuery('SELECT * FROM all_booking WHERE id = ? LIMIT 1', [upsellData.bookingId]);
    if (!bookingRows || bookingRows.length === 0) {
        throw new Error('Booking not found for customer portal upsell');
    }

    const booking = bookingRows[0];
    const existingPassengers = await runPoolQuery('SELECT * FROM passenger WHERE booking_id = ? ORDER BY id ASC', [upsellData.bookingId]);
    const currentPassengerCount = existingPassengers.length > 0
        ? existingPassengers.length
        : (parsePositiveInt(booking.pax) || 0);

    const slotMetrics = await getCustomerPortalSlotMetrics({
        booking,
        bookingPassengerCount: currentPassengerCount,
        location: booking.location,
        flightDate: booking.flight_date
    });

    if (slotMetrics.isScheduled && slotMetrics.remainingSeats < upsellData.passengers.length) {
        throw new Error('This flight no longer has enough remaining seats for the requested passengers');
    }

    const authoritativeAmounts = getAuthoritativeStripeAmounts(
        session,
        upsellData.totalAmount || upsellData.offerSnapshot?.totalCharge || 0
    );
    const paidAmount = roundCurrency(
        authoritativeAmounts.paidAmount || upsellData.totalAmount || upsellData.offerSnapshot?.totalCharge || 0
    );

    if (paidAmount <= 0) {
        throw new Error('Invalid upsell payment amount');
    }

    const distributedPrices = distributeAmountAcrossPassengers(paidAmount, upsellData.passengers.length);
    // Handle Season Saver upgrade: remove restriction, update voucher type, update paid
    const isSeasonSaverUpgrade = upsellData.offerSnapshot?.mode === 'season_saver_upgrade';
    if (isSeasonSaverUpgrade) {
        const nextPaid = roundCurrency((Number(booking.paid) || 0) + paidAmount);
        await runPoolQuery(
            `UPDATE all_booking SET season_saver = 0, voucher_type = 'Flexible Weekday', paid = ?, original_amount = ? WHERE id = ?`,
            [nextPaid, roundCurrency(Number(booking.original_amount || 0) + paidAmount), upsellData.bookingId]
        );
        // Also update corresponding voucher if exists
        if (booking.voucher_code) {
            await runPoolQuery(
                `UPDATE all_vouchers SET season_saver = 0 WHERE voucher_ref = ?`,
                [booking.voucher_code]
            ).catch(() => {});
        }
        await savePaymentHistory(session, upsellData.bookingId, null, booking.voucher_code || null);
        storeData.processed = true;
        storeData.customerPortalUpsellData = { ...upsellData, applied: true, booking_id: upsellData.bookingId };
        return { success: true, bookingId: upsellData.bookingId, mode: 'season_saver_upgrade' };
    }

    const isPrivateUpgrade = upsellData.offerSnapshot?.mode === 'private_upgrade';
    const targetBookingTotal = isPrivateUpgrade && Number.isFinite(Number(upsellData.offerSnapshot?.privateEightPrice))
        ? roundCurrency(Number(upsellData.offerSnapshot.privateEightPrice))
        : null;
    const ticketType = upsellData.offerSnapshot?.mode === 'private_upgrade'
        ? 'Private Upgrade'
        : (upsellData.voucherType || booking.voucher_type_detail || booking.voucher_type || 'Customer Portal Upsell');

    const insertPassengerValues = upsellData.passengers.map((passenger, index) => [
        upsellData.bookingId,
        passenger.first_name,
        passenger.last_name,
        passenger.weight ? Number(passenger.weight) : null,
        null,
        null,
        ticketType,
        0,
        distributedPrices[index]
    ]);

    await runPoolQuery(
        `
            INSERT INTO passenger (
                booking_id, first_name, last_name, weight, email, phone, ticket_type, weather_refund, price
            ) VALUES ?
        `,
        [insertPassengerValues]
    );

    const currentBaseTotal = roundCurrency(
        isPrivateUpgrade
            ? Math.max(
                0,
                (Number(booking.paid) || 0) -
                (Number(booking.add_to_booking_items_total_price) || 0) -
                (Number(booking.weather_refund_total_price) || 0)
            )
            : (
                Number(booking.original_amount) || Math.max(
                    0,
                    (Number(booking.paid) || 0) +
                    (Number(booking.due) || 0) -
                    (Number(booking.add_to_booking_items_total_price) || 0) -
                    (Number(booking.weather_refund_total_price) || 0)
                )
            )
    );
    const nextPassengerCount = currentPassengerCount + upsellData.passengers.length;
    const nextPaidTotal = roundCurrency((Number(booking.paid) || 0) + paidAmount);
    const nextDueTotal = roundCurrency(
        targetBookingTotal != null
            ? Math.max(0, targetBookingTotal - nextPaidTotal)
            : (Number(booking.due) || 0)
    );
    const nextOriginalAmount = roundCurrency(
        targetBookingTotal != null
            ? targetBookingTotal
            : (currentBaseTotal + paidAmount)
    );

    await runPoolQuery(
        `
            UPDATE all_booking
            SET pax = ?,
                paid = ?,
                due = ?,
                original_amount = ?
            WHERE id = ?
        `,
        [nextPassengerCount, nextPaidTotal, nextDueTotal, nextOriginalAmount, upsellData.bookingId]
    );

    const bookingDate = booking.flight_date && dayjs(booking.flight_date).isValid()
        ? dayjs(booking.flight_date).format('YYYY-MM-DD')
        : null;
    const bookingTime = booking.time_slot
        ? dayjs(`2000-01-01 ${booking.time_slot}`).format('HH:mm')
        : (booking.flight_date && dayjs(booking.flight_date).isValid() ? dayjs(booking.flight_date).format('HH:mm') : null);

    if (bookingDate && bookingTime && booking.activity_id) {
        updateSpecificAvailability(bookingDate, bookingTime, booking.activity_id, upsellData.passengers.length);
    } else if (bookingDate && bookingTime && booking.location) {
        try {
            const activityRows = await runPoolQuery(
                'SELECT id FROM activity WHERE location = ? AND status = "Live" ORDER BY id DESC LIMIT 1',
                [booking.location]
            );
            if (activityRows && activityRows.length > 0) {
                updateSpecificAvailability(bookingDate, bookingTime, activityRows[0].id, upsellData.passengers.length);
            }
        } catch (error) {
            console.warn('Customer Portal - Could not update availability after upsell:', error.message);
        }
    }

    await savePaymentHistory(session, upsellData.bookingId, null, booking.voucher_code || null);

    storeData.processed = true;
    storeData.customerPortalUpsellData = {
        ...upsellData,
        applied: true,
        booking_id: upsellData.bookingId
    };

    return {
        bookingId: upsellData.bookingId,
        addedPassengerCount: upsellData.passengers.length,
        paidAmount
    };
};

const getBookingInviteFriendsSnapshot = async (bookingId) => {
    if (!bookingId) {
        return null;
    }

    const bookingRows = await runPoolQuery('SELECT * FROM all_booking WHERE id = ? LIMIT 1', [bookingId]);
    if (!bookingRows || bookingRows.length === 0) {
        return null;
    }

    const booking = bookingRows[0];
    const passengers = await runPoolQuery(
        'SELECT id, booking_id, first_name, last_name, email, phone FROM passenger WHERE booking_id = ? ORDER BY id ASC',
        [bookingId]
    );
    const inviteFriends = await buildInviteFriendsData({
        booking,
        passengers,
        location: booking.location,
        flightDate: booking.flight_date,
        isFlightVoucher: booking.book_flight === 'Flight Voucher' || booking.is_flight_voucher
    });

    return {
        booking,
        passengers,
        inviteFriends
    };
};

