// Passenger tablosunda herhangi bir yolcunun weight bilgisini güncellemek için
app.patch('/api/updatePassengerField', (req, res) => {
    const { passenger_id, field, value } = req.body;
    const allowedFields = ['weight', 'first_name', 'last_name', 'price']; // Add 'price'
    if (!passenger_id || !field || !allowedFields.includes(field)) {
        return res.status(400).json({ success: false, message: 'Invalid request' });
    }

    // First, get the passenger's booking_id and current name values
    const getPassengerSql = `SELECT booking_id, first_name, last_name FROM passenger WHERE id = ?`;
    con.query(getPassengerSql, [passenger_id], (err, passengerRows) => {
        if (err) {
            console.error('Error fetching passenger:', err);
            return res.status(500).json({ success: false, message: 'Database error' });
        }

        if (!passengerRows || passengerRows.length === 0) {
            return res.status(404).json({ success: false, message: 'Passenger not found' });
        }

        const passenger = passengerRows[0];
        const booking_id = passenger.booking_id;

        // Determine the new first_name and last_name values after update
        let newFirstName = passenger.first_name;
        let newLastName = passenger.last_name;
        if (field === 'first_name') {
            newFirstName = value;
        } else if (field === 'last_name') {
            newLastName = value;
        }

        // Update the passenger field
        const updateSql = `UPDATE passenger SET ${field} = ? WHERE id = ?`;
        con.query(updateSql, [value, passenger_id], (err, result) => {
            if (err) {
                console.error('Error updating passenger field:', err);
                return res.status(500).json({ success: false, message: 'Database error' });
            }

            // If first_name or last_name was updated, check if this is the first passenger
            // and update the booking name accordingly
            if (field === 'first_name' || field === 'last_name') {
                // Get all passengers for this booking ordered by id to find the first one
                const getFirstPassengerSql = `SELECT id FROM passenger WHERE booking_id = ? ORDER BY id ASC LIMIT 1`;
                con.query(getFirstPassengerSql, [booking_id], (err, firstPassengerRows) => {
                    if (err) {
                        console.error('Error fetching first passenger:', err);
                        // Don't fail the request, just log the error
                        return res.json({ success: true });
                    }

                    if (firstPassengerRows && firstPassengerRows.length > 0) {
                        const firstPassengerId = firstPassengerRows[0].id;
                        // If this is the first passenger, update booking name
                        if (firstPassengerId == passenger_id) {
                            // Use the calculated new name values
                            const newName = `${newFirstName || ''} ${newLastName || ''}`.trim();

                            // Update booking name
                            const updateBookingNameSql = `UPDATE all_booking SET name = ? WHERE id = ?`;
                            con.query(updateBookingNameSql, [newName, booking_id], (err, bookingResult) => {
                                if (err) {
                                    console.error('Error updating booking name:', err);
                                    // Don't fail the request, just log the error
                                }
                                res.json({ success: true });
                            });
                        } else {
                            res.json({ success: true });
                        }
                    } else {
                        res.json({ success: true });
                    }
                });
            } else {
                res.json({ success: true });
            }
        });
    });
});

// Update voucher passenger field
app.patch('/api/updateVoucherPassengerField', (req, res) => {
    console.log('=== updateVoucherPassengerField ENDPOINT CALLED ===');
    console.log('Request body:', req.body);
    const { voucher_id, passenger_index, field, value } = req.body;
    const allowedFields = ['weight', 'first_name', 'last_name', 'price'];
    if (!voucher_id || passenger_index === undefined || !field || !allowedFields.includes(field)) {
        console.log('Validation failed:', { voucher_id, passenger_index, field, value });
        return res.status(400).json({ success: false, message: 'Invalid request' });
    }

    // First, get the current voucher_passenger_details
    const getSql = `SELECT voucher_passenger_details FROM all_vouchers WHERE id = ?`;
    con.query(getSql, [voucher_id], (err, rows) => {
        if (err) {
            console.error('Error fetching voucher passenger details:', err);
            return res.status(500).json({ success: false, message: 'Database error' });
        }

        if (rows.length === 0) {
            return res.status(404).json({ success: false, message: 'Voucher not found' });
        }

        // Parse existing passenger details
        let passengerDetails = [];
        try {
            const rawDetails = rows[0].voucher_passenger_details;
            if (rawDetails) {
                passengerDetails = typeof rawDetails === 'string'
                    ? JSON.parse(rawDetails)
                    : rawDetails;
            }
        } catch (e) {
            console.warn('Failed to parse voucher_passenger_details:', e);
            passengerDetails = [];
        }

        // Ensure passengerDetails is an array
        if (!Array.isArray(passengerDetails)) {
            passengerDetails = [];
        }

        // Ensure the passenger index exists
        if (passenger_index >= passengerDetails.length || passenger_index < 0) {
            return res.status(400).json({ success: false, message: 'Invalid passenger index' });
        }

        // Ensure the passenger object exists
        if (!passengerDetails[passenger_index]) {
            passengerDetails[passenger_index] = {};
        }

        // Update the specific field for the passenger at the given index
        passengerDetails[passenger_index][field] = value;

        // Update the voucher_passenger_details column
        const updateSql = `UPDATE all_vouchers SET voucher_passenger_details = ? WHERE id = ?`;
        con.query(updateSql, [JSON.stringify(passengerDetails), voucher_id], (updateErr, updateResult) => {
            if (updateErr) {
                console.error('Error updating voucher passenger details:', updateErr);
                return res.status(500).json({ success: false, message: 'Database error' });
            }

            // If price was updated, also update the voucher's paid amount
            if (field === 'price') {
                const totalPrice = passengerDetails.reduce((sum, p) => {
                    const price = parseFloat(p.price) || 0;
                    return sum + price;
                }, 0);

                const updatePaidSql = `UPDATE all_vouchers SET paid = ? WHERE id = ?`;
                con.query(updatePaidSql, [totalPrice, voucher_id], (paidErr) => {
                    if (paidErr) {
                        console.warn('Warning: Could not update voucher paid amount:', paidErr);
                    }
                });
            }

            res.json({ success: true, passengerDetails });
        });
    });
});

// Add voucher passenger
app.post('/api/addVoucherPassenger', (req, res) => {
    console.log('=== addVoucherPassenger ENDPOINT CALLED ===');
    console.log('Request body:', req.body);
    const { voucher_id, first_name, last_name, weight, price } = req.body;

    if (!voucher_id || !first_name || !last_name) {
        return res.status(400).json({ success: false, message: 'Missing required fields' });
    }

    // First, get the current voucher_passenger_details
    const getSql = `SELECT voucher_passenger_details, paid FROM all_vouchers WHERE id = ?`;
    con.query(getSql, [voucher_id], (err, rows) => {
        if (err) {
            console.error('Error fetching voucher passenger details:', err);
            return res.status(500).json({ success: false, message: 'Database error' });
        }

        if (rows.length === 0) {
            return res.status(404).json({ success: false, message: 'Voucher not found' });
        }

        // Parse existing passenger details
        let passengerDetails = [];
        try {
            const rawDetails = rows[0].voucher_passenger_details;
            if (rawDetails) {
                passengerDetails = typeof rawDetails === 'string'
                    ? JSON.parse(rawDetails)
                    : rawDetails;
            }
        } catch (e) {
            console.warn('Failed to parse voucher_passenger_details:', e);
            passengerDetails = [];
        }

        // Ensure passengerDetails is an array
        if (!Array.isArray(passengerDetails)) {
            passengerDetails = [];
        }

        // Calculate price per passenger if not provided
        let passengerPrice = price;
        if (!passengerPrice || passengerPrice === '') {
            const currentPaid = parseFloat(rows[0].paid) || 0;
            const currentPassengerCount = passengerDetails.length;
            // If there are existing passengers, divide paid amount equally
            // Otherwise, set to 0 (will be updated later)
            passengerPrice = currentPassengerCount > 0 ? (currentPaid / (currentPassengerCount + 1)).toFixed(2) : 0;
        }

        // Add new passenger
        const newPassenger = {
            first_name: first_name,
            last_name: last_name,
            weight: weight || null,
            price: passengerPrice || null
        };

        passengerDetails.push(newPassenger);

        // Calculate new total paid amount
        const totalPrice = passengerDetails.reduce((sum, p) => {
            const pPrice = parseFloat(p.price) || 0;
            return sum + pPrice;
        }, 0);

        // Update the voucher_passenger_details column
        const updateSql = `UPDATE all_vouchers SET voucher_passenger_details = ?, paid = ? WHERE id = ?`;
        con.query(updateSql, [JSON.stringify(passengerDetails), totalPrice, voucher_id], (updateErr, updateResult) => {
            if (updateErr) {
                console.error('Error updating voucher passenger details:', updateErr);
                return res.status(500).json({ success: false, message: 'Database error' });
            }

            res.json({ success: true, passengerDetails, newPassenger });
        });
    });
});

// Analytics endpoint
app.get('/api/analytics', async (req, res) => {
    const { start_date, end_date } = req.query;
    const normalizeAnalyticsDateParam = (value) => {
        const dateValue = String(value || '').trim();
        return /^\d{4}-\d{2}-\d{2}$/.test(dateValue) ? dateValue : null;
    };
    const analyticsStartDate = normalizeAnalyticsDateParam(start_date);
    const analyticsEndDate = normalizeAnalyticsDateParam(end_date);
    // Helper for date filter
    const dateFilter = (field = 'flight_date') => {
        let sql = '';
        if (analyticsStartDate) sql += ` AND DATE(${field}) >= ${con.escape(analyticsStartDate)}`;
        if (analyticsEndDate) sql += ` AND DATE(${field}) <= ${con.escape(analyticsEndDate)}`;
        return sql;
    };
    const queryAsync = (sql, params = []) =>
        con.promise().query(sql, params).then(([rows]) => rows);
    const tableHasColumn = async (tableName, columnName) => {
        try {
            const rows = await queryAsync(`
                SELECT 1
                FROM INFORMATION_SCHEMA.COLUMNS
                WHERE TABLE_SCHEMA = DATABASE()
                  AND TABLE_NAME = ?
                  AND COLUMN_NAME = ?
                LIMIT 1
            `, [tableName, columnName]);
            return rows.length > 0;
        } catch (error) {
            console.warn(`Unable to inspect schema for ${tableName}.${columnName}:`, error?.message || error);
            return false;
        }
    };
    const parseAnalyticsDate = (value) => {
        if (!value) return null;

        const strictFormats = [
            'YYYY-MM-DD HH:mm:ss',
            'YYYY-MM-DD HH:mm',
            'YYYY-MM-DD',
            'YYYY-MM-DDTHH:mm:ss.SSSZ',
            'YYYY-MM-DDTHH:mm:ssZ',
            'YYYY-MM-DDTHH:mm:ss.SSS[Z]',
            'YYYY-MM-DDTHH:mm:ss[Z]',
            'YYYY-MM-DDTHH:mm:ss',
            'DD/MM/YYYY HH:mm:ss',
            'DD/MM/YYYY HH:mm',
            'DD/MM/YYYY',
            'DD/MM/YY HH:mm:ss',
            'DD/MM/YY HH:mm',
            'DD/MM/YY'
        ];

        const strictParsed = moment(value, strictFormats, true);
        if (strictParsed.isValid()) return strictParsed;

        const looseParsed = moment(value);
        return looseParsed.isValid() ? looseParsed : null;
    };
    const isAnalyticsDateExpired = (value) => {
        const parsed = parseAnalyticsDate(value);
        if (!parsed) return false;
        return parsed.endOf('day').isBefore(moment());
    };
    const normalizeAnalyticsStatus = (value = '') =>
        normalizeAnalyticsText(value).toLowerCase();
    const isRedeemedAnalyticsValue = (value = '') =>
        ['yes', 'redeemed', 'true', '1'].includes(normalizeAnalyticsStatus(value));
    const isActiveBookingLiabilityRow = (row = {}) => {
        const status = normalizeAnalyticsStatus(row.status);
        if (status === 'flown' || status === 'expired') return false;
        if (isAnalyticsDateExpired(row.expires)) return false;
        return roundCurrencyAmount(row.paid) > 0;
    };
    const isActiveVoucherLiabilityRow = (row = {}) => {
        const status = normalizeAnalyticsStatus(row.status);
        if (isRedeemedAnalyticsValue(row.redeemed)) return false;
        if (status === 'used' || status === 'flown' || status === 'expired') return false;
        if (isAnalyticsDateExpired(row.expires)) return false;
        return roundCurrencyAmount(row.paid) > 0;
    };
    const normalizeAnalyticsText = (value = '') =>
        String(value || '').replace(/\s+/g, ' ').trim();
    const isGenericFlightTypeLabel = (value = '') => {
        const lower = normalizeAnalyticsText(value).toLowerCase();
        return ['shared', 'shared flight', 'private', 'private flight'].includes(lower);
    };
    const normalizeVoucherLabel = (type) => {
        const value = normalizeAnalyticsText(type);
        if (!value || isGenericFlightTypeLabel(value)) return null;

        const lower = value.toLowerCase();
        if (lower.includes('proposal')) return 'Proposal';
        if (lower.includes('private')) return 'Private Charter';
        if (lower.includes('any')) return 'Any Day Flight';
        if (lower.includes('flex')) return 'Flex Weekday';
        if (lower.includes('weekday')) return 'Weekday Morning';
        if (lower.includes('weekend')) return 'Weekend';
        if (lower.includes('gift')) return 'Gift Voucher';

        return value;
    };
    const normalizeAddOnName = (value = '') => {
        const cleaned = normalizeAnalyticsText(value);
        if (!cleaned) return '';

        const lower = cleaned.toLowerCase();
        if (lower.includes('weather') || lower.includes('wx')) return 'Weather Refundable';
        if (lower.includes('choose location')) return 'Choose Location';

        return cleaned;
    };
    const isWeatherAddOnName = (value = '') =>
        normalizeAddOnName(value) === 'Weather Refundable';
    const parseAnalyticsAddOnItems = (rawValue) => {
        if (!rawValue) return [];
        if (Array.isArray(rawValue)) return rawValue;

        if (typeof rawValue === 'string') {
            const trimmed = rawValue.trim();
            if (!trimmed) return [];

            if (trimmed.startsWith('[')) {
                try {
                    const parsed = JSON.parse(trimmed);
                    return Array.isArray(parsed) ? parsed : [];
                } catch (error) {
                    console.warn('Failed to parse analytics add-on JSON:', error?.message || error);
                }
            }

            return trimmed
                .split(',')
                .map((item) => normalizeAnalyticsText(item))
                .filter(Boolean)
                .map((name) => ({ name }));
        }

        return [];
    };
    const getAddOnItemName = (item) =>
        normalizeAddOnName(
            item?.name ??
            item?.title ??
            item?.label ??
            item?.item_name ??
            ''
        );
    const getAddOnItemPrice = (item) => {
        if (!item || typeof item !== 'object') return 0;
        const priceCandidate =
            item.price ??
            item.amount ??
            item.totalPrice ??
            item.total_price ??
            item.value;
        return roundCurrencyAmount(priceCandidate);
    };
    const addAddOnValue = (map, rawName, rawValue) => {
        const name = normalizeAddOnName(rawName);
        const value = roundCurrencyAmount(rawValue);
        if (!name || value <= 0) return;
        map[name] = roundCurrencyAmount((map[name] || 0) + value);
    };
    const isRefundedGrossSalesStatus = (value = '') => {
        const status = normalizeAnalyticsStatus(value);
        return status === 'refund' || status === 'refunded';
    };
    const createGrossSalesMetric = () => ({
        revenue: 0,
        count: 0
    });
    const createGrossSalesBreakdown = () => ({
        total: createGrossSalesMetric(),
        private: createGrossSalesMetric(),
        shared: createGrossSalesMetric()
    });
    const finalizeGrossSalesBreakdown = (breakdown) => ({
        total: {
            revenue: roundCurrencyAmount(breakdown.total.revenue),
            count: Number(breakdown.total.count) || 0
        },
        private: {
            revenue: roundCurrencyAmount(breakdown.private.revenue),
            count: Number(breakdown.private.count) || 0
        },
        shared: {
            revenue: roundCurrencyAmount(breakdown.shared.revenue),
            count: Number(breakdown.shared.count) || 0
        }
    });
    const calculateGrossSalesPercentChange = (current, comparison) => {
        const currentValue = Number(current) || 0;
        const comparisonValue = Number(comparison) || 0;
        if (comparisonValue === 0) return currentValue === 0 ? 0 : null;
        return Math.round(((currentValue - comparisonValue) / comparisonValue) * 1000) / 10;
    };
    const buildGrossSalesComparisonMetric = (currentMetric, comparisonMetric) => ({
        revenue: roundCurrencyAmount(comparisonMetric?.revenue || 0),
        count: Number(comparisonMetric?.count || 0),
        revenueDelta: roundCurrencyAmount((currentMetric?.revenue || 0) - (comparisonMetric?.revenue || 0)),
        revenueDeltaPercent: calculateGrossSalesPercentChange(currentMetric?.revenue || 0, comparisonMetric?.revenue || 0),
        countDelta: (Number(currentMetric?.count || 0) - Number(comparisonMetric?.count || 0)),
        countDeltaPercent: calculateGrossSalesPercentChange(currentMetric?.count || 0, comparisonMetric?.count || 0)
    });
    const buildGrossSalesComparison = (currentBreakdown, comparisonBreakdown, range) => ({
        range,
        total: buildGrossSalesComparisonMetric(currentBreakdown.total, comparisonBreakdown.total),
        private: buildGrossSalesComparisonMetric(currentBreakdown.private, comparisonBreakdown.private),
        shared: buildGrossSalesComparisonMetric(currentBreakdown.shared, comparisonBreakdown.shared)
    });
    const buildGrossSalesRanges = () => {
        const today = moment();
        const todayDate = today.format('YYYY-MM-DD');
        const currentDayOfMonth = today.date();
        const previousMonthStart = today.clone().subtract(1, 'month').startOf('month');
        const previousMonthEnd = previousMonthStart
            .clone()
            .date(Math.min(currentDayOfMonth, previousMonthStart.daysInMonth()));
        const lastYearStart = today.clone().subtract(1, 'year').startOf('month');
        const lastYearEnd = lastYearStart
            .clone()
            .date(Math.min(currentDayOfMonth, lastYearStart.daysInMonth()));

        return {
            today: {
                start: todayDate,
                end: todayDate
            },
            monthToDate: {
                start: today.clone().startOf('month').format('YYYY-MM-DD'),
                end: todayDate
            },
            previousMonthToDate: {
                start: previousMonthStart.format('YYYY-MM-DD'),
                end: previousMonthEnd.format('YYYY-MM-DD')
            },
            samePeriodLastYear: {
                start: lastYearStart.format('YYYY-MM-DD'),
                end: lastYearEnd.format('YYYY-MM-DD')
            }
        };
    };
    const getGrossSalesRevenue = (row = {}) => {
        if (isRefundedGrossSalesStatus(row.status)) return 0;

        const paid = roundCurrencyAmount(row.paid);
        const paymentHistoryCount = Number(row.payment_history_count || 0);
        const paymentTotal = roundCurrencyAmount(row.payment_total);
        const refundTotal = roundCurrencyAmount(row.refund_total);

        if (paymentHistoryCount > 0 && paymentTotal > 0) {
            if (refundTotal >= paymentTotal) return 0;

            const netPaymentTotal = roundCurrencyAmount(paymentTotal - refundTotal);
            if (refundTotal > 0) return netPaymentTotal;

            return Math.max(paid, paymentTotal);
        }

        return paid > 0 ? paid : 0;
    };
    const getGrossSalesSegment = (row = {}) => {
        const typeSignals = [
            row.experience,
            row.flight_type,
            row.flight_type_source,
            row.voucher_type,
            row.voucher_type_detail,
            row.experience_type,
            row.book_flight,
            row.linked_voucher_type,
            row.linked_voucher_type_detail,
            row.linked_experience_type
        ];
        return typeSignals.some(isPrivateCharterTypeValue) ? 'private' : 'shared';
    };
    const summarizeGrossSalesRows = (rows = []) => {
        const breakdown = createGrossSalesBreakdown();

        rows.forEach((row) => {
            const revenue = getGrossSalesRevenue(row);
            if (!(revenue > 0)) return;

            const segment = getGrossSalesSegment(row);
            breakdown[segment].revenue += revenue;
            breakdown[segment].count += 1;
            breakdown.total.revenue += revenue;
            breakdown.total.count += 1;
        });

        return finalizeGrossSalesBreakdown(breakdown);
    };
    const getGrossSalesSnapshot = async () => {
        const [
            hasPaymentHistoryAmount,
            hasPaymentHistoryStatus,
            hasPaymentHistoryOrigin,
            hasPaymentHistoryVoucherId,
            hasPaymentHistoryVoucherRef,
            hasBookingRedeemedVoucher,
            hasBookingVoucherRedeemed,
            hasBookingIsVoucherRedeemed,
            hasBookingFlightTypeSource,
            hasBookingVoucherTypeDetail,
            hasVoucherTypeDetail
        ] = await Promise.all([
            tableHasColumn('payment_history', 'amount'),
            tableHasColumn('payment_history', 'payment_status'),
            tableHasColumn('payment_history', 'origin'),
            tableHasColumn('payment_history', 'voucher_id'),
            tableHasColumn('payment_history', 'voucher_ref'),
            tableHasColumn('all_booking', 'redeemed_voucher'),
            tableHasColumn('all_booking', 'voucher_redeemed'),
            tableHasColumn('all_booking', 'is_voucher_redeemed'),
            tableHasColumn('all_booking', 'flight_type_source'),
            tableHasColumn('all_booking', 'voucher_type_detail'),
            tableHasColumn('all_vouchers', 'voucher_type_detail')
        ]);
        const hasPaymentHistory = hasPaymentHistoryAmount && hasPaymentHistoryStatus;
        const paymentStatusSql = `TRIM(LOWER(COALESCE(payment_status, '')))`;
        const paymentOriginSql = hasPaymentHistoryOrigin
            ? `TRIM(LOWER(COALESCE(origin, ''))) != 'refund'`
            : '1 = 1';
        const refundOriginSql = hasPaymentHistoryOrigin
            ? `OR TRIM(LOWER(COALESCE(origin, ''))) = 'refund'`
            : '';
        const paymentHistoryBookingJoin = hasPaymentHistory
            ? `
                LEFT JOIN (
                    SELECT
                        booking_id,
                        COALESCE(SUM(
                            CASE
                                WHEN amount > 0
                                  AND ${paymentOriginSql}
                                  AND ${paymentStatusSql} NOT IN ('refunded', 'refund', 'failed', 'pending', 'cancelled', 'canceled')
                                THEN amount
                                ELSE 0
                            END
                        ), 0) AS payment_total,
                        COALESCE(SUM(
                            CASE
                                WHEN amount < 0
                                  OR ${paymentStatusSql} IN ('refunded', 'refund')
                                  ${refundOriginSql}
                                THEN ABS(amount)
                                ELSE 0
                            END
                        ), 0) AS refund_total,
                        COUNT(*) AS payment_history_count
                    FROM payment_history
                    WHERE booking_id IS NOT NULL
                    GROUP BY booking_id
                ) ph ON ph.booking_id = ab.id
            `
            : `
                LEFT JOIN (
                    SELECT NULL AS booking_id, 0 AS payment_total, 0 AS refund_total, 0 AS payment_history_count
                ) ph ON 1 = 0
            `;
        const voucherPaymentJoins = [];
        const voucherPaymentTotalExpressions = [];
        const voucherRefundTotalExpressions = [];
        const voucherPaymentHistoryCountExpressions = [];

        if (hasPaymentHistory && hasPaymentHistoryVoucherId) {
            voucherPaymentJoins.push(`
                LEFT JOIN (
                    SELECT
                        voucher_id,
                        COALESCE(SUM(
                            CASE
                                WHEN amount > 0
                                  AND ${paymentOriginSql}
                                  AND ${paymentStatusSql} NOT IN ('refunded', 'refund', 'failed', 'pending', 'cancelled', 'canceled')
                                THEN amount
                                ELSE 0
                            END
                        ), 0) AS payment_total,
                        COALESCE(SUM(
                            CASE
                                WHEN amount < 0
                                  OR ${paymentStatusSql} IN ('refunded', 'refund')
                                  ${refundOriginSql}
                                THEN ABS(amount)
                                ELSE 0
                            END
                        ), 0) AS refund_total,
                        COUNT(*) AS payment_history_count
                    FROM payment_history
                    WHERE voucher_id IS NOT NULL
                    GROUP BY voucher_id
                ) ph_voucher_id ON ph_voucher_id.voucher_id = v.id
            `);
            voucherPaymentTotalExpressions.push('COALESCE(ph_voucher_id.payment_total, 0)');
            voucherRefundTotalExpressions.push('COALESCE(ph_voucher_id.refund_total, 0)');
            voucherPaymentHistoryCountExpressions.push('COALESCE(ph_voucher_id.payment_history_count, 0)');
        }

        if (hasPaymentHistory && hasPaymentHistoryVoucherRef) {
            voucherPaymentJoins.push(`
                LEFT JOIN (
                    SELECT
                        voucher_ref,
                        COALESCE(SUM(
                            CASE
                                WHEN amount > 0
                                  AND ${paymentOriginSql}
                                  AND ${paymentStatusSql} NOT IN ('refunded', 'refund', 'failed', 'pending', 'cancelled', 'canceled')
                                THEN amount
                                ELSE 0
                            END
                        ), 0) AS payment_total,
                        COALESCE(SUM(
                            CASE
                                WHEN amount < 0
                                  OR ${paymentStatusSql} IN ('refunded', 'refund')
                                  ${refundOriginSql}
                                THEN ABS(amount)
                                ELSE 0
                            END
                        ), 0) AS refund_total,
                        COUNT(*) AS payment_history_count
                    FROM payment_history
                    WHERE voucher_ref IS NOT NULL AND voucher_ref != ''
                    GROUP BY voucher_ref
                ) ph_voucher_ref ON ph_voucher_ref.voucher_ref = v.voucher_ref
            `);
            voucherPaymentTotalExpressions.push('COALESCE(ph_voucher_ref.payment_total, 0)');
            voucherRefundTotalExpressions.push('COALESCE(ph_voucher_ref.refund_total, 0)');
            voucherPaymentHistoryCountExpressions.push('COALESCE(ph_voucher_ref.payment_history_count, 0)');
        }

        const voucherPaymentTotalExpression = voucherPaymentTotalExpressions.length > 0
            ? `GREATEST(${voucherPaymentTotalExpressions.join(', ')})`
            : '0';
        const voucherRefundTotalExpression = voucherRefundTotalExpressions.length > 0
            ? `GREATEST(${voucherRefundTotalExpressions.join(', ')})`
            : '0';
        const voucherPaymentHistoryCountExpression = voucherPaymentHistoryCountExpressions.length > 0
            ? `GREATEST(${voucherPaymentHistoryCountExpressions.join(', ')})`
            : '0';
        const voucherPaymentTotalSelect = `${voucherPaymentTotalExpression} AS payment_total`;
        const voucherRefundTotalSelect = `${voucherRefundTotalExpression} AS refund_total`;
        const voucherPaymentHistoryCountSelect = `${voucherPaymentHistoryCountExpression} AS payment_history_count`;
        const redeemedBookingConditions = [];
        if (hasBookingRedeemedVoucher) {
            redeemedBookingConditions.push(`TRIM(LOWER(COALESCE(ab.redeemed_voucher, ''))) IN ('yes', 'redeemed', 'true', '1')`);
        }
        if (hasBookingVoucherRedeemed) {
            redeemedBookingConditions.push(`TRIM(LOWER(COALESCE(ab.voucher_redeemed, ''))) IN ('yes', 'redeemed', 'true', '1')`);
        }
        if (hasBookingIsVoucherRedeemed) {
            redeemedBookingConditions.push(`TRIM(LOWER(COALESCE(ab.is_voucher_redeemed, ''))) IN ('yes', 'redeemed', 'true', '1')`);
        }
        if (hasBookingFlightTypeSource) {
            redeemedBookingConditions.push(`TRIM(LOWER(COALESCE(ab.flight_type_source, ''))) = 'redeem voucher'`);
        }
        const redeemedBookingFilter = redeemedBookingConditions.length > 0
            ? `AND NOT (${redeemedBookingConditions.join(' OR ')})`
            : '';

        const fetchGrossSalesRange = async (range) => {
            const bookingRows = await queryAsync(`
                SELECT
                    'booking' AS source_type,
                    ab.id,
                    ab.paid,
                    ab.status,
                    ab.experience,
                    ab.flight_type,
                    ${hasBookingFlightTypeSource ? 'ab.flight_type_source' : 'NULL AS flight_type_source'},
                    ab.voucher_type,
                    ${hasBookingVoucherTypeDetail ? 'ab.voucher_type_detail' : 'NULL AS voucher_type_detail'},
                    v.voucher_type AS linked_voucher_type,
                    ${hasVoucherTypeDetail ? 'v.voucher_type_detail AS linked_voucher_type_detail' : 'NULL AS linked_voucher_type_detail'},
                    v.experience_type AS linked_experience_type,
                    NULL AS experience_type,
                    NULL AS book_flight,
                    COALESCE(ph.payment_total, 0) AS payment_total,
                    COALESCE(ph.refund_total, 0) AS refund_total,
                    COALESCE(ph.payment_history_count, 0) AS payment_history_count
                FROM all_booking ab
                LEFT JOIN all_vouchers v ON v.voucher_ref = ab.voucher_code
                ${paymentHistoryBookingJoin}
                WHERE ab.created_at IS NOT NULL
                  AND DATE(ab.created_at) >= ?
                  AND DATE(ab.created_at) <= ?
                  ${redeemedBookingFilter}
                  AND (
                        COALESCE(ab.paid, 0) > 0
                        OR COALESCE(ph.payment_total, 0) > 0
                      )
            `, [range.start, range.end]);

            const voucherRows = await queryAsync(`
                SELECT
                    'voucher' AS source_type,
                    v.id,
                    v.paid,
                    v.status,
                    NULL AS experience,
                    NULL AS flight_type,
                    NULL AS flight_type_source,
                    v.voucher_type,
                    ${hasVoucherTypeDetail ? 'v.voucher_type_detail' : 'NULL AS voucher_type_detail'},
                    NULL AS linked_voucher_type,
                    NULL AS linked_voucher_type_detail,
                    NULL AS linked_experience_type,
                    v.experience_type,
                    v.book_flight,
                    ${voucherPaymentTotalSelect},
                    ${voucherRefundTotalSelect},
                    ${voucherPaymentHistoryCountSelect}
                FROM all_vouchers v
                ${voucherPaymentJoins.join('\n')}
                WHERE v.created_at IS NOT NULL
                  AND DATE(v.created_at) >= ?
                  AND DATE(v.created_at) <= ?
                  AND (
                        COALESCE(v.paid, 0) > 0
                        OR ${voucherPaymentTotalExpression} > 0
                      )
            `, [range.start, range.end]);

            return summarizeGrossSalesRows([...(bookingRows || []), ...(voucherRows || [])]);
        };

        const ranges = buildGrossSalesRanges();
        const [
            today,
            monthToDate,
            previousMonthToDate,
            samePeriodLastYear
        ] = await Promise.all([
            fetchGrossSalesRange(ranges.today),
            fetchGrossSalesRange(ranges.monthToDate),
            fetchGrossSalesRange(ranges.previousMonthToDate),
            fetchGrossSalesRange(ranges.samePeriodLastYear)
        ]);

        return {
            generatedAt: moment().toISOString(),
            today: {
                range: ranges.today,
                ...today
            },
            monthToDate: {
                range: ranges.monthToDate,
                ...monthToDate,
                comparisons: {
                    previousMonthToDate: buildGrossSalesComparison(monthToDate, previousMonthToDate, ranges.previousMonthToDate),
                    samePeriodLastYear: buildGrossSalesComparison(monthToDate, samePeriodLastYear, ranges.samePeriodLastYear)
                }
            }
        };
    };
    // 1. Booking Attempts
    // Query all bookings from all_booking table (matching the "All Booking" table view)
    // flight_attempts represents the number of cancellations/reschedules:
    // - 0 = 1st attempt (no cancellations)
    // - 1 = 2nd attempt (1 cancellation)
    // - 2 = 3rd attempt (2 cancellations)
    // - 3 = 4th attempt (3 cancellations)
    // - 4 = 5th attempt (4 cancellations)
    // - 5+ = 6+ attempts (5+ cancellations)
    const attemptsSql = `
        SELECT flight_attempts
        FROM all_booking
        WHERE flight_date IS NOT NULL
        AND status IN ('Flown', 'Confirmed', 'Scheduled')
        ${dateFilter()}
    `;
    con.query(attemptsSql, [], (err, rows) => {
        if (err) return res.status(500).json({ error: 'Failed to fetch booking attempts' });
        const total = rows.length;
        let first = 0, second = 0, third = 0, fourth = 0, fifth = 0, sixthPlus = 0;
        rows.forEach(r => {
            // Treat null/undefined as 0 (1st attempt)
            const att = Number((r.flight_attempts !== undefined && r.flight_attempts !== null) ? r.flight_attempts : 0);
            if (att === 0) first++;
            else if (att === 1) second++;
            else if (att === 2) third++;
            else if (att === 3) fourth++;
            else if (att === 4) fifth++;
            else sixthPlus++; // att >= 5
        });
        // Calculate percentages with proper rounding to ensure sum is 100%
        const calculatePercentages = (counts, total) => {
            if (total === 0) {
                return {
                    first: 0,
                    second: 0,
                    third: 0,
                    fourth: 0,
                    fifth: 0,
                    sixthPlus: 0
                };
            }
            // Calculate raw percentages
            const raw = {
                first: (counts.first / total) * 100,
                second: (counts.second / total) * 100,
                third: (counts.third / total) * 100,
                fourth: (counts.fourth / total) * 100,
                fifth: (counts.fifth / total) * 100,
                sixthPlus: (counts.sixthPlus / total) * 100
            };
            // Round each percentage
            const rounded = {
                first: Math.round(raw.first),
                second: Math.round(raw.second),
                third: Math.round(raw.third),
                fourth: Math.round(raw.fourth),
                fifth: Math.round(raw.fifth),
                sixthPlus: Math.round(raw.sixthPlus)
            };
            // Calculate sum of rounded percentages
            const sum = rounded.first + rounded.second + rounded.third + rounded.fourth + rounded.fifth + rounded.sixthPlus;
            // Adjust if sum is not 100% (due to rounding)
            if (sum !== 100 && total > 0) {
                // Find the category with the largest fractional part and adjust it
                const fractionalParts = {
                    first: raw.first - rounded.first,
                    second: raw.second - rounded.second,
                    third: raw.third - rounded.third,
                    fourth: raw.fourth - rounded.fourth,
                    fifth: raw.fifth - rounded.fifth,
                    sixthPlus: raw.sixthPlus - rounded.sixthPlus
                };
                // Sort by fractional part (descending) to find which to adjust
                const sorted = Object.entries(fractionalParts)
                    .sort((a, b) => b[1] - a[1]);
                // Adjust the category with largest fractional part
                const diff = 100 - sum;
                if (diff > 0) {
                    rounded[sorted[0][0]] += diff;
                } else {
                    rounded[sorted[sorted.length - 1][0]] += diff;
                }
            }
            return rounded;
        };
        const bookingAttempts = calculatePercentages({ first, second, third, fourth, fifth, sixthPlus }, total);
        // 2. Sales by Source
        // First, find the question_id for "How did you hear about us?" question
        const findQuestionSql = `
            SELECT id FROM additional_information_questions 
            WHERE question_text LIKE '%hear about us%' OR question_text LIKE '%hear about%'
            AND is_active = 1
            LIMIT 1
        `;
        con.query(findQuestionSql, [], (errFindQ, questionRows) => {
            if (errFindQ) {
                console.warn('Could not find "hear about us" question:', errFindQ);
            }

            const hearAboutUsQuestionId = questionRows && questionRows.length > 0 ? questionRows[0].id : null;
            console.log('Found "hear about us" question_id:', hearAboutUsQuestionId);

            // Get source data from multiple sources:
            // 1. Legacy hear_about_us column from all_booking
            // 2. additional_information_answers table for bookings
            // 3. all_vouchers table (additional_information_json and legacy fields)

            const sourceDataMap = {};
            // Declare variables in upper scope so they're accessible in all callbacks
            let salesBySource = [];
            let nonRedemption = { value: 0, percent: 0 };
            let addOns = [];
            let addOnsTotalValue = 0;

            // 1. Get from legacy hear_about_us column in all_booking
            const legacySourceSql = `
            SELECT hear_about_us, COUNT(*) as count
            FROM all_booking
            WHERE flight_date IS NOT NULL
            AND status IN ('Flown', 'Confirmed', 'Scheduled')
                AND hear_about_us IS NOT NULL AND hear_about_us != ''
            ${dateFilter()}
            GROUP BY hear_about_us
        `;

            con.query(legacySourceSql, [], (errLegacy, legacyRows) => {
                if (errLegacy) {
                    console.warn('Error fetching legacy hear_about_us:', errLegacy);
                } else {
                    legacyRows.forEach(row => {
                        const source = (row.hear_about_us || '').trim();
                        if (source) {
                            sourceDataMap[source] = (sourceDataMap[source] || 0) + row.count;
                        }
                    });
                }

                // 2. Get from additional_information_answers for bookings
                if (hearAboutUsQuestionId) {
                    const answersSourceSql = `
                        SELECT aia.answer, COUNT(*) as count
                        FROM additional_information_answers aia
                        INNER JOIN all_booking ab ON aia.booking_id = ab.id
                        WHERE aia.question_id = ?
                        AND ab.flight_date IS NOT NULL
                        AND ab.status IN ('Flown', 'Confirmed', 'Scheduled')
                        AND aia.answer IS NOT NULL AND aia.answer != ''
                        ${dateFilter('ab.flight_date')}
                        GROUP BY aia.answer
                    `;

                    con.query(answersSourceSql, [hearAboutUsQuestionId], (errAnswers, answerRows) => {
                        if (errAnswers) {
                            console.warn('Error fetching answers from additional_information_answers:', errAnswers);
                        } else {
                            answerRows.forEach(row => {
                                const source = (row.answer || '').trim();
                                if (source) {
                                    sourceDataMap[source] = (sourceDataMap[source] || 0) + row.count;
                                }
                            });
                        }

                        // 3. Get from all_vouchers (both additional_information_json and legacy fields)
                        // For vouchers, we count each voucher that has source information
                        const vouchersSourceSql = `
                            SELECT 
                                v.additional_information_json,
                                v.hear_about_us,
                                v.created_at
                            FROM all_vouchers v
                            WHERE v.created_at IS NOT NULL
                            ${dateFilter('v.created_at')}
                        `;

                        con.query(vouchersSourceSql, [], (errVouchers, voucherRows) => {
                            if (errVouchers) {
                                console.warn('Error fetching vouchers source data:', errVouchers);
                            } else {
                                voucherRows.forEach(row => {
                                    let source = null;

                                    // First try additional_information_json
                                    if (row.additional_information_json) {
                                        try {
                                            const jsonData = typeof row.additional_information_json === 'string'
                                                ? JSON.parse(row.additional_information_json)
                                                : row.additional_information_json;

                                            if (hearAboutUsQuestionId && jsonData[`question_${hearAboutUsQuestionId}`]) {
                                                source = jsonData[`question_${hearAboutUsQuestionId}`];
                                            }
                                        } catch (e) {
                                            console.warn('Error parsing voucher additional_information_json:', e);
                                        }
                                    }

                                    // Fallback to legacy hear_about_us
                                    if (!source && row.hear_about_us) {
                                        source = row.hear_about_us;
                                    }

                                    if (source && source.trim()) {
                                        source = source.trim();
                                        sourceDataMap[source] = (sourceDataMap[source] || 0) + 1;
                                    }
                                });
                            }

                            // Calculate totals and percentages
                            const totalSrc = Object.values(sourceDataMap).reduce((sum, count) => sum + count, 0);
                            salesBySource = Object.entries(sourceDataMap)
                                .map(([source, count]) => ({
                                    source: source || 'Other',
                                    percent: totalSrc ? Math.round((count / totalSrc) * 100) : 0,
                                    count: count
                                }))
                                .sort((a, b) => b.count - a.count); // Sort by count descending

                            console.log('Sales by Source calculated:', salesBySource);

                            // Continue with the remaining analytics using the same normalized rules.
                            (async () => {
                                try {
                                    const hasVoucherLocationColumn = await tableHasColumn('all_vouchers', 'location');
                                    const grossSalesPromise = getGrossSalesSnapshot();
                                    const [
                                        nonRedemptionBookingRows,
                                        nonRedemptionVoucherRows,
                                        bookingAddOnRows,
                                        voucherAddOnRows,
                                        addOnCatalogRows,
                                        bookingLocRows,
                                        voucherLocRows,
                                        voucherLocRows2,
                                        bookingTypeRows,
                                        voucherTypeRows,
                                        bookingLiabilityRows,
                                        voucherLiabilityDetailRows,
                                        flownRows,
                                    ] = await Promise.all([
                                        queryAsync(`
                                            SELECT
                                                COUNT(*) AS count,
                                                COALESCE(SUM(COALESCE(paid, 0)), 0) AS total
                                            FROM all_booking
                                            WHERE COALESCE(paid, 0) > 0
                                              AND (
                                                    TRIM(LOWER(COALESCE(status, ''))) = 'expired'
                                                    OR (expires IS NOT NULL AND expires < CURDATE())
                                                  )
                                              AND TRIM(LOWER(COALESCE(status, ''))) != 'flown'
                                              ${dateFilter('expires')}
                                        `),
                                        queryAsync(`
                                            SELECT
                                                COUNT(*) AS count,
                                                COALESCE(SUM(COALESCE(paid, 0)), 0) AS total
                                            FROM all_vouchers
                                            WHERE COALESCE(paid, 0) > 0
                                              AND expires IS NOT NULL
                                              AND expires < CURDATE()
                                              AND (
                                                    redeemed IS NULL
                                                    OR TRIM(LOWER(redeemed)) NOT IN ('yes', 'redeemed', 'true', '1')
                                                  )
                                              AND (
                                                    status IS NULL
                                                    OR TRIM(LOWER(status)) NOT IN ('used', 'flown')
                                                  )
                                              ${dateFilter('expires')}
                                        `),
                                        queryAsync(`
                                            SELECT
                                                id,
                                                choose_add_on,
                                                COALESCE(add_to_booking_items_total_price, 0) AS add_to_booking_items_total_price,
                                                COALESCE(weather_refund_total_price, 0) AS weather_refund_total_price,
                                                paid
                                            FROM all_booking
                                            WHERE COALESCE(paid, 0) > 0
                                              ${dateFilter()}
                                        `),
                                        queryAsync(`
                                            SELECT
                                                id,
                                                add_to_booking_items,
                                                voucher_passenger_details,
                                                paid,
                                                voucher_type,
                                                experience_type,
                                                book_flight,
                                                numberOfPassengers
                                            FROM all_vouchers
                                            WHERE COALESCE(paid, 0) > 0
                                              ${dateFilter('created_at')}
                                        `),
                                        queryAsync(`
                                            SELECT title, price
                                            FROM add_to_booking_items
                                        `),
                                        queryAsync(`
                                            SELECT ab.location, COUNT(*) as count
                                            FROM all_booking ab
                                            LEFT JOIN all_vouchers v ON v.voucher_ref = ab.voucher_code
                                            WHERE ab.flight_date IS NOT NULL
                                              AND ab.status IN ('Flown', 'Confirmed', 'Scheduled')
                                              AND ab.location IS NOT NULL AND ab.location != ''
                                              AND v.id IS NULL
                                              ${dateFilter('ab.flight_date')}
                                            GROUP BY ab.location
                                        `),
                                        queryAsync(`
                                            SELECT preferred_location, COUNT(*) as count
                                            FROM all_vouchers
                                            WHERE created_at IS NOT NULL
                                              AND preferred_location IS NOT NULL AND preferred_location != ''
                                              ${dateFilter('created_at')}
                                            GROUP BY preferred_location
                                        `),
                                        hasVoucherLocationColumn ? queryAsync(`
                                            SELECT location, COUNT(*) as count
                                            FROM all_vouchers
                                            WHERE created_at IS NOT NULL
                                              AND location IS NOT NULL AND location != ''
                                              AND (preferred_location IS NULL OR preferred_location = '')
                                              ${dateFilter('created_at')}
                                            GROUP BY location
                                        `) : Promise.resolve([]),
                                        queryAsync(`
                                            SELECT
                                                COALESCE(NULLIF(v.voucher_type, ''), NULLIF(ab.voucher_type, ''), NULLIF(ab.voucher_type_detail, '')) as voucher_type,
                                                COUNT(*) as count
                                            FROM all_booking ab
                                            LEFT JOIN all_vouchers v ON v.voucher_ref = ab.voucher_code
                                            WHERE ab.flight_date IS NOT NULL
                                              AND ab.status IN ('Flown', 'Confirmed', 'Scheduled')
                                              ${dateFilter('ab.flight_date')}
                                            GROUP BY voucher_type
                                        `),
                                        queryAsync(`
                                            SELECT voucher_type, COUNT(*) as count
                                            FROM all_vouchers
                                            WHERE created_at IS NOT NULL
                                              ${dateFilter('created_at')}
                                            GROUP BY voucher_type
                                        `),
                                        // Liability is always a live balance and must ignore the selected date range.
                                        queryAsync(`
                                            SELECT
                                                ab.id,
                                                ab.paid,
                                                ab.status,
                                                ab.expires,
                                                ab.experience,
                                                ab.flight_type,
                                                ab.voucher_type,
                                                ab.voucher_type_detail,
                                                v.voucher_type AS linked_voucher_type,
                                                ab.location,
                                                ab.pax,
                                                COALESCE(ab.add_to_booking_items_total_price, 0) AS add_to_booking_items_total_price,
                                                COALESCE(ab.weather_refund_total_price, 0) AS weather_refund_total_price
                                            FROM all_booking ab
                                            LEFT JOIN all_vouchers v ON v.voucher_ref = ab.voucher_code
                                            WHERE ab.paid IS NOT NULL
                                              AND ab.paid > 0
                                        `),
                                        queryAsync(`
                                            SELECT
                                                v.id,
                                                v.paid,
                                                v.status,
                                                v.redeemed,
                                                v.expires,
                                                v.voucher_type,
                                                v.voucher_type_detail,
                                                v.experience_type,
                                                v.book_flight,
                                                v.preferred_location
                                                ${hasVoucherLocationColumn ? ', v.location' : ', NULL AS location'}
                                            FROM all_vouchers v
                                            WHERE v.paid IS NOT NULL
                                              AND v.paid > 0
                                        `),
                                        queryAsync(`
                                            SELECT location, COUNT(*) as count
                                            FROM all_booking
                                            WHERE status != 'Cancelled'
                                              AND flight_date IS NOT NULL
                                              AND flight_date < CURDATE()
                                              ${dateFilter('flight_date')}
                                            GROUP BY location
                                        `)
                                    ]);

                                    const expiredBookingPaid = Number(nonRedemptionBookingRows?.[0]?.total || 0);
                                    const expiredVoucherPaid = Number(nonRedemptionVoucherRows?.[0]?.total || 0);
                                    const expiredBookingCount = Number(nonRedemptionBookingRows?.[0]?.count || 0);
                                    const expiredVoucherCount = Number(nonRedemptionVoucherRows?.[0]?.count || 0);

                                    nonRedemption = {
                                        value: roundCurrencyAmount(expiredBookingPaid + expiredVoucherPaid),
                                        percent: 0,
                                        count: expiredBookingCount + expiredVoucherCount
                                    };

                                    const addOnCatalogMap = {};
                                    (addOnCatalogRows || []).forEach((row) => {
                                        const name = normalizeAddOnName(row.title);
                                        const price = roundCurrencyAmount(row.price);
                                        if (!name || price <= 0 || addOnCatalogMap[name] > 0) return;
                                        addOnCatalogMap[name] = price;
                                    });

                                    const addOnMap = {};

                                    (bookingAddOnRows || []).forEach((row) => {
                                        const parsedItems = parseAnalyticsAddOnItems(row.choose_add_on);
                                        let allocatedNonWeather = 0;
                                        let hasExplicitWeatherAddOn = false;

                                        parsedItems.forEach((item) => {
                                            const itemName = getAddOnItemName(item);
                                            if (!itemName) return;

                                            let itemPrice = getAddOnItemPrice(item);
                                            if (!(itemPrice > 0)) {
                                                itemPrice = roundCurrencyAmount(addOnCatalogMap[itemName]);
                                            }
                                            if (!(itemPrice > 0)) return;

                                            if (isWeatherAddOnName(itemName)) {
                                                hasExplicitWeatherAddOn = true;
                                            } else {
                                                allocatedNonWeather += itemPrice;
                                            }

                                            addAddOnValue(addOnMap, itemName, itemPrice);
                                        });

                                        const storedAddOnTotal = roundCurrencyAmount(row.add_to_booking_items_total_price);
                                        const remainingStoredAddOnTotal = roundCurrencyAmount(storedAddOnTotal - allocatedNonWeather);
                                        if (remainingStoredAddOnTotal > 0) {
                                            const fallbackNames = parsedItems
                                                .map((item) => getAddOnItemName(item))
                                                .filter((name) => name && !isWeatherAddOnName(name));

                                            if (fallbackNames.length === 1) {
                                                addAddOnValue(addOnMap, fallbackNames[0], remainingStoredAddOnTotal);
                                            } else {
                                                addAddOnValue(addOnMap, 'Other Add-Ons', remainingStoredAddOnTotal);
                                            }
                                        }

                                        const weatherRefundTotal = roundCurrencyAmount(row.weather_refund_total_price);
                                        if (!hasExplicitWeatherAddOn && weatherRefundTotal > 0) {
                                            addAddOnValue(addOnMap, 'Weather Refundable', weatherRefundTotal);
                                        }
                                    });

                                    (voucherAddOnRows || []).forEach((row) => {
                                        const parsedItems = parseAnalyticsAddOnItems(row.add_to_booking_items);
                                        let allocatedNonWeather = 0;
                                        let hasExplicitWeatherAddOn = false;

                                        parsedItems.forEach((item) => {
                                            const itemName = getAddOnItemName(item);
                                            if (!itemName) return;

                                            let itemPrice = getAddOnItemPrice(item);
                                            if (!(itemPrice > 0)) {
                                                itemPrice = roundCurrencyAmount(addOnCatalogMap[itemName]);
                                            }
                                            if (!(itemPrice > 0)) return;

                                            if (isWeatherAddOnName(itemName)) {
                                                hasExplicitWeatherAddOn = true;
                                            } else {
                                                allocatedNonWeather += itemPrice;
                                            }

                                            addAddOnValue(addOnMap, itemName, itemPrice);
                                        });

                                        if (!hasExplicitWeatherAddOn) {
                                            const voucherPassengers = parsePassengerList(row.voucher_passenger_details);
                                            const weatherPassengerCount = voucherPassengers.filter((passenger) =>
                                                isWeatherRefundSelectedValue(passenger?.weather_refund) ||
                                                isWeatherRefundSelectedValue(passenger?.weatherRefund)
                                            ).length;

                                            if (weatherPassengerCount > 0) {
                                                const isPrivateVoucher = [
                                                    row.voucher_type,
                                                    row.experience_type,
                                                    row.book_flight
                                                ].some(isPrivateCharterTypeValue);

                                                let weatherRefundTotal = 0;
                                                if (isPrivateVoucher) {
                                                    const passengerBaseTotal = roundCurrencyAmount(
                                                        derivePaidAmount({
                                                            paidValue: 0,
                                                            voucherPassengerDetails: voucherPassengers,
                                                            passengerCount: parseInt(row.numberOfPassengers, 10) || voucherPassengers.length || 0,
                                                            includePriceFallback: false
                                                        })
                                                    );
                                                    const paidTotal = roundCurrencyAmount(row.paid);

                                                    if (paidTotal > 0 && passengerBaseTotal > 0) {
                                                        weatherRefundTotal = roundCurrencyAmount(
                                                            Math.max(0, paidTotal - allocatedNonWeather - passengerBaseTotal)
                                                        );
                                                    }

                                                    if (!(weatherRefundTotal > 0) && paidTotal > allocatedNonWeather) {
                                                        weatherRefundTotal = roundCurrencyAmount(
                                                            (paidTotal - allocatedNonWeather) / 11
                                                        );
                                                    }
                                                } else {
                                                    weatherRefundTotal = roundCurrencyAmount(weatherPassengerCount * WEATHER_REFUND_PRICE_GBP);
                                                }

                                                if (weatherRefundTotal > 0) {
                                                    addAddOnValue(addOnMap, 'Weather Refundable', weatherRefundTotal);
                                                }
                                            }
                                        }
                                    });

                                    addOns = Object.entries(addOnMap)
                                        .map(([name, value]) => ({
                                            name,
                                            value: roundCurrencyAmount(value)
                                        }))
                                        .sort((a, b) => b.value - a.value);
                                    addOnsTotalValue = roundCurrencyAmount(
                                        Object.values(addOnMap).reduce((sum, value) => sum + (Number(value) || 0), 0)
                                    );

                                    const locationDataMap = {};
                                    [...(bookingLocRows || []), ...(voucherLocRows || [])].forEach((row) => {
                                        const location = normalizeAnalyticsText(row.location || row.preferred_location);
                                        if (!location) return;
                                        locationDataMap[location] = (locationDataMap[location] || 0) + (Number(row.count) || 0);
                                    });
                                    (voucherLocRows2 || []).forEach((row) => {
                                        const location = normalizeAnalyticsText(row.location);
                                        if (!location) return;
                                        locationDataMap[location] = (locationDataMap[location] || 0) + (Number(row.count) || 0);
                                    });

                                    const totalLoc = Object.values(locationDataMap).reduce((sum, count) => sum + count, 0);
                                    const salesByLocation = Object.entries(locationDataMap)
                                        .map(([location, count]) => ({
                                            location: location || 'Other',
                                            percent: totalLoc ? Math.round((count / totalLoc) * 100) : 0,
                                            count
                                        }))
                                        .sort((a, b) => b.count - a.count);

                                    const addTypeCount = (map, type, count) => {
                                        const label = normalizeVoucherLabel(type);
                                        if (!label) return;
                                        map[label] = (map[label] || 0) + (Number(count) || 0);
                                    };

                                    const typeCounts = {};
                                    (bookingTypeRows || []).forEach((row) => addTypeCount(typeCounts, row.voucher_type, row.count));
                                    (voucherTypeRows || []).forEach((row) => addTypeCount(typeCounts, row.voucher_type, row.count));

                                    const totalType = Object.values(typeCounts).reduce((sum, count) => sum + count, 0);
                                    const salesByBookingType = Object.entries(typeCounts)
                                        .map(([label, count]) => ({
                                            type: label,
                                            percent: totalType ? Math.round((count / totalType) * 100) : 0,
                                            count
                                        }))
                                        .sort((a, b) => b.count - a.count);

                                    const activeBookingLiabilityRows = (bookingLiabilityRows || []).filter(isActiveBookingLiabilityRow);
                                    const activeVoucherLiabilityRows = (voucherLiabilityDetailRows || []).filter(isActiveVoucherLiabilityRow);

                                    const liabilityLocationMap = {};
                                    activeBookingLiabilityRows.forEach((row) => {
                                        const location = normalizeAnalyticsText(row.location) || 'Other';
                                        liabilityLocationMap[location] = roundCurrencyAmount(
                                            (liabilityLocationMap[location] || 0) + (Number(row.paid) || 0)
                                        );
                                    });

                                    const liabilityByLocation = Object.entries(liabilityLocationMap)
                                        .map(([location, value]) => ({
                                            location,
                                            value: roundCurrencyAmount(value)
                                        }))
                                        .sort((a, b) => b.value - a.value);

                                    const liabilityTypeMap = {};
                                    activeBookingLiabilityRows.forEach((row) => {
                                        const label = normalizeVoucherLabel(
                                            row.linked_voucher_type ||
                                            row.voucher_type ||
                                            row.voucher_type_detail ||
                                            row.experience ||
                                            row.flight_type
                                        );
                                        if (!label) return;
                                        liabilityTypeMap[label] = roundCurrencyAmount(
                                            (liabilityTypeMap[label] || 0) + (Number(row.paid) || 0)
                                        );
                                    });

                                    const liabilityByFlightType = Object.entries(liabilityTypeMap)
                                        .map(([label, value]) => ({
                                            type: label,
                                            value: roundCurrencyAmount(value)
                                        }))
                                        .sort((a, b) => b.value - a.value);

                                    const refundableBookingIds = activeBookingLiabilityRows.map((row) => row.id).filter(Boolean);
                                    const refundablePassengerRows = refundableBookingIds.length > 0
                                        ? await queryAsync(
                                            `
                                                SELECT booking_id, COUNT(*) as wx_count
                                                FROM passenger
                                                WHERE booking_id IN (${refundableBookingIds.map(() => '?').join(',')})
                                                  AND (weather_refund = 1 OR weather_refund = '1')
                                                GROUP BY booking_id
                                            `,
                                            refundableBookingIds
                                        )
                                        : [];

                                    const passengerWeatherCountByBooking = {};
                                    (refundablePassengerRows || []).forEach((row) => {
                                        passengerWeatherCountByBooking[row.booking_id] = Number(row.wx_count) || 0;
                                    });

                                    let refundableLiabilityTotal = 0;
                                    for (const bookingRow of activeBookingLiabilityRows) {
                                        let weatherRefundTotal = roundCurrencyAmount(bookingRow.weather_refund_total_price);
                                        const passengerWeatherCount = Number(passengerWeatherCountByBooking[bookingRow.id]) || 0;
                                        const isPrivateBooking = [
                                            bookingRow.experience,
                                            bookingRow.flight_type,
                                            bookingRow.voucher_type,
                                            bookingRow.voucher_type_detail
                                        ].some(isPrivateCharterTypeValue);

                                        if (!(weatherRefundTotal > 0) && passengerWeatherCount > 0) {
                                            if (isPrivateBooking) {
                                                weatherRefundTotal = await derivePrivateCharterWeatherRefundTotal(bookingRow);
                                            } else {
                                                weatherRefundTotal = roundCurrencyAmount(passengerWeatherCount * WEATHER_REFUND_PRICE_GBP);
                                            }
                                        }

                                        // Private Charter bookings store the weather-refund toggle at the booking
                                        // level, not as a per-passenger flag, so passengerWeatherCount can be 0
                                        // even when the customer paid the refundable surcharge. Always probe the
                                        // private charter pricing as a fallback so those bookings are still
                                        // counted toward Refundable Liability (e.g. booking 1609).
                                        if (isPrivateBooking && !(weatherRefundTotal > 0)) {
                                            try {
                                                const derived = await derivePrivateCharterWeatherRefundTotal(bookingRow);
                                                if (derived > 0) {
                                                    weatherRefundTotal = derived;
                                                }
                                            } catch (privateRefundError) {
                                                console.warn('Analytics: failed to derive private charter weather refund for booking', bookingRow?.id, privateRefundError?.message || privateRefundError);
                                            }
                                        }

                                        const hasWeatherRefund = weatherRefundTotal > 0 || passengerWeatherCount > 0;
                                        if (!hasWeatherRefund) continue;

                                        const baseFlightValue = roundCurrencyAmount(
                                            Math.max(
                                                0,
                                                (Number(bookingRow.paid) || 0) -
                                                (Number(bookingRow.add_to_booking_items_total_price) || 0) -
                                                weatherRefundTotal
                                            )
                                        );
                                        refundableLiabilityTotal += baseFlightValue;
                                    }

                                    const flownFlightsByLocation = (flownRows || []).map((row) => ({
                                        location: normalizeAnalyticsText(row.location) || 'Other',
                                        count: Number(row.count) || 0
                                    }));

                                    const voucherLiability = roundCurrencyAmount(
                                        activeVoucherLiabilityRows.reduce((sum, row) => sum + (Number(row.paid) || 0), 0)
                                    );
                                    const totalBookingLiability = roundCurrencyAmount(
                                        activeBookingLiabilityRows.reduce((sum, row) => sum + (Number(row.paid) || 0), 0)
                                    );
                                    const totalLiability = roundCurrencyAmount(totalBookingLiability + voucherLiability);
                                    const grossSales = await grossSalesPromise;

                                    res.json({
                                        bookingAttempts,
                                        grossSales,
                                        salesBySource,
                                        nonRedemption,
                                        addOns,
                                        addOnsTotal: addOnsTotalValue,
                                        salesByLocation,
                                        salesByBookingType,
                                        liabilityByLocation,
                                        liabilityByFlightType,
                                        refundableLiability: roundCurrencyAmount(refundableLiabilityTotal),
                                        flownFlightsByLocation,
                                        voucherLiability,
                                        totalLiability
                                    });
                                } catch (analyticsError) {
                                    console.error('Analytics endpoint calculation error:', analyticsError);
                                    res.status(500).json({ error: 'Failed to fetch analytics' });
                                }
                            })();
                        });
                    });
                }
            });
        });
    });
});
