app.post("/api/createActivity", upload.single('image'), (req, res) => {
    const {
        activity_name,
        capacity,
        event_time,
        location,
        flight_type,
        voucher_type,
        private_charter_voucher_types,
        private_charter_pricing,
        private_charter_sale_pricing,
        status,
        weekday_morning_price,
        weekday_morning_sale_price,
        flexible_weekday_price,
        flexible_weekday_sale_price,
        any_day_flight_price,
        any_day_flight_sale_price,
        shared_flight_from_price,
        shared_flight_from_sale_price,
        private_charter_from_price,
        private_charter_from_sale_price
    } = req.body;
    let image = null;
    if (req.file) {
        // Sunucuya göre path'i düzelt
        image = `/uploads/activities/${req.file.filename}`;
    }
    if (!activity_name || !capacity || !location || !flight_type || !status || !weekday_morning_price || !flexible_weekday_price || !any_day_flight_price || !shared_flight_from_price || !private_charter_from_price) {
        return res.status(400).json({ success: false, message: "Eksik bilgi!" });
    }

    // Validate and format flight_type
    let formattedFlightType = flight_type;
    if (Array.isArray(flight_type)) {
        formattedFlightType = flight_type.join(',');
    } else if (typeof flight_type === 'string') {
        // Ensure it's properly formatted
        formattedFlightType = flight_type.split(',').map(type => type.trim()).join(',');
    }

    // Validate and format private_charter_voucher_types
    let formattedPrivateCharterVoucherTypes = private_charter_voucher_types;
    if (Array.isArray(private_charter_voucher_types)) {
        formattedPrivateCharterVoucherTypes = private_charter_voucher_types.join(',');
    } else if (typeof private_charter_voucher_types === 'string') {
        // Ensure it's properly formatted
        formattedPrivateCharterVoucherTypes = private_charter_voucher_types.split(',').map(type => type.trim()).join(',');
    }

    const sanitizedPrivateCharterSalePricing = sanitizeSalePricingMap(private_charter_sale_pricing);
    con.query('SELECT COALESCE(MAX(display_order), 0) + 1 AS next_order FROM activity', (errMax, maxRows) => {
        if (errMax) {
            return res.status(500).json({ success: false, message: "Database error" });
        }
        const nextOrder = maxRows && maxRows[0] && maxRows[0].next_order != null ? maxRows[0].next_order : 1;

        const sql = `
        INSERT INTO activity (
            activity_name,
            capacity,
            start_date,
            end_date,
            event_time,
            location,
            flight_type,
            voucher_type,
            private_charter_voucher_types,
            private_charter_pricing,
            private_charter_sale_pricing,
            status,
            image,
            weekday_morning_price,
            weekday_morning_sale_price,
            flexible_weekday_price,
            flexible_weekday_sale_price,
            any_day_flight_price,
            any_day_flight_sale_price,
            shared_flight_from_price,
            shared_flight_from_sale_price,
            private_charter_from_price,
            private_charter_from_sale_price,
            display_order
        )
        VALUES (?, ?, NULL, NULL, NULL, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `;
        con.query(sql, [
            activity_name,
            capacity,
            location,
            formattedFlightType,
            voucher_type || 'All',
            formattedPrivateCharterVoucherTypes || null,
            serializeJsonField(private_charter_pricing),
            serializeJsonField(sanitizedPrivateCharterSalePricing),
            status,
            image,
            weekday_morning_price,
            formatSaleNumericPrice(weekday_morning_sale_price),
            flexible_weekday_price,
            formatSaleNumericPrice(flexible_weekday_sale_price),
            any_day_flight_price,
            formatSaleNumericPrice(any_day_flight_sale_price),
            shared_flight_from_price,
            formatSaleNumericPrice(shared_flight_from_sale_price),
            private_charter_from_price,
            formatSaleNumericPrice(private_charter_from_sale_price),
            nextOrder
        ], (err, result) => {
            if (err) {
                return res.status(500).json({ success: false, message: "Database error" });
            }
            res.json({ success: true, data: result });
        });
    });
});

