// Update availability status (Open/Close)
app.patch('/api/availability/:id/status', (req, res) => {
    const { id } = req.params;
    const { status } = req.body;

    if (!id || !status) {
        return res.status(400).json({ success: false, message: 'Missing availability id or status' });
    }

    if (status !== 'Open' && status !== 'Closed') {
        return res.status(400).json({ success: false, message: 'Status must be either "Open" or "Closed"' });
    }

    const sql = 'UPDATE activity_availability SET status = ? WHERE id = ?';
    con.query(sql, [status, id], (err, result) => {
        if (err) {
            console.error('Error updating availability status:', err);
            return res.status(500).json({ success: false, message: 'Database error', error: err });
        }

        if (result.affectedRows === 0) {
            return res.status(404).json({ success: false, message: 'Availability not found' });
        }

        res.json({
            success: true,
            message: `Availability status updated to ${status}`,
            data: { id, status }
        });
    });
});

const normalizeHoldSpaces = (value) => {
    if (typeof value === 'number') {
        return Number.isInteger(value) ? value : NaN;
    }

    const normalizedValue = String(value ?? '').trim();
    if (!/^\d+$/.test(normalizedValue)) {
        return NaN;
    }

    return Number.parseInt(normalizedValue, 10);
};

const buildHoldSpacesPayload = (availability) => {
    const available = Math.max(0, Number(availability.available || 0));
    const heldSpaces = Math.max(0, Number(availability.held_spaces || 0));
    const checkoutHeldSeats = getActiveCheckoutHeldSeatsForSlot(
        availability.activity_id,
        availability.date,
        availability.time
    );
    const totalHeldSeats = heldSpaces + checkoutHeldSeats;

    return {
        id: availability.id,
        activity_id: availability.activity_id,
        date: availability.date,
        time: availability.time,
        capacity: Number(availability.capacity || 0),
        available,
        actualAvailable: available,
        calculated_available: Math.max(0, available - totalHeldSeats),
        held_spaces: heldSpaces,
        adminHeldSpaces: heldSpaces,
        checkoutHeldSeats,
        heldSeats: totalHeldSeats,
        public_available: Math.max(0, available - totalHeldSeats),
        status: availability.status
    };
};

// Hold spaces on an availability without deleting the underlying spaces.
app.patch('/api/availability/:id/hold-spaces', (req, res) => {
    const { id } = req.params;
    const spaces = normalizeHoldSpaces(req.body?.spaces);

    if (!id) {
        return res.status(400).json({ success: false, message: 'Missing availability id' });
    }

    if (!Number.isInteger(spaces) || spaces <= 0) {
        return res.status(400).json({ success: false, message: 'Spaces must be a positive whole number' });
    }

    const selectSql = `
        SELECT id, activity_id, DATE_FORMAT(date, '%Y-%m-%d') as date, time, capacity, available, held_spaces, status
        FROM activity_availability
        WHERE id = ?
        LIMIT 1
    `;

    con.query(selectSql, [id], (selectErr, rows) => {
        if (selectErr) {
            console.error('Error loading availability before holding spaces:', selectErr);
            return res.status(500).json({ success: false, message: 'Database error', error: selectErr });
        }

        if (!rows || rows.length === 0) {
            return res.status(404).json({ success: false, message: 'Availability not found' });
        }

        const availability = rows[0];
        const available = Math.max(0, Number(availability.available || 0));
        const currentHeldSpaces = Math.max(0, Number(availability.held_spaces || 0));
        const activeCheckoutHeldSeats = getActiveCheckoutHeldSeatsForSlot(
            availability.activity_id,
            availability.date,
            availability.time
        );
        const remainingSpaces = Math.max(0, available - currentHeldSpaces - activeCheckoutHeldSeats);

        if (spaces > remainingSpaces) {
            return res.status(400).json({
                success: false,
                message: `Cannot hold ${spaces} space${spaces === 1 ? '' : 's'}; only ${remainingSpaces} available to hold.`,
                data: buildHoldSpacesPayload(availability)
            });
        }

        const nextHeldSpaces = currentHeldSpaces + spaces;
        const updateSql = `
            UPDATE activity_availability
            SET held_spaces = COALESCE(held_spaces, 0) + ?
            WHERE id = ?
              AND COALESCE(held_spaces, 0) + ? <= GREATEST(available - ?, 0)
        `;

        con.query(updateSql, [spaces, id, spaces, activeCheckoutHeldSeats], (updateErr, updateResult) => {
            if (updateErr) {
                console.error('Error holding availability spaces:', updateErr);
                return res.status(500).json({ success: false, message: 'Database error', error: updateErr });
            }

            if (!updateResult || updateResult.affectedRows === 0) {
                return res.status(409).json({
                    success: false,
                    message: 'Availability changed while holding spaces. Please refresh and try again.',
                    data: buildHoldSpacesPayload(availability)
                });
            }

            res.json({
                success: true,
                message: `${spaces} space${spaces === 1 ? '' : 's'} held`,
                data: buildHoldSpacesPayload({
                    ...availability,
                    held_spaces: nextHeldSpaces
                })
            });
        });
    });
});

// Release held spaces so they return to public availability.
app.patch('/api/availability/:id/release-held-spaces', (req, res) => {
    const { id } = req.params;
    const requestedSpaces = req.body?.spaces === undefined || req.body?.spaces === null || req.body?.spaces === ''
        ? null
        : normalizeHoldSpaces(req.body.spaces);

    if (!id) {
        return res.status(400).json({ success: false, message: 'Missing availability id' });
    }

    if (requestedSpaces !== null && (!Number.isInteger(requestedSpaces) || requestedSpaces <= 0)) {
        return res.status(400).json({ success: false, message: 'Spaces must be a positive whole number' });
    }

    const selectSql = `
        SELECT id, activity_id, DATE_FORMAT(date, '%Y-%m-%d') as date, time, capacity, available, held_spaces, status
        FROM activity_availability
        WHERE id = ?
        LIMIT 1
    `;

    con.query(selectSql, [id], (selectErr, rows) => {
        if (selectErr) {
            console.error('Error loading availability before releasing held spaces:', selectErr);
            return res.status(500).json({ success: false, message: 'Database error', error: selectErr });
        }

        if (!rows || rows.length === 0) {
            return res.status(404).json({ success: false, message: 'Availability not found' });
        }

        const availability = rows[0];
        const currentHeldSpaces = Math.max(0, Number(availability.held_spaces || 0));
        const spacesToRelease = requestedSpaces === null ? currentHeldSpaces : requestedSpaces;

        if (currentHeldSpaces <= 0) {
            return res.status(400).json({
                success: false,
                message: 'This availability has no held spaces to release.',
                data: buildHoldSpacesPayload(availability)
            });
        }

        if (spacesToRelease > currentHeldSpaces) {
            return res.status(400).json({
                success: false,
                message: `Cannot release ${spacesToRelease} space${spacesToRelease === 1 ? '' : 's'}; only ${currentHeldSpaces} held.`,
                data: buildHoldSpacesPayload(availability)
            });
        }

        const nextHeldSpaces = Math.max(0, currentHeldSpaces - spacesToRelease);
        const updateSql = `
            UPDATE activity_availability
            SET held_spaces = GREATEST(COALESCE(held_spaces, 0) - ?, 0)
            WHERE id = ?
              AND COALESCE(held_spaces, 0) >= ?
        `;

        con.query(updateSql, [spacesToRelease, id, spacesToRelease], (updateErr, updateResult) => {
            if (updateErr) {
                console.error('Error releasing availability held spaces:', updateErr);
                return res.status(500).json({ success: false, message: 'Database error', error: updateErr });
            }

            if (!updateResult || updateResult.affectedRows === 0) {
                return res.status(409).json({
                    success: false,
                    message: 'Held spaces changed while releasing. Please refresh and try again.',
                    data: buildHoldSpacesPayload(availability)
                });
            }

            res.json({
                success: true,
                message: `${spacesToRelease} held space${spacesToRelease === 1 ? '' : 's'} released`,
                data: buildHoldSpacesPayload({
                    ...availability,
                    held_spaces: nextHeldSpaces
                })
            });
        });
    });
});

// Update availability flight types and voucher types
app.patch('/api/availability/:id/flight-types', (req, res) => {
    const { id } = req.params;
    const { flight_types, voucher_types } = req.body;

    if (!id) {
        return res.status(400).json({ success: false, message: 'Missing availability id' });
    }

    // Build update query dynamically based on provided fields
    const updates = [];
    const values = [];

    if (flight_types !== undefined) {
        updates.push('flight_types = ?');
        values.push(flight_types);
    }

    if (voucher_types !== undefined) {
        updates.push('voucher_types = ?');
        values.push(voucher_types || null);
    }

    if (updates.length === 0) {
        return res.status(400).json({ success: false, message: 'No fields to update' });
    }

    const selectSql = `
        SELECT id, hidden_flight_types, hidden_voucher_types, flight_types, voucher_types
        FROM activity_availability
        WHERE id = ?
        LIMIT 1
    `;

    con.query(selectSql, [id], (selectErr, rows) => {
        if (selectErr) {
            console.error('Error loading availability before flight type update:', selectErr);
            return res.status(500).json({ success: false, message: 'Database error', error: selectErr });
        }

        if (!rows || rows.length === 0) {
            return res.status(404).json({ success: false, message: 'Availability not found' });
        }

        const currentAvailability = rows[0];
        const nextFlightTypes = flight_types !== undefined ? flight_types : currentAvailability.flight_types;
        const nextVoucherTypes = voucher_types !== undefined ? voucher_types : currentAvailability.voucher_types;
        const prunedHiddenTypes = pruneHiddenAvailabilityTypes({
            flightTypes: nextFlightTypes,
            voucherTypes: nextVoucherTypes,
            hiddenFlightTypes: currentAvailability.hidden_flight_types,
            hiddenVoucherTypes: currentAvailability.hidden_voucher_types
        });

        updates.push('hidden_flight_types = ?');
        values.push(prunedHiddenTypes.hiddenFlightTypes);
        updates.push('hidden_voucher_types = ?');
        values.push(prunedHiddenTypes.hiddenVoucherTypes);
        values.push(id);

        const sql = `UPDATE activity_availability SET ${updates.join(', ')} WHERE id = ?`;

        con.query(sql, values, (err, result) => {
            if (err) {
                console.error('Error updating availability flight types:', err);
                return res.status(500).json({ success: false, message: 'Database error', error: err });
            }

            res.json({
                success: true,
                message: 'Availability flight types updated successfully',
                data: {
                    id,
                    flight_types: nextFlightTypes,
                    voucher_types: nextVoucherTypes,
                    hidden_flight_types: prunedHiddenTypes.hiddenFlightTypes,
                    hidden_voucher_types: prunedHiddenTypes.hiddenVoucherTypes
                }
            });
        });
    });
});

// Hide or restore specific experience types for an availability without deleting the slot.
app.patch('/api/availability/:id/hidden-types', (req, res) => {
    const { id } = req.params;
    const action = String(req.body?.action || '').trim().toLowerCase();
    const experienceTypes = Array.isArray(req.body?.experience_types)
        ? req.body.experience_types
        : (Array.isArray(req.body?.experienceTypes) ? req.body.experienceTypes : []);

    if (!id) {
        return res.status(400).json({ success: false, message: 'Missing availability id' });
    }

    if (action !== 'hide' && action !== 'show') {
        return res.status(400).json({ success: false, message: 'Action must be "hide" or "show"' });
    }

    if (!experienceTypes.length) {
        return res.status(400).json({ success: false, message: 'At least one experience type is required' });
    }

    const selectSql = `
        SELECT id, hidden_flight_types, hidden_voucher_types
        FROM activity_availability
        WHERE id = ?
        LIMIT 1
    `;

    con.query(selectSql, [id], (selectErr, rows) => {
        if (selectErr) {
            console.error('Error loading availability visibility:', selectErr);
            return res.status(500).json({ success: false, message: 'Database error', error: selectErr });
        }

        if (!rows || rows.length === 0) {
            return res.status(404).json({ success: false, message: 'Availability not found' });
        }

        const currentAvailability = rows[0];
        const nextHiddenTypes = applyExperienceTypesToAvailabilityHiddenLists({
            currentHiddenFlightTypes: currentAvailability.hidden_flight_types,
            currentHiddenVoucherTypes: currentAvailability.hidden_voucher_types,
            experienceTypes,
            action
        });

        const updateSql = `
            UPDATE activity_availability
            SET hidden_flight_types = ?, hidden_voucher_types = ?
            WHERE id = ?
        `;

        con.query(
            updateSql,
            [nextHiddenTypes.hiddenFlightTypes, nextHiddenTypes.hiddenVoucherTypes, id],
            (updateErr) => {
                if (updateErr) {
                    console.error('Error updating availability visibility:', updateErr);
                    return res.status(500).json({ success: false, message: 'Database error', error: updateErr });
                }

                res.json({
                    success: true,
                    message: action === 'hide'
                        ? 'Availability experience types hidden successfully'
                        : 'Availability experience types restored successfully',
                    data: {
                        id,
                        hidden_flight_types: nextHiddenTypes.hiddenFlightTypes,
                        hidden_voucher_types: nextHiddenTypes.hiddenVoucherTypes
                    }
                });
            }
        );
    });
});

// Auto-update availability status based on available count
app.post('/api/updateAvailabilityStatus', (req, res) => {
    const sql = `
        UPDATE activity_availability 
        SET status = CASE 
            WHEN available = 0 THEN 'Closed'
            WHEN available > 0 THEN 'Open'
            ELSE status
        END
        WHERE available = 0 OR available > 0
    `;

    con.query(sql, (err, result) => {
        if (err) {
            console.error('Error auto-updating availability status:', err);
            return res.status(500).json({ success: false, message: 'Database error', error: err });
        }

        res.json({
            success: true,
            message: 'Availability statuses updated automatically',
            affectedRows: result.affectedRows
        });
    });
});

// Auto-update availability status for a specific activity based on booking count
app.post('/api/activity/:id/updateAvailabilityStatus', (req, res) => {
    const { id } = req.params;
    if (!id) return res.status(400).json({ success: false, message: 'Missing activity ID' });

    const sql = `
        UPDATE activity_availability aa
        JOIN (
            SELECT 
                DATE(ab.flight_date) as flight_date,
                TIME_FORMAT(TIME(COALESCE(ab.time_slot, ab.flight_date)), '%H:%i') as flight_time_min,
                COALESCE(SUM(ab.pax), 0) as total_booked,
                COALESCE(SUM(
                    CASE 
                        WHEN (LOWER(COALESCE(ab.experience, ab.flight_type)) LIKE '%private%')
                             AND COALESCE(ab.pax, 0) > 4 THEN ${BALLOON_210_CAPACITY}
                        WHEN (LOWER(COALESCE(ab.experience, ab.flight_type)) LIKE '%private%')
                             AND COALESCE(ab.pax, 0) <= 4 THEN 0
                        ELSE COALESCE(ab.pax, 0)
                    END
                ), 0) as shared_consumed_pax,
                COALESCE(SUM(
                    CASE 
                        WHEN (LOWER(COALESCE(ab.experience, ab.flight_type)) LIKE '%private%')
                             AND COALESCE(ab.pax, 0) <= 4 THEN 1
                        ELSE 0
                    END
                ), 0) as private_small_bookings
            FROM all_booking ab
            WHERE DATE(ab.flight_date) >= CURDATE() - INTERVAL 30 DAY
            AND (ab.status IS NULL OR TRIM(LOWER(ab.status)) NOT IN ('cancelled'))
            AND (ab.manual_status_override IS NULL OR TRIM(LOWER(ab.manual_status_override)) NOT IN ('cancelled'))
            GROUP BY DATE(ab.flight_date), TIME_FORMAT(TIME(COALESCE(ab.time_slot, ab.flight_date)), '%H:%i')
        ) as booking_counts ON 
            DATE(aa.date) = booking_counts.flight_date AND
            TIME_FORMAT(TIME(aa.time), '%H:%i') = booking_counts.flight_time_min
        SET 
            aa.status = CASE 
                WHEN booking_counts.private_small_bookings > 0 THEN 'Closed'
                WHEN booking_counts.shared_consumed_pax >= LEAST(aa.capacity, ${BALLOON_210_CAPACITY}) THEN 'Closed'
                ELSE 'Open'
            END,
            aa.available = CASE 
                WHEN booking_counts.private_small_bookings > 0 THEN 0
                ELSE GREATEST(0, LEAST(aa.capacity, ${BALLOON_210_CAPACITY}) - booking_counts.shared_consumed_pax)
            END,
            aa.booked = booking_counts.total_booked
        WHERE aa.activity_id = ?
    `;

    console.log(`Updating availability status for activity ${id}`);

    con.query(sql, [id], (err, result) => {
        if (err) {
            console.error('Error updating availability status for activity:', err);
            return res.status(500).json({ success: false, message: 'Database error', error: err });
        }

        console.log(`Updated ${result.affectedRows} availability statuses for activity ${id}`);
        res.json({
            success: true,
            message: `Updated ${result.affectedRows} availability statuses for activity ${id}`,
            affectedRows: result.affectedRows
        });
    });
});

// Get activity open availabilities
app.get('/api/activity/:id/open-availabilities', (req, res) => {
    const { id } = req.params;
    if (!id) return res.status(400).json({ success: false, message: 'Eksik bilgi!' });
    // Sadece status = 'Open' olanları al
    const sql = 'SELECT date, time FROM activity_availability WHERE activity_id = ? AND status = "Open" ORDER BY date, time';
    con.query(sql, [id], (err, result) => {
        if (err) return res.status(500).json({ success: false, message: 'Database error', error: err });
        // Gün ve saatleri grupla
        const grouped = {};
        result.forEach(row => {
            if (!grouped[row.date]) grouped[row.date] = [];
            grouped[row.date].push(row.time);
        });
        // { date: '2025-07-03', times: ['09:00', '18:00'] } formatına çevir
        const data = Object.entries(grouped).map(([date, times]) => ({ date, times }));
        res.json({ success: true, data });
    });
});

