// Get flown flights (completed flights) - Similar to getAllBookingData
// Use derived table + LEFT JOIN trip_booking to avoid MySQL "Invalid use of group function" with MIN() in correlated subqueries
const FLIGHT_OPERATION_TIME_ZONE = 'Europe/London';
const OPERATIONAL_TIME_ONLY_REGEX = /^(\d{1,2}):(\d{2})(?::(\d{2}))?$/;
const OPERATIONAL_LOCAL_DATETIME_REGEX = /^(\d{4}-\d{2}-\d{2})[ T]((?:\d{1,2}):\d{2}(?::\d{2})?)$/;
const OPERATIONAL_DATE_TIME_FORMATS = [
    'YYYY-MM-DD HH:mm:ss',
    'YYYY-MM-DD HH:mm',
    'YYYY-MM-DDTHH:mm:ss.SSS',
    'YYYY-MM-DDTHH:mm:ss',
    'YYYY-MM-DDTHH:mm',
    'DD/MM/YYYY HH:mm:ss',
    'DD/MM/YYYY HH:mm',
    'HH:mm:ss',
    'HH:mm',
    moment.ISO_8601
];
const operationalLondonTimeFormatter = new Intl.DateTimeFormat('en-GB', {
    timeZone: FLIGHT_OPERATION_TIME_ZONE,
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false
});

const padOperationalTimePart = (value) => String(value).padStart(2, '0');

const parseOperationalDateTime = (value) => {
    if (value === null || value === undefined || value === '') return null;

    const strictParsed = moment(value, OPERATIONAL_DATE_TIME_FORMATS, true);
    if (strictParsed.isValid()) {
        return strictParsed;
    }

    const looseParsed = moment(value);
    return looseParsed.isValid() ? looseParsed : null;
};

const normalizeOperationalWallClockTime = (value) => {
    if (value === null || value === undefined || value === '') return null;

    if (typeof value === 'string') {
        const trimmed = value.trim();
        if (!trimmed) return null;

        const timeOnlyMatch = trimmed.match(OPERATIONAL_TIME_ONLY_REGEX);
        if (timeOnlyMatch) {
            return [
                padOperationalTimePart(timeOnlyMatch[1]),
                padOperationalTimePart(timeOnlyMatch[2]),
                padOperationalTimePart(timeOnlyMatch[3] || '00')
            ].join(':');
        }

        const localDateTimeMatch = trimmed.match(OPERATIONAL_LOCAL_DATETIME_REGEX);
        if (localDateTimeMatch) {
            return normalizeOperationalWallClockTime(localDateTimeMatch[2]);
        }

        const hasExplicitTimezone =
            /Z$/i.test(trimmed) ||
            /[+-]\d{2}:?\d{2}$/.test(trimmed) ||
            /\bGMT\b/i.test(trimmed) ||
            /\bUTC\b/i.test(trimmed);

        if (hasExplicitTimezone) {
            const asDate = new Date(trimmed);
            if (!Number.isNaN(asDate.getTime())) {
                return operationalLondonTimeFormatter.format(asDate);
            }
        }
    }

    if (value instanceof Date) {
        return Number.isNaN(value.getTime()) ? null : operationalLondonTimeFormatter.format(value);
    }

    const parsedMoment = parseOperationalDateTime(value);
    return parsedMoment ? parsedMoment.format('HH:mm:ss') : null;
};

app.get('/api/flown-flights', (req, res) => {
    const flownFlightSlotTimeSql = `
        COALESCE(
            TIME_FORMAT(STR_TO_DATE(NULLIF(ab.time_slot, ''), '%H:%i:%s'), '%H:%i:%s'),
            TIME_FORMAT(STR_TO_DATE(NULLIF(ab.time_slot, ''), '%H:%i'), '%H:%i:%s'),
            TIME_FORMAT(ab.flight_date, '%H:%i:%s')
        )
    `;

    const sql = `
        SELECT 
            g.id,
            g.name,
            g.email,
            g.phone,
            g.flight_date,
            g.flight_date_display,
            g.location,
            g.flight_type,
            g.status,
            g.created_at,
            g.created_at_display,
            g.voucher_type,
            g.voucher_code,
            g.flight_attempts,
            g.expires,
            g.paid,
            g.due,
            g.activity_id,
            g.pax,
            g.passenger_count,
            g.flight_date_only,
            g.flight_time_only,
            g.booking_ids,
            tb.refuel_location,
            tb.land_owner_gift,
            tb.landing_fee,
            tb.vehicle_used,
            tb.aircraft_defects,
            tb.vehicle_trailer_defects,
            DATE_FORMAT(tb.flight_start_time, '%Y-%m-%d %H:%i:%s') as flight_start_time,
            DATE_FORMAT(tb.flight_end_time, '%Y-%m-%d %H:%i:%s') as flight_end_time,
            tb.additional_fields,
            (SELECT CONCAT(pt.first_name, ' ', pt.last_name) 
             FROM flight_pilot_assignments fpa
             LEFT JOIN pilots pt ON pt.id = fpa.pilot_id
             WHERE g.activity_id IS NOT NULL
               AND g.flight_date IS NOT NULL
               AND fpa.activity_id = g.activity_id
               AND fpa.date = DATE(g.flight_date)
               AND fpa.time = TIME(g.flight_date)
             LIMIT 1) as pilot_name,
            (SELECT CONCAT(c.first_name, ' ', c.last_name) 
             FROM flight_crew_assignments fca
             LEFT JOIN crew c ON c.id = fca.crew_id
             WHERE g.activity_id IS NOT NULL
               AND g.flight_date IS NOT NULL
               AND fca.activity_id = g.activity_id
               AND fca.date = DATE(g.flight_date)
               AND fca.time = TIME(g.flight_date)
             LIMIT 1) as crew_name
        FROM (
            SELECT 
                MIN(f.id) as id,
                MIN(f.name) as name,
                MIN(f.email) as email,
                MIN(f.phone) as phone,
                MIN(f.slot_datetime) as flight_date,
                MIN(f.slot_datetime) as flight_date_display,
                f.location,
                f.flight_type,
                MIN(f.status) as status,
                MIN(f.created_at) as created_at,
                MIN(f.created_at) as created_at_display,
                MIN(f.voucher_type) as voucher_type,
                MIN(f.voucher_code) as voucher_code,
                MIN(f.flight_attempts) as flight_attempts,
                MIN(f.expires) as expires,
                SUM(COALESCE(f.paid, 0)) as paid,
                SUM(COALESCE(f.due, 0)) as due,
                MIN(f.activity_id) as activity_id,
                SUM(
                    CASE 
                        WHEN f.pax IS NOT NULL AND f.pax > 0 THEN f.pax
                        ELSE (SELECT COUNT(*) FROM passenger p2 WHERE p2.booking_id = f.id)
                    END
                ) as pax,
                SUM(
                    CASE 
                        WHEN f.pax IS NOT NULL AND f.pax > 0 THEN f.pax
                        ELSE (SELECT COUNT(*) FROM passenger p2 WHERE p2.booking_id = f.id)
                    END
                ) as passenger_count,
                f.slot_date as flight_date_only,
                f.slot_time as flight_time_only,
                GROUP_CONCAT(DISTINCT f.id ORDER BY f.id SEPARATOR ', ') as booking_ids
            FROM (
                SELECT
                    ab.*,
                    DATE(ab.flight_date) as slot_date,
                    ${flownFlightSlotTimeSql} as slot_time,
                    CASE
                        WHEN ab.flight_date IS NULL THEN NULL
                        WHEN ${flownFlightSlotTimeSql} IS NULL THEN ab.flight_date
                        ELSE TIMESTAMP(DATE(ab.flight_date), ${flownFlightSlotTimeSql})
                    END as slot_datetime
                FROM all_booking ab
                WHERE ab.status = 'Flown'
            ) f
            GROUP BY f.slot_date, f.slot_time, f.location, f.flight_type
        ) g
        LEFT JOIN trip_booking tb ON tb.booking_id = (
            SELECT tb2.booking_id
            FROM trip_booking tb2
            WHERE FIND_IN_SET(tb2.booking_id, REPLACE(g.booking_ids, ' ', '')) > 0
            ORDER BY (tb2.flight_start_time IS NOT NULL AND tb2.flight_end_time IS NOT NULL) DESC,
                     tb2.refuel_location IS NOT NULL DESC,
                     tb2.booking_id ASC
            LIMIT 1
        )
        ORDER BY g.flight_date DESC, g.created_at DESC
    `;

    con.query(sql, (err, results) => {
        if (err) {
            console.error('Error fetching flown flights:', err);
            return res.status(500).json({ success: false, message: 'Error fetching flown flights' });
        }
        
        // Get operational selection fields from settings to know which columns to include
        con.query('SELECT DISTINCT field_name FROM operational_selections ORDER BY field_name', (fieldErr, fieldResults) => {
            const operationalFields = fieldResults && fieldResults.length > 0 
                ? fieldResults.map(r => r.field_name)
                : ['Refuel Location', 'Land Owner Gift', 'Landing Fee', 'Vehicle Used'];
            
            // Format the results similar to getAllBookingData
            const formatted = results.map(row => {
                const flightDateMoment = parseOperationalDateTime(row.flight_date);
                const flightStartMoment = parseOperationalDateTime(row.flight_start_time);
                const flightEndMoment = parseOperationalDateTime(row.flight_end_time);

                // Format flight_date as DD/MM/YYYY AM/PM if time exists (for display only)
                let flightDateFormatted = '';
                if (flightDateMoment) {
                    const hour = flightDateMoment.hour();
                    const minute = flightDateMoment.minute();
                    const displayHour = hour === 0 ? 12 : (hour > 12 ? hour - 12 : hour);
                    const ampm = hour < 12 ? 'AM' : 'PM';
                    flightDateFormatted =
                        flightDateMoment.format('DD/MM/YYYY') +
                        ' ' +
                        displayHour +
                        ':' +
                        (minute < 10 ? '0' : '') +
                        minute +
                        ' ' +
                        ampm;
                } else if (row.flight_date) {
                    flightDateFormatted = typeof row.flight_date === 'string'
                        ? row.flight_date
                        : moment(row.flight_date).format('DD/MM/YYYY h:mm A');
                }

                // Determine flight period (AM / PM)
                // Priority: operational flight_start_time from trip_booking; fallback to booking flight_date
                let flightPeriod = '';
                if (flightStartMoment) {
                    const hour = flightStartMoment.hour();
                    flightPeriod = hour < 12 ? 'AM' : 'PM';
                }
                if (!flightPeriod && flightDateMoment) {
                    const hour = flightDateMoment.hour();
                    flightPeriod = hour < 12 ? 'AM' : 'PM';
                }

                let totalFlightTime = null;
                if (flightStartMoment && flightEndMoment) {
                    const duration = moment.duration(flightEndMoment.diff(flightStartMoment));
                    const hours = Math.floor(duration.asHours());
                    const minutes = duration.minutes();
                    totalFlightTime = hours > 0 ? `${hours}h ${minutes}m` : `${minutes}m`;
                }

                const dutyStartTime = flightStartMoment
                    ? flightStartMoment.clone().subtract(45, 'minutes').format('DD/MM/YYYY HH:mm')
                    : null;

                const dutyEndTime = flightEndMoment
                    ? flightEndMoment.clone().add(45, 'minutes').format('DD/MM/YYYY HH:mm')
                    : null;

                let dutyTime = null;
                if (flightStartMoment && flightEndMoment) {
                    const dutyStart = flightStartMoment.clone().subtract(45, 'minutes');
                    const dutyEnd = flightEndMoment.clone().add(45, 'minutes');
                    const duration = moment.duration(dutyEnd.diff(dutyStart));
                    const hours = Math.floor(duration.asHours());
                    const minutes = duration.minutes();
                    dutyTime = hours > 0 ? `${hours}h ${minutes}m` : `${minutes}m`;
                }

                // Format flight_type to show Private or Shared
                let flightTypeDisplay = '';
                if (row.flight_type) {
                    const flightTypeLower = row.flight_type.toLowerCase();
                    if (flightTypeLower.includes('private')) {
                        flightTypeDisplay = 'Private';
                    } else if (flightTypeLower.includes('shared')) {
                        flightTypeDisplay = 'Shared';
                    } else {
                        flightTypeDisplay = row.flight_type; // Keep original if not matching
                    }
                }

                // Parse additional_fields JSON if exists
                let additionalFieldsParsed = {};
                if (row.additional_fields) {
                    try {
                        additionalFieldsParsed = typeof row.additional_fields === 'string' 
                            ? JSON.parse(row.additional_fields) 
                            : row.additional_fields;
                    } catch (e) {
                        console.warn('Failed to parse additional_fields:', e);
                    }
                }

                // Build operational selections object
                const operationalSelections = {
                    'Refuel Location': row.refuel_location || '',
                    'Land Owner Gift': row.land_owner_gift || '',
                    'Landing Fee': row.landing_fee || '',
                    'Vehicle Used': row.vehicle_used || '',
                    ...additionalFieldsParsed
                };

                // Calculate balloon resource
                let balloonResource = 'N/A';
                try {
                    const mockBooking = {
                        experience: row.flight_type,
                        flight_type: row.flight_type,
                        pax: row.pax || row.passenger_count || 0,
                        passenger_count: row.pax || row.passenger_count || 0
                    };
                    const resourceInfo = getAssignedResourceInfo(mockBooking);
                    if (resourceInfo && resourceInfo.resourceName) {
                        // Extract number from "Balloon 210" or "Balloon 105"
                        const match = resourceInfo.resourceName.match(/(\d+)/);
                        if (match) {
                            balloonResource = match[1]; // Returns "210" or "105"
                        } else {
                            balloonResource = resourceInfo.resourceName;
                        }
                    }
                } catch (e) {
                    console.warn('Error calculating balloon resource:', e);
                }

                return {
                    ...row,
                    booking_ids: row.booking_ids || row.id || '', // Comma-separated booking IDs
                    flight_date_display: flightDateFormatted,
                    created_at_display: row.created_at ? moment(row.created_at).format('DD/MM/YYYY') : '',
                    pax: row.pax || row.passenger_count || 0,
                    status: row.status || 'Flown',
                    operational_selections: operationalSelections,
                    operational_fields: operationalFields,
                    pilot: row.pilot_name || '-',
                    crew: row.crew_name || '-',
                    flight_period: flightPeriod || '-',
                    flight_type_display: flightTypeDisplay || '-',
                    aircraft_defects: row.aircraft_defects || '',
                    vehicle_trailer_defects: row.vehicle_trailer_defects || '',
                    balloon_resource: balloonResource,
                    flight_start_time: flightStartMoment ? flightStartMoment.format('DD/MM/YYYY HH:mm') : null,
                    flight_end_time: flightEndMoment ? flightEndMoment.format('DD/MM/YYYY HH:mm') : null,
                    total_flight_time: totalFlightTime,
                    duty_start_time: dutyStartTime,
                    duty_end_time: dutyEndTime,
                    duty_time: dutyTime
                };
            });
            
            res.json({ success: true, data: formatted, operational_fields: operationalFields });
        });
    });
});

// Save flight operational selections to trip_booking
// Create trip_booking table if it doesn't exist
con.query(`
    CREATE TABLE IF NOT EXISTS trip_booking (
        id INT AUTO_INCREMENT PRIMARY KEY,
        booking_id INT NOT NULL,
        refuel_location VARCHAR(500),
        land_owner_gift VARCHAR(500),
        landing_fee VARCHAR(500),
        vehicle_used VARCHAR(500),
        aircraft_defects TEXT,
        vehicle_trailer_defects TEXT,
        additional_fields JSON,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
        INDEX idx_booking_id (booking_id),
        FOREIGN KEY (booking_id) REFERENCES all_booking(id) ON DELETE CASCADE
    ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
`, (err) => {
    if (err) {
        console.error('Error creating trip_booking table:', err);
    } else {
        console.log('trip_booking table ready');
        // Add new columns if they don't exist
        con.query(`SHOW COLUMNS FROM trip_booking LIKE 'aircraft_defects'`, (err, results) => {
            if (err) {
                console.error('Error checking aircraft_defects column:', err);
            } else if (results.length === 0) {
                con.query(`ALTER TABLE trip_booking ADD COLUMN aircraft_defects TEXT`, (alterErr) => {
                    if (alterErr) {
                        console.error('Error adding aircraft_defects column:', alterErr);
                    } else {
                        console.log('aircraft_defects column added');
                    }
                });
            }
        });
        
        con.query(`SHOW COLUMNS FROM trip_booking LIKE 'vehicle_trailer_defects'`, (err, results) => {
            if (err) {
                console.error('Error checking vehicle_trailer_defects column:', err);
            } else if (results.length === 0) {
                con.query(`ALTER TABLE trip_booking ADD COLUMN vehicle_trailer_defects TEXT`, (alterErr) => {
                    if (alterErr) {
                        console.error('Error adding vehicle_trailer_defects column:', alterErr);
                    } else {
                        console.log('vehicle_trailer_defects column added');
                    }
                });
            }
        });
        
        con.query(`SHOW COLUMNS FROM trip_booking LIKE 'flight_start_time'`, (err, results) => {
            if (err) {
                console.error('Error checking flight_start_time column:', err);
            } else if (results.length === 0) {
                con.query(`ALTER TABLE trip_booking ADD COLUMN flight_start_time DATETIME`, (alterErr) => {
                    if (alterErr) {
                        console.error('Error adding flight_start_time column:', alterErr);
                    } else {
                        console.log('flight_start_time column added');
                    }
                });
            }
        });
        
        con.query(`SHOW COLUMNS FROM trip_booking LIKE 'flight_end_time'`, (err, results) => {
            if (err) {
                console.error('Error checking flight_end_time column:', err);
            } else if (results.length === 0) {
                con.query(`ALTER TABLE trip_booking ADD COLUMN flight_end_time DATETIME`, (alterErr) => {
                    if (alterErr) {
                        console.error('Error adding flight_end_time column:', alterErr);
                    } else {
                        console.log('flight_end_time column added');
                    }
                });
            }
        });
    }
});

app.post('/api/save-flight-operational-selections', (req, res) => {
    const { booking_id, operational_selections, aircraft_defects, vehicle_trailer_defects, flight_start_time, flight_end_time } = req.body;

    if (!booking_id) {
        return res.status(400).json({ success: false, message: 'Booking ID is required' });
    }

    // Prepare data for trip_booking table
    const refuelLocation = operational_selections && operational_selections['Refuel Location'] ? operational_selections['Refuel Location'] : null;
    const landOwnerGift = operational_selections && operational_selections['Land Owner Gift'] ? operational_selections['Land Owner Gift'] : null;
    const landingFee = operational_selections && operational_selections['Landing Fee'] ? operational_selections['Landing Fee'] : null;
    const vehicleUsed = operational_selections && operational_selections['Vehicle Used'] ? operational_selections['Vehicle Used'] : null;
    const aircraftDefects = aircraft_defects || null;
    const vehicleTrailerDefects = vehicle_trailer_defects || null;
    
    // Get the flight date as a timezone-less YYYY-MM-DD string so operational times
    // can be stored as exact wall-clock values without server/browser offset drift.
    con.query(`SELECT DATE_FORMAT(flight_date, '%Y-%m-%d') AS flight_date_only FROM all_booking WHERE id = ?`, [booking_id], (err, bookingResult) => {
        if (err) {
            console.error('Error fetching booking flight_date:', err);
            return res.status(500).json({ success: false, message: 'Error fetching booking information' });
        }
        
        if (bookingResult.length === 0) {
            return res.status(404).json({ success: false, message: 'Booking not found' });
        }
        
        const flightDateStr = bookingResult[0].flight_date_only || null;
        
        // Combine date from flight_date and time for flight_start_time and flight_end_time
        let flightStartTime = null;
        if (flightDateStr && flight_start_time) {
            try {
                const startTime = normalizeOperationalWallClockTime(flight_start_time);
                if (startTime) {
                    flightStartTime = `${flightDateStr} ${startTime}`;
                }
            } catch (e) {
                console.warn('Error parsing flight_start_time:', e);
            }
        }
        
        let flightEndTime = null;
        if (flightDateStr && flight_end_time) {
            try {
                const endTime = normalizeOperationalWallClockTime(flight_end_time);
                if (endTime) {
                    flightEndTime = `${flightDateStr} ${endTime}`;
                }
            } catch (e) {
                console.warn('Error parsing flight_end_time:', e);
            }
        }
        
        // Store additional fields (non-default fields) in JSON
        const additionalFields = {};
        if (operational_selections) {
            Object.keys(operational_selections).forEach(key => {
                if (!['Refuel Location', 'Land Owner Gift', 'Landing Fee', 'Vehicle Used'].includes(key)) {
                    additionalFields[key] = operational_selections[key];
                }
            });
        }

        // Check if record exists
        con.query('SELECT id FROM trip_booking WHERE booking_id = ?', [booking_id], (err, existing) => {
            if (err) {
                console.error('Error checking existing trip_booking:', err);
                return res.status(500).json({ success: false, message: 'Error checking existing record' });
            }

            const additionalFieldsJson = Object.keys(additionalFields).length > 0 ? JSON.stringify(additionalFields) : null;

            if (existing.length > 0) {
                // Update existing record
                const updateSql = `
                    UPDATE trip_booking 
                    SET refuel_location = ?, 
                        land_owner_gift = ?, 
                        landing_fee = ?, 
                        vehicle_used = ?, 
                        aircraft_defects = ?,
                        vehicle_trailer_defects = ?,
                        flight_start_time = ?,
                        flight_end_time = ?,
                        additional_fields = ?,
                        updated_at = NOW()
                    WHERE booking_id = ?
                `;
                con.query(updateSql, [refuelLocation, landOwnerGift, landingFee, vehicleUsed, aircraftDefects, vehicleTrailerDefects, flightStartTime, flightEndTime, additionalFieldsJson, booking_id], (updateErr) => {
                    if (updateErr) {
                        console.error('Error updating trip_booking:', updateErr);
                        return res.status(500).json({ success: false, message: 'Error updating operational selections' });
                    }
                    res.json({ success: true, message: 'Operational selections updated successfully' });
                });
            } else {
                // Insert new record
                const insertSql = `
                    INSERT INTO trip_booking 
                    (booking_id, refuel_location, land_owner_gift, landing_fee, vehicle_used, aircraft_defects, vehicle_trailer_defects, flight_start_time, flight_end_time, additional_fields, created_at, updated_at)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), NOW())
                `;
                con.query(insertSql, [booking_id, refuelLocation, landOwnerGift, landingFee, vehicleUsed, aircraftDefects, vehicleTrailerDefects, flightStartTime, flightEndTime, additionalFieldsJson], (insertErr, result) => {
                    if (insertErr) {
                        console.error('Error inserting trip_booking:', insertErr);
                        return res.status(500).json({ success: false, message: 'Error saving operational selections' });
                    }
                    res.json({ success: true, id: result.insertId, message: 'Operational selections saved successfully' });
                });
            }
        });
    });
});

app.get(['/customerPortal/s/:shortCode', '/customerPortal/s/:shortCode/*'], (req, res) => {
    const shortCode = (req.params.shortCode || '').toString().trim().toLowerCase();

    if (!shortCode) {
        return res.status(400).send('Short code is required');
    }

    ensureCustomerPortalShortLinksSchema((schemaErr) => {
        if (schemaErr) {
            return res.status(500).send('Customer portal short links are not available');
        }

        con.query(
            'SELECT target_url FROM customer_portal_short_links WHERE short_code = ? LIMIT 1',
            [shortCode],
            (err, rows) => {
                if (err) {
                    console.error('Error resolving customer portal short link:', err);
                    return res.status(500).send('Failed to resolve short link');
                }

                if (!rows || rows.length === 0 || !rows[0].target_url) {
                    return resolveCustomerPortalShortLinkByData(shortCode, (rebuildErr, rebuiltMatch) => {
                        if (rebuildErr) {
                            console.error('Error rebuilding customer portal short link:', rebuildErr);
                            return res.status(500).send('Failed to resolve short link');
                        }

                        if (!rebuiltMatch || rebuiltMatch.ambiguous || !rebuiltMatch.targetUrl) {
                            return res
                                .status(410)
                                .type('html')
                                .send(
                                    buildCustomerPortalShortLinkUnavailablePage({
                                        message:
                                            'This customer portal link has expired or is no longer available. Please use the latest link we sent you or contact Fly Away Ballooning for a new one.'
                                    })
                                );
                        }

                        persistCustomerPortalShortLink({
                            shortCode,
                            targetUrl: rebuiltMatch.targetUrl,
                            portalToken: rebuiltMatch.portalToken
                        });

                        return res.redirect(302, rebuiltMatch.targetUrl);
                    });
                }

                const targetUrl = String(rows[0].target_url).trim();

                con.query(
                    `
                        UPDATE customer_portal_short_links
                        SET click_count = click_count + 1, last_used_at = NOW()
                        WHERE short_code = ?
                    `,
                    [shortCode],
                    (updateErr) => {
                        if (updateErr) {
                            console.error('Error updating customer portal short link usage:', updateErr);
                        }
                    }
                );

                return res.redirect(302, targetUrl);
            }
        );
    });
});

// Generate and persist a customer portal short link for a booking or voucher
app.post('/api/customerPortalShortLink', (req, res) => {
    const { bookingId, contextType } = req.body;
    if (!bookingId) {
        return res.status(400).json({ success: false, message: 'bookingId is required' });
    }

    const isVoucher = contextType === 'voucher';
    const normalizedRecordId = isVoucher ? String(bookingId).trim().replace(/^voucher-/i, '') : bookingId;
    const query = isVoucher
        ? 'SELECT * FROM all_vouchers WHERE id = ? LIMIT 1'
        : 'SELECT * FROM all_booking WHERE id = ? LIMIT 1';

    con.query(query, [normalizedRecordId], (err, rows) => {
        if (err) {
            console.error('Error fetching record for portal link:', err);
            return res.status(500).json({ success: false, message: 'Database error' });
        }

        if (!rows || rows.length === 0) {
            return res.status(404).json({ success: false, message: 'Record not found' });
        }

        const record = rows[0];
        // For vouchers, add the _original and voucher_id fields
        const bookingData = isVoucher
            ? { ...record, voucher_id: record.id, _original: record }
            : record;

        const shortUrl = getCustomerPortalLink(bookingData);
        if (!shortUrl) {
            return res.status(500).json({ success: false, message: 'Failed to generate portal link' });
        }

        return res.json({ success: true, shortUrl });
    });
});

app.get(['/cp/:token', '/cp/:token/*'], (req, res) => {
    const token = sanitizeCustomerPortalToken(req.params.token || '');
    const targetUrl = buildCanonicalCustomerPortalTarget(token, extractUrlSuffix(req.originalUrl || ''));

    if (!targetUrl) {
        return res.status(404).send('Customer portal link not found');
    }

    return res.redirect(302, targetUrl);
});

