// Get activity pricing for a specific location
app.get('/api/locationPricing/:location', (req, res) => {
    const location = normalizeVoucherLocation(req.params.location);
    if (!location) return res.status(400).json({ success: false, message: 'Location is required' });

    const sql = `
        SELECT
            weekday_morning_price,
            weekday_morning_sale_price,
            flexible_weekday_price,
            flexible_weekday_sale_price,
            any_day_flight_price,
            any_day_flight_sale_price,
            shared_flight_from_price,
            shared_flight_from_sale_price,
            private_charter_from_price,
            private_charter_from_sale_price,
            flight_type
        FROM activity 
        WHERE location = ? AND status = 'Live'
        ORDER BY id ASC
        LIMIT 1
    `;
    con.query(sql, [location], (err, result) => {
        if (err) return res.status(500).json({ success: false, message: "Database error" });
        if (!result || result.length === 0) {
            return res.status(404).json({ success: false, message: "No pricing found for this location" });
        }

        const pricing = result[0];

        // Process flight_type to map to experience names
        let flightTypes = [];
        let experiences = [];
        if (pricing.flight_type) {
            if (typeof pricing.flight_type === 'string') {
                flightTypes = pricing.flight_type.split(',').map(type => type.trim());
            } else if (Array.isArray(pricing.flight_type)) {
                flightTypes = pricing.flight_type;
            }

            // Map flight types to experience names
            experiences = flightTypes.map(type => {
                if (type === 'Private') return 'Private Charter';
                if (type === 'Shared') return 'Shared Flight';
                return type; // Keep original if not mapped
            });
        }

        if (location === BRISTOL_LOCATION) {
            flightTypes = ['Private'];
            experiences = ['Private Charter'];
        }

        res.json({
            success: true,
            data: {
                weekday_morning_price: pricing.weekday_morning_price,
                weekday_morning_sale_price: formatSaleNumericPrice(pricing.weekday_morning_sale_price),
                flexible_weekday_price: pricing.flexible_weekday_price,
                flexible_weekday_sale_price: formatSaleNumericPrice(pricing.flexible_weekday_sale_price),
                any_day_flight_price: pricing.any_day_flight_price,
                any_day_flight_sale_price: formatSaleNumericPrice(pricing.any_day_flight_sale_price),
                shared_flight_from_price: pricing.shared_flight_from_price,
                shared_flight_from_sale_price: formatSaleNumericPrice(pricing.shared_flight_from_sale_price),
                private_charter_from_price: pricing.private_charter_from_price,
                private_charter_from_sale_price: formatSaleNumericPrice(pricing.private_charter_from_sale_price),
                flight_type: flightTypes,
                experiences: experiences
            }
        });
    });
});

// Get a single availability by activity, date and time (with hold consideration)
app.get('/api/availabilityBySlot', (req, res) => {
    const { activity_id, date, time } = req.query;
    if (!activity_id || !date || !time) {
        return res.status(400).json({ success: false, message: 'activity_id, date and time are required' });
    }
    const sql = 'SELECT id, capacity, available, held_spaces, status FROM activity_availability WHERE activity_id = ? AND DATE(date) = ? AND TIME(time) = ? LIMIT 1';
    con.query(sql, [activity_id, date, time], (err, rows) => {
        if (err) return res.status(500).json({ success: false, message: 'Database error' });
        if (!rows || rows.length === 0) return res.json({ success: true, data: null });

        const checkoutHeldSeats = getActiveCheckoutHeldSeatsForSlot(activity_id, date, time);
        const adminHeldSpaces = Math.max(0, Number(rows[0].held_spaces || 0));
        const totalHeldSeats = checkoutHeldSeats + adminHeldSpaces;

        // Return availability minus held seats
        const availabilityData = {
            ...rows[0],
            available: Math.max(0, rows[0].available - totalHeldSeats),
            actualAvailable: rows[0].available,
            heldSpaces: adminHeldSpaces,
            held_spaces: adminHeldSpaces,
            checkoutHeldSeats,
            heldSeats: totalHeldSeats
        };

        return res.json({ success: true, data: availabilityData });
    });
});

// Hold availability for a specific slot
app.post('/api/holdAvailability', (req, res) => {
    const { activity_id, date, time, seats, sessionId } = req.body;

    if (!activity_id || !date || !time || !seats || !sessionId) {
        return res.status(400).json({ success: false, message: 'Missing required fields' });
    }

    const seatsToHold = Number(seats);
    if (!Number.isInteger(seatsToHold) || seatsToHold <= 0) {
        return res.status(400).json({ success: false, message: 'Seats must be a positive whole number' });
    }

    const holdKey = `${activity_id}_${date}_${time}_${sessionId}`;

    const sql = 'SELECT id, available, held_spaces FROM activity_availability WHERE activity_id = ? AND DATE(date) = ? AND TIME(time) = ? LIMIT 1';
    con.query(sql, [activity_id, date, time], (err, rows) => {
        if (err) {
            console.error('Error validating availability hold:', err);
            return res.status(500).json({ success: false, message: 'Database error' });
        }

        if (!rows || rows.length === 0) {
            return res.status(404).json({ success: false, message: 'Availability slot not found' });
        }

        const slot = rows[0];
        const adminHeldSpaces = Math.max(0, Number(slot.held_spaces || 0));
        const activeCheckoutHeldSeats = getActiveCheckoutHeldSeatsForSlot(activity_id, date, time, {
            excludeHoldKey: holdKey
        });

        const availableToHold = Math.max(0, Number(slot.available || 0) - adminHeldSpaces - activeCheckoutHeldSeats);
        if (seatsToHold > availableToHold) {
            return res.status(409).json({
                success: false,
                message: `Only ${availableToHold} space${availableToHold === 1 ? '' : 's'} available for this slot.`,
                data: {
                    available: availableToHold,
                    held_spaces: adminHeldSpaces,
                    checkoutHeldSeats: activeCheckoutHeldSeats
                }
            });
        }

        const expiresAt = Date.now() + (5 * 60 * 1000); // 5 minutes

        // Store the hold
        availabilityHolds.set(holdKey, {
            activity_id,
            date,
            time,
            seats: seatsToHold,
            sessionId,
            expiresAt,
            createdAt: Date.now()
        });

        console.log(`🔒 Hold created for ${seatsToHold} seat(s) at ${date} ${time} (session: ${sessionId}, expires in 5 min)`);
        console.log(`🔒 Hold details:`, { activity_id, date, time, seats: seatsToHold, sessionId, holdKey });

        res.json({
            success: true,
            message: 'Availability held',
            holdKey,
            expiresAt,
            expiresIn: 300 // seconds
        });
    });
});

// Release availability hold
app.post('/api/releaseHold', (req, res) => {
    const { sessionId, activity_id, date, time } = req.body;

    if (!sessionId) {
        return res.status(400).json({ success: false, message: 'sessionId is required' });
    }

    let released = false;

    // If specific slot provided, release only that hold
    if (activity_id && date && time) {
        const holdKey = `${activity_id}_${date}_${time}_${sessionId}`;
        if (availabilityHolds.has(holdKey)) {
            availabilityHolds.delete(holdKey);
            console.log(`🔓 Hold released for ${date} ${time} (session: ${sessionId})`);
            released = true;
        }
    } else {
        // Release all holds for this session
        for (const [key, hold] of availabilityHolds.entries()) {
            if (hold.sessionId === sessionId) {
                availabilityHolds.delete(key);
                console.log(`🔓 Hold released for ${hold.date} ${hold.time} (session: ${sessionId})`);
                released = true;
            }
        }
    }

    res.json({
        success: true,
        message: released ? 'Hold(s) released' : 'No holds found',
        released
    });
});

