// Session status endpoint to avoid duplicate creation from client
// When processed, also returns conversion_data for client-side Google Ads conversion tracking
app.get('/api/session-status', (req, res) => {
    const { session_id } = req.query;
    if (!session_id) return res.status(400).json({ processed: false, message: 'session_id is required' });
    const data = stripeSessionStore[session_id];
    const processed = !!(data && (data.processed || data.processing));
    const result = { processed, type: data?.type || null };

    // When processed, include conversion_data so frontend can fire gtag conversion (webhook may have run first)
    // Skip extend_voucher and customer portal upgrade/upsell payments - not primary purchase conversions
    if (
        processed &&
        data &&
        data.type !== 'extend_voucher' &&
        data.type !== CUSTOMER_PORTAL_UPSELL_SESSION_TYPE &&
        data.type !== CUSTOMER_PORTAL_VOUCHER_UPGRADE_SESSION_TYPE
    ) {
        const source = data.bookingData || data.voucherData || {};
        const chooseFlightType = source.chooseFlightType || {};
        const flightTypeStr = (chooseFlightType.type || '').toLowerCase();
        let funnelType = 'booking';
        if (data.type === 'voucher') {
            const isGift = (source.book_flight || source.voucher_type || '').toLowerCase().includes('gift');
            funnelType = isGift ? 'gift' : 'voucher';
        } else if (data.type === 'booking') {
            funnelType = 'booking';
        }
        const experienceType = flightTypeStr.includes('private') ? 'private' : 'shared';
        const productType = (source.selectedVoucherType?.title || source.voucher_type || '').toString();
        const value = getAuthoritativePaidAmountFromSessionStore(data);
        // Build user_data for Enhanced Conversions (in-page code) - email required, phone improves match rate
        let user_data = {};
        if (source.passengerData && Array.isArray(source.passengerData) && source.passengerData[0]) {
            const p = source.passengerData[0];
            if (p.email && String(p.email).trim()) user_data.email = String(p.email).trim().toLowerCase();
            if (p.phone && String(p.phone).trim()) user_data.phone_number = String(p.phone).trim().replace(/\s+/g, '');
        } else if (source.purchaser_email || source.email) {
            if (source.purchaser_email || source.email) user_data.email = String(source.purchaser_email || source.email).trim().toLowerCase();
            if (source.purchaser_phone || source.phone || source.mobile) user_data.phone_number = String(source.purchaser_phone || source.phone || source.mobile || '').trim().replace(/\s+/g, '');
        }
        result.conversion_data = {
            transaction_id: session_id,
            value,
            currency: 'GBP',
            funnel_type: funnelType,
            experience_type: experienceType,
            product_type: productType,
            user_data: Object.keys(user_data).length ? user_data : undefined
        };
    }
    return res.json(result);
});

// Private vs Shared can share same activity/date/time — segment disambiguates manifest slots
function normalizeAssignmentSlotSegment(raw) {
    if (raw === null || raw === undefined) return '';
    const s = String(raw).trim().toLowerCase();
    if (!s) return '';
    if (s.includes('private')) return 'private';
    if (s.includes('shared')) return 'shared';
    return String(raw).trim().slice(0, 32);
}

function sqlBookingsFlightTypeMatchesSegment(segment) {
    if (!segment) return '';
    if (segment === 'private') return " AND LOWER(COALESCE(flight_type, '')) LIKE '%private%' ";
    if (segment === 'shared') return " AND LOWER(COALESCE(flight_type, '')) LIKE '%shared%' ";
    return '';
}

