// Existing DBs: add slot_segment and widen unique key (CREATE IF NOT EXISTS skips new columns)
function runFlightAssignmentSlotSegmentMigration() {
    const migrateTable = (tableName) => {
        con.query(`SHOW COLUMNS FROM ${tableName} LIKE 'slot_segment'`, (err, rows) => {
            if (err) {
                console.error(`slot_segment migration: cannot inspect ${tableName}:`, err.message);
                return;
            }
            if (rows && rows.length > 0) {
                return;
            }
            con.query(
                `ALTER TABLE ${tableName} ADD COLUMN slot_segment VARCHAR(32) NOT NULL DEFAULT '' AFTER time`,
                (e2) => {
                    if (e2) {
                        console.error(`slot_segment migration: add column ${tableName}:`, e2.message);
                        return;
                    }
                    con.query(`ALTER TABLE ${tableName} DROP INDEX uniq_slot`, (e3) => {
                        if (e3 && !String(e3.message || '').includes("check that it exists") && !String(e3.message || '').includes("Can't DROP")) {
                            console.error(`slot_segment migration: drop uniq_slot ${tableName}:`, e3.message);
                        }
                        con.query(
                            `ALTER TABLE ${tableName} ADD UNIQUE KEY uniq_slot (activity_id, date, time, slot_segment)`,
                            (e4) => {
                                if (e4) {
                                    console.error(`slot_segment migration: add uniq_slot ${tableName}:`, e4.message);
                                } else {
                                    console.log(`✅ ${tableName}: slot_segment + uniq_slot(activity_id, date, time, slot_segment)`);
                                }
                            }
                        );
                    });
                }
            );
        });
    };
    migrateTable('flight_crew_assignments');
    migrateTable('flight_pilot_assignments');
}
runFlightAssignmentSlotSegmentMigration();

function runAvailabilityVisibilityMigrations() {
    const ensureAvailabilityColumn = (columnName, sqlDefinition, positionClause = '') => {
        con.query(`SHOW COLUMNS FROM activity_availability LIKE '${columnName}'`, (err, rows) => {
            if (err) {
                console.error(`availability visibility migration: cannot inspect ${columnName}:`, err.message);
                return;
            }

            if (rows && rows.length > 0) {
                return;
            }

            con.query(
                `ALTER TABLE activity_availability ADD COLUMN ${columnName} ${sqlDefinition} ${positionClause}`.trim(),
                (alterErr) => {
                    if (alterErr) {
                        console.error(`availability visibility migration: add ${columnName}:`, alterErr.message);
                    } else {
                        console.log(`✅ activity_availability.${columnName} ready`);
                    }
                }
            );
        });
    };

    ensureAvailabilityColumn('held_spaces', 'INT NOT NULL DEFAULT 0', 'AFTER available');
    ensureAvailabilityColumn('hidden_flight_types', 'VARCHAR(255) NULL', 'AFTER flight_types');
    ensureAvailabilityColumn('hidden_voucher_types', 'VARCHAR(255) NULL', 'AFTER voucher_types');

    const createManifestDateNotesTable = `
        CREATE TABLE IF NOT EXISTS manifest_date_notes (
            id INT AUTO_INCREMENT PRIMARY KEY,
            manifest_date DATE NOT NULL,
            note TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
            UNIQUE KEY uniq_manifest_date (manifest_date)
        ) COMMENT 'Admin note attached to a manifest date';
    `;

    con.query(createManifestDateNotesTable, (createErr) => {
        if (createErr) {
            console.error('Error creating manifest_date_notes table:', createErr);
        } else {
            console.log('✅ manifest_date_notes table ready');
        }
    });
}
runAvailabilityVisibilityMigrations();

