// Upsert crew assignment for a slot
app.post('/api/crew-assignment', (req, res) => {
    const { activity_id, date, time, crew_id, slot_segment } = req.body;
    const normalizedSegment = normalizeAssignmentSlotSegment(slot_segment);
    
    // Validate required fields
    if (activity_id === null || activity_id === undefined || activity_id === '') {
        return res.status(400).json({ success: false, message: 'activity_id is required' });
    }
    if (!date || !time) {
        return res.status(400).json({ success: false, message: 'date and time are required' });
    }

    // Normalize activity_id to integer
    const normalizedActivityId = typeof activity_id === 'string' 
        ? (activity_id.trim() === '' ? null : parseInt(activity_id, 10))
        : activity_id;
    
    // Validate normalized activity_id
    if (normalizedActivityId === null || normalizedActivityId === undefined || isNaN(normalizedActivityId) || normalizedActivityId <= 0) {
        console.error('Invalid activity_id received:', { original: activity_id, normalized: normalizedActivityId, body: req.body });
        return res.status(400).json({ 
            success: false, 
            message: `Invalid activity_id: ${activity_id}. Expected a positive integer.` 
        });
    }
    
    // Normalize crew_id: convert empty string to null, and ensure integer type
    const normalizedCrewId = (crew_id === '' || crew_id === null || crew_id === undefined) 
        ? null 
        : (typeof crew_id === 'string' ? parseInt(crew_id, 10) : crew_id);
    
    // If crew_id is provided, validate it's a valid number
    if (normalizedCrewId !== null && (isNaN(normalizedCrewId) || normalizedCrewId <= 0)) {
        console.error('Invalid crew_id received:', { original: crew_id, normalized: normalizedCrewId });
        return res.status(400).json({ 
            success: false, 
            message: `Invalid crew_id: ${crew_id}. Expected a positive integer or null.` 
        });
    }

    console.log('Saving crew assignment:', { activity_id: normalizedActivityId, date, time, crew_id: normalizedCrewId, slot_segment: normalizedSegment });

    // If crew_id is null, delete the assignment
    if (normalizedCrewId === null || normalizedCrewId === undefined) {
        const deleteSql = 'DELETE FROM flight_crew_assignments WHERE activity_id = ? AND date = ? AND time = ? AND slot_segment = ?';
        con.query(deleteSql, [normalizedActivityId, date, time, normalizedSegment], async (err, result) => {
            if (err) {
                console.error('Error deleting crew assignment:', err);
                return res.status(500).json({ success: false, message: 'Database error', error: err.message });
            }
            console.log('Crew assignment deleted successfully:', result);
            
            // Update Google Calendar events - remove crew but keep pilot
            try {
                const flightDateTime = `${date} ${time}`;
                const segClause = sqlBookingsFlightTypeMatchesSegment(normalizedSegment);
                const getBookingsSql = `
                    SELECT id, google_calendar_event_id, flight_type, location, flight_date, pax, time_slot
                    FROM all_booking 
                    WHERE activity_id = ? 
                    AND DATE(flight_date) = ? 
                    AND (time_slot = ? OR TIME(flight_date) = ?)
                    AND status != 'Cancelled'
                    AND google_calendar_event_id IS NOT NULL
                    ${segClause}
                `;
                
                con.query(getBookingsSql, [normalizedActivityId, date, time, time], async (bookingsErr, bookingsResult) => {
                    if (!bookingsErr && bookingsResult && bookingsResult.length > 0) {
                        // Get total passenger count
                        const getTotalPassengersSql = `
                            SELECT SUM(pax) as total_passengers 
                            FROM all_booking 
                            WHERE activity_id = ? 
                            AND DATE(flight_date) = ? 
                            AND (time_slot = ? OR TIME(flight_date) = ?)
                            AND status != 'Cancelled'
                            ${segClause}
                        `;
                        
                        con.query(getTotalPassengersSql, [normalizedActivityId, date, time, time], async (paxErr, paxResult) => {
                            const totalPassengers = (paxResult && paxResult.length > 0 && paxResult[0].total_passengers) 
                                ? parseInt(paxResult[0].total_passengers) 
                                : 0;
                            
                            // Get pilot member if assigned (to preserve pilot info)
                            const getPilotSql = `
                                SELECT p.first_name, p.last_name 
                                FROM flight_pilot_assignments fpa
                                JOIN pilots p ON fpa.pilot_id = p.id
                                WHERE fpa.activity_id = ? 
                                AND fpa.date = ? 
                                AND fpa.time = ?
                                AND fpa.slot_segment = ?
                                LIMIT 1
                            `;
                            
                            con.query(getPilotSql, [normalizedActivityId, date, time, normalizedSegment], async (pilotErr, pilotResult) => {
                                let pilotMember = null;
                                if (!pilotErr && pilotResult && pilotResult.length > 0) {
                                    pilotMember = `${pilotResult[0].first_name} ${pilotResult[0].last_name}`;
                                }
                                
                                // Update all Google Calendar events - crew is null now
                                const updatePromises = bookingsResult.map(async (booking) => {
                                    try {
                                        await updateCalendarEvent(booking.google_calendar_event_id, {
                                            location: booking.location,
                                            flightType: booking.flight_type,
                                            passengerCount: totalPassengers,
                                            flightDate: booking.flight_date || flightDateTime,
                                            crewMember: null, // Crew removed
                                            pilotMember: pilotMember,
                                            bookingId: booking.id.toString()
                                        });
                                        console.log(`✅ Updated Google Calendar event for booking ${booking.id} (Crew removed, Pilot: ${pilotMember || 'None'})`);
                                    } catch (calendarError) {
                                        console.error(`❌ Error updating Google Calendar event for booking ${booking.id}:`, calendarError);
                                        const errorMessage = `Google Calendar: Failed to update event ${booking.google_calendar_event_id || 'unknown'} after crew removal for booking ${booking.id || 'unknown'}`;
                                        const errorDetails = calendarError.response?.data 
                                            ? JSON.stringify(calendarError.response.data) 
                                            : calendarError.message || 'Unknown error';
                                        const stackTrace = calendarError.stack || `${calendarError.name}: ${calendarError.message}`;
                                        saveErrorLog('error', `${errorMessage}. Details: ${errorDetails}`, stackTrace, 'crew-assignment.deleteCalendarEvent');
                                    }
                                });
                                
                                await Promise.all(updatePromises);
                            });
                        });
                    }
                });
            } catch (calendarError) {
                console.error('Error updating Google Calendar events after crew removal:', calendarError);
            }
            
            res.json({
                success: true,
                message: 'Crew assignment cleared',
                data: { activity_id: normalizedActivityId, date, time, crew_id: null, slot_segment: normalizedSegment }
            });
        });
        return;
    }

    // Validate that the crew member exists
    const validateCrewSql = 'SELECT id FROM crew WHERE id = ? AND is_active = 1';
    con.query(validateCrewSql, [normalizedCrewId], (validateErr, validateResult) => {
        if (validateErr) {
            console.error('Error validating crew member:', validateErr);
            return res.status(500).json({ success: false, message: 'Database error', error: validateErr.message });
        }

        if (validateResult.length === 0) {
            return res.status(400).json({ success: false, message: 'Invalid crew member ID' });
        }

        const sql = `
            INSERT INTO flight_crew_assignments (activity_id, date, time, slot_segment, crew_id)
            VALUES (?, ?, ?, ?, ?)
            ON DUPLICATE KEY UPDATE crew_id = VALUES(crew_id), updated_at = CURRENT_TIMESTAMP
        `;

        con.query(sql, [normalizedActivityId, date, time, normalizedSegment, normalizedCrewId], async (err, result) => {
            if (err) {
                console.error('Error upserting crew assignment:', err);
                return res.status(500).json({ success: false, message: 'Database error', error: err.message });
            }
            console.log('Crew assignment saved successfully:', result);

            // Update Google Calendar events for all bookings on this flight slot
            try {
                // Get crew member name
                const getCrewNameSql = 'SELECT first_name, last_name FROM crew WHERE id = ?';
                con.query(getCrewNameSql, [normalizedCrewId], async (crewErr, crewResult) => {
                    let crewMember = null;
                    if (!crewErr && crewResult && crewResult.length > 0) {
                        crewMember = `${crewResult[0].first_name} ${crewResult[0].last_name}`;
                    }

                    // Get all bookings for this flight slot
                    const flightDateTime = `${date} ${time}`;
                    const segClauseSave = sqlBookingsFlightTypeMatchesSegment(normalizedSegment);
                    const getBookingsSql = `
                        SELECT id, google_calendar_event_id, flight_type, location, flight_date, pax, time_slot
                        FROM all_booking 
                        WHERE activity_id = ? 
                        AND DATE(flight_date) = ? 
                        AND (time_slot = ? OR TIME(flight_date) = ?)
                        AND status != 'Cancelled'
                        AND google_calendar_event_id IS NOT NULL
                        ${segClauseSave}
                    `;
                    
                    con.query(getBookingsSql, [normalizedActivityId, date, time, time], async (bookingsErr, bookingsResult) => {
                        if (!bookingsErr && bookingsResult && bookingsResult.length > 0) {
                            // Get total passenger count for this flight slot
                            const getTotalPassengersSql = `
                                SELECT SUM(pax) as total_passengers 
                                FROM all_booking 
                                WHERE activity_id = ? 
                                AND DATE(flight_date) = ? 
                                AND (time_slot = ? OR TIME(flight_date) = ?)
                                AND status != 'Cancelled'
                                ${segClauseSave}
                            `;
                            
                            con.query(getTotalPassengersSql, [normalizedActivityId, date, time, time], async (paxErr, paxResult) => {
                                const totalPassengers = (paxResult && paxResult.length > 0 && paxResult[0].total_passengers) 
                                    ? parseInt(paxResult[0].total_passengers) 
                                    : 0;
                                
                                // Get pilot member if assigned (to preserve pilot info when updating crew)
                                const getPilotSql = `
                                    SELECT p.first_name, p.last_name 
                                    FROM flight_pilot_assignments fpa
                                    JOIN pilots p ON fpa.pilot_id = p.id
                                    WHERE fpa.activity_id = ? 
                                    AND fpa.date = ? 
                                    AND fpa.time = ?
                                    AND fpa.slot_segment = ?
                                    LIMIT 1
                                `;
                                
                                con.query(getPilotSql, [normalizedActivityId, date, time, normalizedSegment], async (pilotErr, pilotResult) => {
                                    let pilotMember = null;
                                    if (!pilotErr && pilotResult && pilotResult.length > 0) {
                                        pilotMember = `${pilotResult[0].first_name} ${pilotResult[0].last_name}`;
                                    }
                                    
                                    // Update all Google Calendar events for this flight slot
                                    const updatePromises = bookingsResult.map(async (booking) => {
                                        try {
                                            await updateCalendarEvent(booking.google_calendar_event_id, {
                                                location: booking.location,
                                                flightType: booking.flight_type,
                                                passengerCount: totalPassengers,
                                                flightDate: booking.flight_date || flightDateTime,
                                                crewMember: crewMember,
                                                pilotMember: pilotMember,
                                                bookingId: booking.id.toString()
                                            });
                                            console.log(`✅ Updated Google Calendar event for booking ${booking.id} (Crew: ${crewMember || 'None'}, Pilot: ${pilotMember || 'None'})`);
                                        } catch (calendarError) {
                                            console.error(`❌ Error updating Google Calendar event for booking ${booking.id}:`, calendarError);
                                            
                                            // Save error to logs database
                                            const errorMessage = `Google Calendar: Failed to update event ${booking.google_calendar_event_id || 'unknown'} for booking ${booking.id || 'unknown'}`;
                                            const errorDetails = calendarError.response?.data 
                                                ? JSON.stringify(calendarError.response.data) 
                                                : calendarError.message || 'Unknown error';
                                            const stackTrace = calendarError.stack || `${calendarError.name}: ${calendarError.message}`;
                                            saveErrorLog('error', `${errorMessage}. Crew Assignment - Activity: ${normalizedActivityId}, Date: ${date}, Time: ${time}, Details: ${errorDetails}`, stackTrace, 'crew-assignment.updateCalendarEvent');
                                        }
                                    });
                                    
                                    await Promise.all(updatePromises);
                                });
                            });
                        }
                    });
                });
            } catch (calendarError) {
                console.error('Error updating Google Calendar events for crew assignment:', calendarError);
                
                // Save error to logs database
                const errorMessage = `Google Calendar: Error updating events for crew assignment - Activity: ${normalizedActivityId}, Date: ${date}, Time: ${time}`;
                const errorDetails = calendarError.response?.data 
                    ? JSON.stringify(calendarError.response.data) 
                    : calendarError.message || 'Unknown error';
                const stackTrace = calendarError.stack || `${calendarError.name}: ${calendarError.message}`;
                saveErrorLog('error', `${errorMessage}. Details: ${errorDetails}`, stackTrace, 'crew-assignment.googleCalendarSync');
                
                // Don't fail the request if calendar sync fails
            }

            // Return the saved assignment data
            res.json({
                success: true,
                message: 'Crew assignment saved',
                data: { activity_id: normalizedActivityId, date, time, crew_id: normalizedCrewId, slot_segment: normalizedSegment }
            });
        });
    });
});

