const CUSTOMER_PORTAL_PRE_FORMATTED_CREATED_AT_REGEX = /^\d{2}\/\d{2}\/\d{4}(?: \d{2}:\d{2})?$/;

function formatCustomerPortalCreatedAt(rawCreatedAt = '') {
    if (rawCreatedAt == null || rawCreatedAt === '') {
        return '';
    }

    if (typeof rawCreatedAt === 'string') {
        const trimmedValue = rawCreatedAt.trim();
        if (!trimmedValue) {
            return '';
        }

        // Some legacy short links were generated from already-formatted
        // portal timestamps (DD/MM/YYYY HH:mm). Re-parsing these strings can
        // shift the time and break deterministic short-code recovery.
        if (CUSTOMER_PORTAL_PRE_FORMATTED_CREATED_AT_REGEX.test(trimmedValue)) {
            return trimmedValue;
        }
    }

    try {
        const dateObj = moment(rawCreatedAt);
        if (dateObj.isValid()) {
            return dateObj.format('DD/MM/YYYY HH:mm');
        }
    } catch (error) {
        console.warn('Error formatting customer portal created_at:', error);
    }

    return String(rawCreatedAt).trim();
}

function buildCustomerPortalToken(booking = {}) {
    const explicitToken =
        booking.customerPortalToken ||
        booking.customer_portal_token ||
        booking.portal_token ||
        booking.portalToken ||
        booking.portal_link_token;
    if (explicitToken) return explicitToken;

    // For Flight/Gift Voucher links we may receive the type from different
    // tables/contexts (all_vouchers.book_flight, all_booking.flight_type, etc.).
    const bookingTypeRaw =
        booking.book_flight ??
        booking.bookFlight ??
        booking.flight_type ??
        booking.flightType ??
        booking.voucher_type ??
        booking.voucherType ??
        '';
    const bookingType = String(bookingTypeRaw).trim().toLowerCase();
    const isFlightVoucher = Boolean(
        booking.is_flight_voucher ||
        booking.isFlightVoucher ||
        bookingType.includes('flight voucher') ||
        bookingType.includes('book flight')
    );
    const isGiftVoucher = bookingType.includes('gift voucher');
    const isVoucherIdForced = (() => {
        try {
            const idRaw = booking.id ?? booking.booking_id ?? booking.bookingId ?? '';
            return String(idRaw).startsWith('voucher-');
        } catch {
            return false;
        }
    })();
    const isRedeemedVoucher = (() => {
        const v = booking.redeemed_voucher ?? booking.is_voucher_redeemed ?? booking.redeemed ?? booking._original?.redeemed;
        if (v === undefined || v === null) return false;
        if (typeof v === 'string') return v.trim().toLowerCase() === 'yes' || v.trim().toLowerCase() === 'true';
        return v === 1 || v === true;
    })();
    
    // Get voucher ID from _original if available, or from booking.voucher_id
    const voucherId = booking._original?.id || booking.voucher_id || null;
    
    // Determine ID to use: voucher ID for Flight/Gift Voucher, booking ID for others
    let idToUse = '';
    if (isVoucherIdForced) {
        // Caller explicitly provided voucher-* id; keep voucher context even if redeemed
        idToUse = booking.id ?? booking.booking_id ?? booking.bookingId ?? '';
    } else if ((isFlightVoucher || isGiftVoucher) && !isRedeemedVoucher) {
        // Use voucher ID with prefix for Flight/Gift Voucher
        if (voucherId) {
            idToUse = `voucher-${voucherId}`;
        } else if (booking.id && String(booking.id).startsWith('voucher-')) {
            // Already in voucher- format
            idToUse = String(booking.id);
        } else {
            // Fallback: use booking ID if voucher ID not available
            idToUse = booking.id ?? booking.booking_id ?? booking.bookingId ?? '';
        }
    } else {
        // For regular bookings, use booking ID
        idToUse = booking.id ?? booking.booking_id ?? booking.bookingId ?? '';
    }
    
    // For Flight Voucher, use purchaser_email instead of email
    // For Gift Voucher, use recipient_email
    // For other types, use email
    let emailToUse = '';
    if (isFlightVoucher) {
        emailToUse = booking.purchaser_email || booking._original?.purchaser_email || booking.email || booking.customer_email || '';
    } else if (isGiftVoucher) {
        emailToUse = booking.recipient_email || booking._original?.recipient_email || booking.email || booking.customer_email || '';
    } else {
        emailToUse = booking.email || booking.customer_email || '';
    }

    // Format created_at to DD/MM/YYYY HH:mm format (same as frontend)
    const formattedCreatedAt = formatCustomerPortalCreatedAt(
        booking.created_at ?? booking.created ?? ''
    );

    const sourceParts = [
        idToUse,
        booking.voucher_code ?? booking.voucherCode ?? booking.voucher_ref ?? '',
        emailToUse,
        formattedCreatedAt
    ].map((part) => (part == null ? '' : String(part).trim()))
     .filter((part) => part !== '');

    if (!sourceParts.length) return null;
    try {
        return Buffer.from(sourceParts.join('|'), 'utf8').toString('base64');
    } catch (error) {
        console.warn('Error encoding customer portal token:', error);
        return null;
    }
}

