function sanitizeCustomerPortalToken(token = '') {
    return String(token).trim().replace(/[^a-zA-Z0-9+/=_-]/g, '');
}

function getUtf8Bytes(value = '') {
    return Uint8Array.from(Buffer.from(String(value), 'utf8'));
}

function buildLegacyClientHashSegment(value = '', seed = LEGACY_CLIENT_FNV_32_OFFSET_BASIS) {
    const bytes = getUtf8Bytes(value);
    let hash = seed >>> 0;

    for (const byte of bytes) {
        hash ^= byte;
        hash = Math.imul(hash, LEGACY_CLIENT_FNV_32_PRIME) >>> 0;
    }

    return (hash >>> 0).toString(36).padStart(7, '0');
}

function buildLegacyClientCustomerPortalShortCode(value = '') {
    const normalizedValue = value == null ? '' : String(value);
    if (!normalizedValue) return '';

    const primary = buildLegacyClientHashSegment(
        normalizedValue,
        LEGACY_CLIENT_FNV_32_OFFSET_BASIS
    );
    const secondary = buildLegacyClientHashSegment(
        `${normalizedValue}|customerPortal`,
        LEGACY_CLIENT_FNV_32_SECONDARY_SEED
    );

    return `${primary}${secondary}`.slice(0, 13);
}

function buildDeterministicCustomerPortalShortCode(value = '') {
    const normalizedValue = value == null ? '' : String(value).trim();
    if (!normalizedValue) return '';

    // Use a longer SHA-256-derived code so short links remain stable without
    // relying on a small hash space that can accidentally cross-resolve.
    return crypto
        .createHash('sha256')
        .update(normalizedValue)
        .digest('hex')
        .slice(0, CUSTOMER_PORTAL_SHORT_CODE_LENGTH);
}

function buildLegacyCustomerPortalShortCode(value = '') {
    const bytes = Buffer.from(String(value), 'utf8');
    let hash = LEGACY_FNV_OFFSET_BASIS;

    for (const byte of bytes) {
        hash ^= BigInt(byte);
        hash = (hash * LEGACY_FNV_PRIME) % LEGACY_UINT64_MOD;
    }

    return hash.toString(36).padStart(13, '0');
}

function getCustomerPortalCreatedAtCandidates(value = '') {
    const candidates = new Set();
    const raw = value == null ? '' : String(value).trim();

    if (raw) {
        candidates.add(raw);
    }

    const addMomentFormats = (dateValue) => {
        if (!dateValue || !dateValue.isValid()) return;
        candidates.add(dateValue.format('DD/MM/YYYY HH:mm'));
        candidates.add(dateValue.format('DD/MM/YYYY'));
    };

    const dayjsValue = dayjs(value);
    if (dayjsValue.isValid()) {
        candidates.add(dayjsValue.format('DD/MM/YYYY HH:mm'));
        candidates.add(dayjsValue.format('DD/MM/YYYY'));
    }

    const momentValue = moment(value);
    if (momentValue.isValid()) {
        addMomentFormats(momentValue);
        addMomentFormats(momentValue.clone().utc());

        // Existing links were generated in a mix of browser/server timezone
        // contexts (including half/quarter-hour offsets). We try a bounded
        // range of offsets to recover missing mappings without knowing
        // the original runtime timezone.
        for (let offsetMinutes = -12 * 60; offsetMinutes <= 14 * 60; offsetMinutes += 15) {
            addMomentFormats(momentValue.clone().utcOffset(offsetMinutes));
        }
    }

    return Array.from(candidates).filter(Boolean);
}

function getCustomerPortalShortCodeVariants(targetUrl = '') {
    const trimmedTargetUrl = targetUrl == null ? '' : String(targetUrl).trim();
    if (!trimmedTargetUrl) return [];

    return Array.from(new Set([
        buildDeterministicCustomerPortalShortCode(trimmedTargetUrl),
        buildLegacyClientCustomerPortalShortCode(trimmedTargetUrl),
        buildLegacyCustomerPortalShortCode(trimmedTargetUrl)
    ].filter(Boolean))).map((code) => String(code).trim().toLowerCase());
}

function buildCustomerPortalShortLinkCandidates(record = {}) {
    const matches = [];
    const seenTargets = new Set();
    const createdCandidates = getCustomerPortalCreatedAtCandidates(record.created_at ?? record.created ?? '');

    for (const createdCandidate of createdCandidates) {
        const tokenSource = {
            ...record,
            created_at: createdCandidate,
            created: createdCandidate
        };
        const portalToken = buildCustomerPortalToken(tokenSource);
        const targetUrls = buildCustomerPortalTargetCandidates(portalToken);

        targetUrls.forEach((targetUrl) => {
            if (!targetUrl || seenTargets.has(targetUrl)) {
                return;
            }

            seenTargets.add(targetUrl);

            const shortCodes = getCustomerPortalShortCodeVariants(targetUrl);
            shortCodes.forEach((shortCode) => {
                matches.push({
                    shortCode,
                    targetUrl,
                    portalToken
                });
            });
        });
    }

    return matches;
}

function isUnknownColumnError(err) {
    return Boolean(
        err &&
            (err.errno === 1054 ||
                err.code === 'ER_BAD_FIELD_ERROR' ||
                String(err.sqlMessage || err.message || '').includes('Unknown column'))
    );
}

